interface ColumnConfigProps {
  isOpen: boolean;
  onClose: () => void;
  allColumns: { key: string; header: string }[];
  currentOrder: string[]; 
  onSave: (newOrder: string[]) => void;
}

export const ColumnConfigDialog: React.FC<ColumnConfigProps> = ({ isOpen, onClose, allColumns, currentOrder, onSave }) => {
  const [orderedKeys, setOrderedKeys] = useState(currentOrder);

  useEffect(() => {
      if (isOpen) setOrderedKeys(currentOrder);
  }, [isOpen, currentOrder]);

  const toggleVisibility = (key: string) => {
      if (orderedKeys.includes(key)) {
          setOrderedKeys(orderedKeys.filter(k => k !== key));
      } else {
          setOrderedKeys([...orderedKeys, key]);
      }
  };

  const move = (index: number, direction: -1 | 1) => {
      const newOrder = [...orderedKeys];
      const [item] = newOrder.splice(index, 1);
      newOrder.splice(index + direction, 0, item);
      setOrderedKeys(newOrder);
  };

  const visibleCols = orderedKeys.map(k => allColumns.find(c => c.key === k)).filter(Boolean) as typeof allColumns;
  const hiddenCols = allColumns.filter(c => !orderedKeys.includes(c.key));

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="列配置" size="sm" 
      footer={<><Button variant="secondary" onClick={onClose}>取消</Button><Button onClick={() => { onSave(orderedKeys); onClose(); }}>保存</Button></>}
    >
      <div className="space-y-4">
          <div>
              <div className="text-xs text-slate-400 mb-2">已显示 (点击箭头排序)</div>
              <div className="space-y-1 max-h-60 overflow-y-auto custom-scrollbar border border-slate-700 rounded p-1">
                  {visibleCols.map((col, idx) => (
                      <div key={col.key} className="flex items-center justify-between bg-slate-800 p-2 rounded text-sm">
                          <span>{col.header}</span>
                          <div className="flex items-center gap-1">
                              <button disabled={idx === 0} onClick={() => move(idx, -1)} className="p-1 hover:text-blue-400 disabled:opacity-30"><ArrowUp size={14}/></button>
                              <button disabled={idx === visibleCols.length - 1} onClick={() => move(idx, 1)} className="p-1 hover:text-blue-400 disabled:opacity-30"><ArrowDown size={14}/></button>
                              <button onClick={() => toggleVisibility(col.key)} className="p-1 hover:text-red-400 ml-2"><X size={14}/></button>
                          </div>
                      </div>
                  ))}
                  {visibleCols.length === 0 && <div className="text-xs text-slate-500 text-center py-2">无显示列</div>}
              </div>
          </div>

          {hiddenCols.length > 0 && (
              <div>
                  <div className="text-xs text-slate-400 mb-2">已隐藏 (点击添加)</div>
                  <div className="flex flex-wrap gap-2">
                      {hiddenCols.map(col => (
                          <button 
                            key={col.key} 
                            onClick={() => toggleVisibility(col.key)}
                            className="bg-slate-800 border border-slate-700 hover:border-blue-500 rounded px-2 py-1 text-xs text-slate-300 flex items-center gap-1"
                          >
                              <Plus size={12} /> {col.header}
                          </button>
                      ))}
                  </div>
              </div>
          )}
      </div>
    </Modal>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, ChevronLeft, ChevronRight, ChevronsRight, ChevronsLeft, Users, Repeat, Crown, Globe, Download, Settings, FileText } from 'lucide-react';
import { MOCK_DOMAINS, MOCK_CUSTOMERS } from '../constants';
import { Domain } from '../types';
import { useGlobalContext } from '../GlobalContext';

export const DomainManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentEditDomain, setCurrentEditDomain] = useState<Partial<Domain> | null>(null);

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Domain | null>(null);

  // Transfer State
  const [transferSearch, setTransferSearch] = useState('');
  const [transferPage, setTransferPage] = useState(1);
  const [selectedSource, setSelectedSource] = useState<string[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<string[]>([]);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     if (domain.isSuper) return; // Cannot disable super domain
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const handleEdit = (domain: Domain) => {
    setCurrentEditDomain({ 
      ...domain, 
      customerIds: domain.customerIds || [],
      managementMode: domain.managementMode || 'switching'
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleDelete = (row: Domain) => {
    if (row.isSuper) return;
    setDeleteTarget(row);
    setDeleteConfirmOpen(true);
  };

  // --- Column Definitions ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'serial', header: '序号', accessor: 'serialNumber', width: '60px' 
    },
    { 
      key: 'name', header: '域名称', 
      accessor: (row: Domain) => (
        <div className="flex flex-col text-left">
           <div className="flex items-center">
               {row.isSuper ? (
                 <Crown size={16} className="text-yellow-500 mr-2" />
               ) : (
                 <Building2 size={16} className="text-blue-400 mr-2"/>
               )}
               <span className={`font-medium ${row.isSuper ? 'text-yellow-100' : 'text-blue-100'}`}>{row.name}</span>
               {row.isSuper && <Badge color="yellow" className="ml-2 scale-90">总控</Badge>}
           </div>
           <span className="text-[10px] text-slate-500 font-mono ml-6 mt-0.5">{row.code}</span>
        </div>
      ),
      width: '200px'
    },
    { 
      key: 'desc', header: '描述', 
      accessor: (row: Domain) => <span className="text-slate-400 text-xs truncate max-w-[150px] block text-left" title={row.description}>{row.description || '-'}</span> 
    },
    {
      key: 'mode', header: '管理模式',
      accessor: (row: Domain) => (
         row.managementMode === 'fusion' ? (
           <Badge color="blue" className="flex items-center gap-1 w-fit mx-auto">
              <Users size={10} /> 跨域融合
           </Badge>
         ) : (
           <Badge color="gray" className="flex items-center gap-1 w-fit mx-auto">
              <Repeat size={10} /> 按域切换
           </Badge>
         )
      )
    },
    { 
      key: 'customers', header: '关联客户', 
      accessor: (row: Domain) => {
        if (row.isSuper) {
             return <span className="text-slate-400 text-xs italic">所有客户权限</span>;
        }
        const ids = row.customerIds || [];
        if (ids.length === 0) return <span className="text-slate-500">-</span>;

        const names = ids.map(id => MOCK_CUSTOMERS.find(c => c.id === id)?.name).filter(Boolean) as string[];
        const displayCount = 2;
        const visibleNames = names.slice(0, displayCount);
        const diff = names.length - displayCount;

        return (
          <div className="flex items-center justify-center gap-1" title={names.join('、')}>
            <span className="text-slate-300 text-sm truncate max-w-[150px]">{visibleNames.join('、')}</span>
            {diff > 0 && <Badge color="gray" className="scale-90">+{diff}</Badge>}
          </div>
        )
      } 
    },
    { 
      key: 'status', header: '状态', 
      accessor: (row: Domain) => (
        <div className="flex justify-center">
            <Switch 
                checked={row.status === 'active'} 
                onChange={(checked) => initiateStatusChange(row, checked)} 
                disabled={row.isSuper}
            />
        </div>
      ),
      width: '80px'
    },
    { key: 'createTime', header: '创建时间', accessor: (row: Domain) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'updateTime', header: '更新时间', accessor: (row: Domain) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    {
      key: 'action', header: '操作',
      accessor: (row: Domain) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          {!row.isSuper && (
            <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row)}>删除</Button>
          )}
        </div>
      ),
      width: '140px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Reset search on context change
  useEffect(() => {
    setSearchName('');
    setSearchCode('');
    setSearchStatus('');
  }, [mode, currentDomain]);

  // Filtering Data
  const filteredData = useMemo(() => {
      let baseData = data;
      // Filter by Context
      if (mode === 'switching' && currentDomain) {
          baseData = data.filter(d => d.id === currentDomain.id);
      }

      return baseData.filter(d => {
          const matchName = d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchCode = d.code.toLowerCase().includes(searchCode.toLowerCase());
          const matchStatus = searchStatus ? d.status === searchStatus : true;
          return matchName && matchCode && matchStatus;
      });
  }, [data, searchName, searchCode, searchStatus, mode, currentDomain]);

  // Prepared data for table with serial numbers
  const tableData = useMemo(() => {
      return filteredData.map((d, index) => ({
          ...d,
          serialNumber: index + 1
      }));
  }, [filteredData]);

  const handleAdd = () => {
    setCurrentEditDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: null,
      customerIds: [],
      managementMode: 'switching',
      isSuper: false,
      description: ''
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const confirmDelete = () => {
    if (deleteTarget) {
        setData(data.filter(n => n.id !== deleteTarget.id));
    }
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          setData(data.map(item => item.id === targetStatusChange.id ? { ...item, status: targetStatusChange.newStatus } : item));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const handleSave = () => {
      setIsModalOpen(false);
      const timestamp = new Date().toLocaleString();
      if (currentEditDomain?.id) {
          // Update
          setData(data.map(n => n.id === currentEditDomain.id ? { 
              ...n, 
              ...currentEditDomain,
              updateTime: timestamp,
              updater: 'admin' // Mock user
          } as Domain : n));
      } else {
          // Create
          const newDomain = {
              ...currentEditDomain,
              id: Date.now().toString(),
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin',
              parentId: null
          } as Domain;
          setData([...data, newDomain]);
      }
  };

  // --- Transfer Logic ---
  const currentCustomerIds = currentEditDomain?.customerIds || [];
  const ITEMS_PER_TRANSFER_PAGE = 8; // Keep pagination for transfer list inside modal only

  const availableCustomers = useMemo(() => {
    return MOCK_CUSTOMERS.filter(c => !currentCustomerIds.includes(c.id));
  }, [currentCustomerIds]);

  const filteredSource = useMemo(() => {
    return availableCustomers.filter(c => c.name.toLowerCase().includes(transferSearch.toLowerCase()));
  }, [availableCustomers, transferSearch]);

  const totalTransferPages = Math.ceil(filteredSource.length / ITEMS_PER_TRANSFER_PAGE);
  const currentSourcePage = filteredSource.slice((transferPage - 1) * ITEMS_PER_TRANSFER_PAGE, transferPage * ITEMS_PER_TRANSFER_PAGE);

  const handleSelectAllSource = (checked: boolean) => {
    if (checked) {
        const allFilteredIds = filteredSource.map(c => c.id);
        setSelectedSource([...new Set([...selectedSource, ...allFilteredIds])]);
    } else {
        const filteredIds = filteredSource.map(c => c.id);
        setSelectedSource(selectedSource.filter(id => !filteredIds.includes(id)));
    }
  };

  const moveToTarget = () => {
    const newIds = [...currentCustomerIds, ...selectedSource];
    setCurrentEditDomain(prev => ({ ...prev!, customerIds: newIds }));
    setSelectedSource([]);
  };

  const moveToSource = () => {
    const newIds = currentCustomerIds.filter(id => !selectedTarget.includes(id));
    setCurrentEditDomain(prev => ({ ...prev!, customerIds: newIds }));
    setSelectedTarget([]);
  };

  return (
    <div className="space-y-4 h-full flex flex-col">
      <Card className="shrink-0 px-6 py-6">
        <div className="flex flex-col gap-4">
           {/* Row 1: Search Conditions */}
           <div className="flex flex-wrap gap-6 items-center">
               <Input 
                 label="域名称" 
                 placeholder="输入名称" 
                 className="w-48" 
                 value={searchName} 
                 onChange={e => setSearchName(e.target.value)} 
               />
               <Input 
                 label="域编码" 
                 placeholder="输入编码" 
                 className="w-48" 
                 value={searchCode} 
                 onChange={e => setSearchCode(e.target.value)} 
               />
               <Select 
                 label="状态" 
                 options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '禁用', value: 'inactive'}]} 
                 className="w-32" 
                 value={searchStatus}
                 onChange={e => setSearchStatus(e.target.value)}
               />
           </div>

           {/* Row 2: Actions */}
           <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button 
                        variant="secondary" 
                        icon={<RotateCcw size={16} />} 
                        onClick={() => { setSearchName(''); setSearchCode(''); setSearchStatus(''); }}
                    >
                        重置
                    </Button>
                    {/* Add button is strictly Green and in Search Area as requested */}
                    {mode === 'fusion' && (
                        <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增子域</Button>
                    )}
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
           </div>
        </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col" title={mode === 'switching' && currentDomain ? `[${currentDomain.name}] 域信息` : "域列表"}>
         <div className="flex-1 overflow-auto">
            <Table columns={activeColumns} data={tableData} />
         </div>
         <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {filteredData.length} 条</div>
         </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={currentEditDomain?.isSuper ? "智慧运维总控信息" : (currentEditDomain?.id ? "编辑子域信息" : "新增子域")}
        size="lg"
        footer={
          <>
            <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
            <Button onClick={handleSave}>确定</Button>
          </>
        }
      >
         <div className="space-y-6">
           {/* Basic Info */}
           <div>
               <SectionTitle title="域基础信息" />
               <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                    <div className="col-span-1">
                        <Input 
                            label="域名称" 
                            value={currentEditDomain?.name || ''}
                            onChange={(e) => setCurrentEditDomain(prev => ({...prev!, name: e.target.value}))}
                            placeholder="请输入域名称" 
                            disabled={currentEditDomain?.isSuper}
                        />
                    </div>

                    <div className="col-span-1">
                        <Input 
                            label="域编码" 
                            value={currentEditDomain?.code || ''} 
                            onChange={(e) => setCurrentEditDomain(prev => ({ ...prev!, code: e.target.value }))}
                            placeholder="唯一标识 (Code)" 
                            disabled={!!currentEditDomain?.id} 
                        />
                    </div>

                    <div className="col-span-1">
                        <Input label="管理员账号" defaultValue={currentEditDomain?.manager} placeholder="关联初始管理员" />
                    </div>

                    <div className="col-span-2">
                        <label className="text-sm text-slate-400 block mb-1.5">描述信息</label>
                        <textarea 
                            className="w-full bg-[#1e293b] border border-slate-700 rounded p-2 text-sm text-white focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-slate-600"
                            rows={3}
                            placeholder="请输入域描述..."
                            value={currentEditDomain?.description || ''}
                            onChange={(e) => setCurrentEditDomain(prev => ({ ...prev!, description: e.target.value }))}
                        />
                    </div>

                    <div className="col-span-2 bg-[#1e293b]/50 p-5 rounded-lg border border-slate-700/50">
                            <label className="text-sm font-medium text-slate-300 block mb-4">管理模式 (Management Mode)</label>
                            <div className="grid grid-cols-2 gap-6">
                                <div 
                                    className={`border rounded p-4 cursor-pointer transition-all flex items-start gap-4 ${currentEditDomain?.managementMode === 'fusion' ? 'bg-blue-600/10 border-blue-500' : 'bg-[#0f172a] border-slate-700 hover:border-slate-500'}`}
                                    onClick={() => !currentEditDomain?.isSuper && setCurrentEditDomain(prev => ({ ...prev!, managementMode: 'fusion' }))}
                                >
                                    <div className={`mt-0.5 rounded-full p-1.5 ${currentEditDomain?.managementMode === 'fusion' ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-700 text-slate-400'}`}>
                                        <Users size={16} />
                                    </div>
                                    <div>
                                        <div className={`text-sm font-bold ${currentEditDomain?.managementMode === 'fusion' ? 'text-blue-200' : 'text-slate-300'}`}>跨域融合模式</div>
                                        <div className="text-xs text-slate-400 mt-1.5 leading-relaxed">
                                            支持跨域查询，管理员可直接访问所有关联客户的数据。
                                        </div>
                                    </div>
                                </div>

                                <div 
                                    className={`border rounded p-4 cursor-pointer transition-all flex items-start gap-4 ${currentEditDomain?.managementMode === 'switching' ? 'bg-blue-600/10 border-blue-500' : 'bg-[#0f172a] border-slate-700 hover:border-slate-500'}`}
                                    onClick={() => !currentEditDomain?.isSuper && setCurrentEditDomain(prev => ({ ...prev!, managementMode: 'switching' }))}
                                >
                                    <div className={`mt-0.5 rounded-full p-1.5 ${currentEditDomain?.managementMode === 'switching' ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-700 text-slate-400'}`}>
                                        <Repeat size={16} />
                                    </div>
                                    <div>
                                        <div className={`text-sm font-bold ${currentEditDomain?.managementMode === 'switching' ? 'text-blue-200' : 'text-slate-300'}`}>按域切换模式</div>
                                        <div className="text-xs text-slate-400 mt-1.5 leading-relaxed">
                                            需切换不同上下文来访问特定数据，数据隔离性强。
                                        </div>
                                    </div>
                                </div>
                            </div>
                            {currentEditDomain?.isSuper && <div className="mt-3 text-xs text-amber-500/80 flex items-center gap-1"><Crown size={12}/> 总控中心默认启用跨域融合模式，拥有全局视野。</div>}
                    </div>
                </div>
            </div>

           {/* Customer Transfer Frame */}
           <div>
               <SectionTitle title="关联客户配置" />

               {currentEditDomain?.isSuper ? (
                   <div className="bg-slate-800/30 rounded-lg p-8 text-center border border-slate-700 border-dashed">
                       <Crown size={32} className="mx-auto text-yellow-500 mb-3 opacity-50"/>
                       <p className="text-slate-300 font-medium">总控中心默认拥有所有客户权限</p>
                       <p className="text-slate-500 text-sm mt-1">无需手动配置关联客户</p>
                   </div>
               ) : (
                <div className="flex h-[320px] gap-4">
                  {/* Left: Source */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg space-y-2">
                         <div className="flex gap-2">
                             <Input 
                                placeholder="搜索客户..." 
                                className="h-8 text-sm py-1" 
                                value={transferSearch}
                                onChange={(e) => { setTransferSearch(e.target.value); setTransferPage(1); }}
                             />
                         </div>
                         <div className="flex justify-between items-center px-1">
                             <label className="flex items-center space-x-2 cursor-pointer text-xs text-slate-300 select-none">
                                <input 
                                    type="checkbox" 
                                    className="rounded bg-slate-900 border-slate-600 text-blue-500" 
                                    onChange={(e) => handleSelectAllSource(e.target.checked)}
                                    checked={filteredSource.length > 0 && filteredSource.every(c => selectedSource.includes(c.id))}
                                />
                                <span>全选 ({filteredSource.length})</span>
                             </label>
                             <span className="text-xs text-slate-500">{selectedSource.length} 已选</span>
                         </div>
                      </div>

                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {currentSourcePage.map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedSource.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedSource.includes(item.id)
                                      ? setSelectedSource(selectedSource.filter(id => id !== item.id))
                                      : setSelectedSource([...selectedSource, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedSource.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                         {filteredSource.length === 0 && <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>}
                      </div>

                      {/* Pagination Controls for Transfer */}
                      {totalTransferPages > 1 && (
                          <div className="p-2 border-t border-slate-700 flex justify-between items-center bg-slate-800/30">
                              <button disabled={transferPage === 1} onClick={() => setTransferPage(p => p - 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronLeft size={16}/></button>
                              <span className="text-xs text-slate-400">{transferPage} / {totalTransferPages}</span>
                              <button disabled={transferPage === totalTransferPages} onClick={() => setTransferPage(p => p + 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronRight size={16}/></button>
                          </div>
                      )}
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col justify-center gap-3">
                        <Button size="sm" variant="secondary" onClick={moveToTarget} disabled={selectedSource.length === 0} title="添加" className="w-10">
                            <ChevronsRight size={18} />
                        </Button>
                        <Button size="sm" variant="secondary" onClick={moveToSource} disabled={selectedTarget.length === 0} title="移除" className="w-10">
                            <ChevronsLeft size={18} />
                        </Button>
                  </div>

                  {/* Right: Target */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[76px]">
                          <span className="text-xs font-semibold text-slate-300 pl-1">已关联客户 ({currentCustomerIds.length})</span>
                          <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setCurrentEditDomain(prev => ({...prev!, customerIds: []}))}>清空</Button>
                      </div>
                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {MOCK_CUSTOMERS.filter(c => currentCustomerIds.includes(c.id)).map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedTarget.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedTarget.includes(item.id)
                                      ? setSelectedTarget(selectedTarget.filter(id => id !== item.id))
                                      : setSelectedTarget([...selectedTarget, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedTarget.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                      </div>
                  </div>
               </div>
               )}
           </div>

           <Input label="备注信息" placeholder="可选填..." />
        </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '禁用'}该域吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除域"
         message={`确定要删除“${deleteTarget?.name}”吗？此操作不可恢复。`}
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTarget(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Folder, FileText, MousePointer, Search, RotateCcw, Download, Settings } from 'lucide-react';
import { MOCK_MENUS } from '../constants';
import { Menu } from '../types';

export const MenuManager: React.FC = () => {
  const [data, setData] = useState<Menu[]>(MOCK_MENUS);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchDescription, setSearchDescription] = useState('');
  const [searchVisible, setSearchVisible] = useState('');

  // Column Config State
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const [currentMenu, setCurrentMenu] = useState<Partial<Menu> & { isExternal?: boolean; isCache?: boolean }>({});

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newVisible: boolean } | null>(null);

  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  const initiateStatusChange = (menu: Menu, checked: boolean) => {
    setTargetStatusChange({ id: menu.id, newVisible: checked });
    setConfirmOpen(true);
  };

  const handleEdit = (menu: Menu) => {
    setCurrentMenu({ 
        ...menu, 
        parentId: menu.parentId || '0',
        isExternal: false, 
        isCache: true 
    });
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      const target = fullFlatData.find(m => m.id === id);
      if (target && target.children && target.children.length > 0) {
          alert("该菜单包含子菜单，请先删除子菜单！");
          return;
      }
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'name', header: '菜单名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center text-left">
           {row.type === 'dir' && <Folder size={16} className="text-yellow-500 mr-2" />}
           {row.type === 'menu' && <FileText size={16} className="text-blue-400 mr-2" />}
           {row.type === 'button' && <MousePointer size={16} className="text-slate-400 mr-2" />}
           <span className="text-slate-200">{row.name}</span>
        </div>
      ),
      width: '200px'
    },
    { 
      key: 'type', header: '类别', 
      accessor: (row: Menu) => {
          if (row.type === 'dir') return <Badge color="yellow">目录</Badge>;
          if (row.type === 'menu') return <Badge color="blue">菜单</Badge>;
          return <Badge color="gray">按钮</Badge>;
      },
      width: '80px'
    },
    { key: 'desc', header: '描述', accessor: (row: Menu) => <span className="text-slate-400 text-xs truncate max-w-[150px] block text-left" title={row.description}>{row.description || '-'}</span> },
    { key: 'sort', header: '排序', accessor: 'sort', width: '60px' },
    { 
      key: 'status', header: '状态', 
      accessor: (row: Menu) => (
        <div className="flex justify-center">
            <Switch 
            checked={row.visible} 
            onChange={(checked) => initiateStatusChange(row, checked)} 
            />
        </div>
      ),
      width: '80px'
    },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'createTime', header: '创建时间', accessor: (row: Menu) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    { key: 'updateTime', header: '更新时间', accessor: (row: Menu) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    {
      key: 'action', header: '操作',
      accessor: (row: Menu) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      ),
      width: '140px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  const flattenMenus = (menus: Menu[], depth = 0): (Menu & { depth: number })[] => {
    let result: (Menu & { depth: number })[] = [];
    menus.forEach(m => {
      result.push({ ...m, depth });
      if (m.children) {
        result = result.concat(flattenMenus(m.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = useMemo(() => {
    const all = flattenMenus(data);
    return all.filter(m => {
        const matchName = !searchName || m.name.toLowerCase().includes(searchName.toLowerCase());
        const matchDesc = !searchDescription || (m.description && m.description.toLowerCase().includes(searchDescription.toLowerCase()));
        const matchVisible = searchVisible === '' || String(m.visible) === searchVisible;
        return matchName && matchDesc && matchVisible;
    });
  }, [data, searchName, searchDescription, searchVisible]);

  const fullFlatData = useMemo(() => flattenMenus(data), [data]);

  const handleAdd = () => {
    setCurrentMenu({ 
        type: 'menu', 
        parentId: '0', 
        sort: 1, 
        visible: true,
        isExternal: false,
        isCache: true
    });
    setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentMenu.name || !currentMenu.type) {
          alert("请完善必要信息");
          return;
      }

      const timestamp = new Date().toLocaleString();
      const menuToSave = {
          ...currentMenu,
          parentId: currentMenu.parentId === '0' ? null : currentMenu.parentId,
      } as Menu;

      if (currentMenu.id) {
          const updateNode = (nodes: Menu[]): Menu[] => {
              return nodes.map(n => {
                  if (n.id === currentMenu.id) {
                      return { 
                          ...n, 
                          ...menuToSave,
                          updateTime: timestamp,
                          updater: 'admin' 
                      };
                  }
                  if (n.children) {
                      return { ...n, children: updateNode(n.children) };
                  }
                  return n;
              });
          };
          setData(updateNode(data));
      } else {
          const newId = Date.now().toString();
          const newMenu = { 
              ...menuToSave, 
              id: newId, 
              children: [],
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin'
          };

          if (newMenu.parentId) {
              const addNode = (nodes: Menu[]): Menu[] => {
                  return nodes.map(n => {
                      if (n.id === newMenu.parentId) {
                          return { ...n, children: [...(n.children || []), newMenu] };
                      }
                      if (n.children) {
                          return { ...n, children: addNode(n.children) };
                      }
                      return n;
                  });
              };
              setData(addNode(data));
          } else {
              setData([...data, newMenu]);
          }
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Menu[]): Menu[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : []
              }));
          };
          setData(removeNode(data));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
     if (targetStatusChange) {
         const updateVisible = (items: Menu[]): Menu[] => {
             return items.map(item => {
                 if (item.id === targetStatusChange.id) {
                     return { ...item, visible: targetStatusChange.newVisible };
                 }
                 if (item.children) {
                     return { ...item, children: updateVisible(item.children) };
                 }
                 return item;
             });
         };
         setData(updateVisible(data));
     }
     setConfirmOpen(false);
     setTargetStatusChange(null);
  };

  return (
    <div className="h-full flex flex-col space-y-4">
      <Card className="shrink-0 px-6 py-6">
         <div className="flex flex-col gap-4">
            <div className="flex flex-wrap gap-6 items-center">
                <Input 
                    label="菜单名称"
                    placeholder="菜单名称" 
                    className="w-48" 
                    value={searchName}
                    onChange={(e) => setSearchName(e.target.value)}
                />
                <Input 
                    label="菜单描述"
                    placeholder="描述信息" 
                    className="w-48" 
                    value={searchDescription}
                    onChange={(e) => setSearchDescription(e.target.value)}
                />
                <Select 
                    label="状态"
                    options={[{label: '全部', value: ''}, {label: '显示', value: 'true'}, {label: '隐藏', value: 'false'}]}
                    value={searchVisible}
                    onChange={e => setSearchVisible(e.target.value)}
                    className="w-32"
                />
            </div>

            <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchDescription(''); setSearchVisible(''); }}>重置</Button>
                    <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增菜单</Button>
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
            </div>
         </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-auto">
          <Table columns={activeColumns} data={flatData} />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatData.length} 条</div>
        </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentMenu.id ? "编辑菜单" : "新增菜单"}
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>确定</Button>
            </>
          }
      >
         <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="text-sm font-medium text-slate-300 mb-2 block">类型</label>
                    <div className="flex space-x-4">
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="dir"
                                checked={currentMenu.type === 'dir'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'dir'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'dir' ? 'text-blue-400' : 'text-slate-400'}>目录</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="menu"
                                checked={currentMenu.type === 'menu'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'menu'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'menu' ? 'text-blue-400' : 'text-slate-400'}>菜单</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="button"
                                checked={currentMenu.type === 'button'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'button'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'button' ? 'text-blue-400' : 'text-slate-400'}>按钮</span>
                        </label>
                    </div>
                </div>

                <div className="col-span-2">
                    <Input 
                        label="上级菜单" 
                        value={fullFlatData.find(m => m.id === currentMenu.parentId)?.name || '主目录'}
                        disabled 
                        className="bg-slate-800 cursor-not-allowed"
                    />
                </div>

                <Input 
                    label="菜单名称" 
                    value={currentMenu.name || ''} 
                    onChange={e => setCurrentMenu({...currentMenu, name: e.target.value})} 
                />

                <Input 
                    label="显示排序" 
                    type="number"
                    value={currentMenu.sort || 0} 
                    onChange={e => setCurrentMenu({...currentMenu, sort: parseInt(e.target.value)})} 
                />

                {currentMenu.type !== 'button' && (
                    <div className="col-span-2 flex space-x-4">
                        <div className="flex-1">
                            <Input 
                                label="路由地址" 
                                value={currentMenu.path || ''} 
                                onChange={e => setCurrentMenu({...currentMenu, path: e.target.value})} 
                                placeholder="/system/menu"
                            />
                        </div>
                        <div className="flex-1">
                            <Input 
                                label="组件路径" 
                                value={currentMenu.component || ''} 
                                onChange={e => setCurrentMenu({...currentMenu, component: e.target.value})} 
                                placeholder="views/system/menu/index"
                            />
                        </div>
                    </div>
                )}

                <div className="col-span-2">
                    <Input 
                        label="权限标识" 
                        value={currentMenu.permission || ''} 
                        onChange={e => setCurrentMenu({...currentMenu, permission: e.target.value})} 
                        placeholder="system:menu:list"
                    />
                </div>

                <div className="col-span-2">
                    <label className="text-sm text-slate-400 block mb-1.5">菜单描述</label>
                    <textarea 
                        className="w-full bg-[#1e293b] border border-slate-700 rounded p-2 text-sm text-white focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-slate-600"
                        rows={2}
                        placeholder="请输入菜单描述..."
                        value={currentMenu.description || ''}
                        onChange={e => setCurrentMenu({...currentMenu, description: e.target.value})}
                    />
                </div>

                <div className="flex flex-col gap-2">
                    <label className="text-sm text-slate-400">显示状态</label>
                    <div className="flex items-center gap-2">
                        <Switch 
                            checked={currentMenu.visible !== false} 
                            onChange={c => setCurrentMenu({...currentMenu, visible: c})} 
                        />
                        <span className="text-sm text-slate-300">{currentMenu.visible !== false ? '显示' : '隐藏'}</span>
                    </div>
                </div>
            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newVisible ? '显示' : '隐藏'}该菜单吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除菜单"
         message="确定要删除该菜单吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, MinusSquare, Shield, ChevronDown, Folder, UserPlus, Lock, ChevronRight, Download, Settings } from 'lucide-react';
import { MOCK_ROLES, REGIONS, MOCK_DOMAINS, MOCK_MENUS, BUSINESS_TYPES } from '../constants';
import { Role, Domain, Menu } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Type to represent either a domain header or a role item row
type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; roleCount: number; expanded: boolean }
  | { type: 'role'; id: string; data: Role; parentDomainId: string };

export const RoleManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [roleData, setRoleData] = useState<Role[]>(MOCK_ROLES);

  // Expanded Domains State
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});

  // Menu Permissions State (IDs)
  const [selectedMenuIds, setSelectedMenuIds] = useState<Set<string>>(new Set());

  const [isDomainLocked, setIsDomainLocked] = useState(false); 
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Search
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchDomainId, setSearchDomainId] = useState('');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  // --- Mock Transfer Data State ---
  const [sourceData] = useState(() => {
      const list = [];
      for(let i=1; i<=8; i++) list.push({ id: `line-${i}`, name: `互联网专线-电路${i}`, category: 'BIZ_LINE' });
      for(let i=1; i<=8; i++) list.push({ id: `5g-${i}`, name: `5G切片-车间${i}`, category: 'BIZ_5G' });
      for(let i=1; i<=8; i++) list.push({ id: `idc-${i}`, name: `IDC机柜-机房${i}`, category: 'BIZ_IDC' });
      for(let i=1; i<=5; i++) list.push({ id: `comp-${i}`, name: `东数西算-节点${i}`, category: 'BIZ_COMP' });
      return list;
  });
  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);
  const [bizCategoryFilter, setBizCategoryFilter] = useState<string>('all');

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setIsDomainLocked(true); 
    setSelectedMenuIds(new Set(role.menuIds || []));
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleAddInDomain = (domainId: string) => {
    setCurrentRole({ 
        domainId: domainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11']));
    setIsDomainLocked(true);
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'name', header: '名称 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group text-left"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-blue-500 fill-blue-500/10 group-hover:text-blue-400" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.roleCount} 角色</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300 relative text-left">
                      <div className="absolute left-[29px] top-[-20px] bottom-[50%] w-[1px] bg-slate-700"></div>
                      <div className="absolute left-[29px] top-[50%] w-4 h-[1px] bg-slate-700"></div>
                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium hover:text-green-400 transition-colors cursor-default">{row.data.name}</span>
                  </div>
              );
          }
      },
      width: '35%'
    },
    { 
      key: 'code', header: '编码', 
      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic opacity-50">{row.data.code}</span>,
      width: '20%'
    },
    { 
      key: 'desc', header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? <span className="text-slate-400 text-sm truncate block max-w-xs text-left">{row.data.description}</span> : '',
    },
    {
      key: 'action', header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <div className="flex justify-center">
                    <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAddInDomain(row.data.id)}>
                        新增角色
                    </Button>
                </div>
              )
          }
          return (
            <div className="flex space-x-2 justify-center">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>配置</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '200px'
    }
  ], [expandedDomains]); // Re-render when expanded domains change to update icon

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Handle Context Change
  useEffect(() => {
    setSearchName('');
    setSearchCode('');
    setSearchDomainId('');
    if (mode === 'switching' && currentDomain) {
        setExpandedDomains(new Set([currentDomain.id]));
    } else {
        setExpandedDomains(new Set(MOCK_DOMAINS.map(d => d.id)));
    }
  }, [mode, currentDomain]);

  useEffect(() => {
    if (isModalOpen) {
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
        setBizCategoryFilter('all');
    }
  }, [isModalOpen]);

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  // --- Process Data into Flat Tree Structure ---
  const flatTreeData = useMemo(() => {
    // 1. Determine Context
    let contextDomains = MOCK_DOMAINS;
    if (mode === 'switching' && currentDomain) {
        contextDomains = MOCK_DOMAINS.filter(d => d.id === currentDomain.id);
    }

    let filteredRoles = roleData;
    if (searchName) filteredRoles = filteredRoles.filter(r => r.name.includes(searchName));
    if (searchCode) filteredRoles = filteredRoles.filter(r => r.code.includes(searchCode));

    // Strictly filter roles in switching mode
    if (mode === 'switching' && currentDomain) {
        filteredRoles = filteredRoles.filter(r => r.domainId === currentDomain.id);
    }

    const result: TreeItem[] = [];
    contextDomains.forEach(domain => {
        // Filter by Domain ID if selected in local search
        if (searchDomainId && domain.id !== searchDomainId) return;

        const domainRoles = filteredRoles.filter(r => r.domainId === domain.id);

        // If searching by name/code and no roles match, skip this domain
        if ((searchName || searchCode) && domainRoles.length === 0) return; 

        // Auto expand if searching or filtering or switching
        const isExpanded = expandedDomains.has(domain.id) || !!searchName || !!searchCode || !!searchDomainId || (mode === 'switching');

        result.push({
            type: 'domain',
            id: `d-${domain.id}`,
            data: domain,
            roleCount: domainRoles.length,
            expanded: isExpanded
        });

        if (isExpanded) {
            domainRoles.forEach(role => {
                result.push({
                    type: 'role',
                    id: role.id,
                    data: role,
                    parentDomainId: domain.id
                });
            });
        }
    });

    return result;
  }, [roleData, expandedDomains, searchName, searchCode, searchDomainId, mode, currentDomain]);

  // --- Handlers ---
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  // Triggered by Top Button
  const handleGlobalAdd = () => {
    const defaultDomainId = (mode === 'switching' && currentDomain) ? currentDomain.id : (MOCK_DOMAINS[0]?.id || '');

    setCurrentRole({ 
        domainId: defaultDomainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11'])); 
    setIsDomainLocked(mode === 'switching');
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setRoleData(roleData.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      const roleToSave = {
          ...currentRole,
          menuIds: Array.from(selectedMenuIds)
      } as Role;

      if (roleToSave.id) {
          setRoleData(roleData.map(r => r.id === roleToSave.id ? roleToSave : r));
      } else {
          const newRole = { 
              ...roleToSave, 
              id: Date.now().toString(),
              code: roleToSave.code || `ROLE_${Date.now()}` 
          } as Role;
          setRoleData([...roleData, newRole]);
      }
      setIsModalOpen(false);
  };

  // --- Menu Logic ---
  const getChildIds = (menu: Menu): string[] => {
      let ids: string[] = [];
      if (menu.children) {
          menu.children.forEach(child => {
              ids.push(child.id);
              ids = [...ids, ...getChildIds(child)];
          });
      }
      return ids;
  };

  const getParentIds = (targetId: string, menus: Menu[], path: string[] = []): string[] => {
      for (const menu of menus) {
          if (menu.id === targetId) return path;
          if (menu.children) {
              const res = getParentIds(targetId, menu.children, [...path, menu.id]);
              if (res.length > 0) return res;
          }
      }
      return [];
  };

  const toggleMenu = (menu: Menu, checked: boolean) => {
      const newSelected = new Set(selectedMenuIds);
      const childIds = getChildIds(menu);
      if (checked) {
          newSelected.add(menu.id);
          childIds.forEach(id => newSelected.add(id));
          const parentIds = getParentIds(menu.id, MOCK_MENUS);
          parentIds.forEach(id => newSelected.add(id));
      } else {
          newSelected.delete(menu.id);
          childIds.forEach(id => newSelected.delete(id));
      }
      setSelectedMenuIds(newSelected);
  };

  type CheckState = 'checked' | 'unchecked' | 'indeterminate';

  const getMenuState = (menu: Menu): CheckState => {
      if (!menu.children || menu.children.length === 0) {
          return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked';
      }

      let allChecked = true;
      let allUnchecked = true;

      const checkChildren = (children: Menu[]) => {
        for (const child of children) {
            const childIsSelected = selectedMenuIds.has(child.id);
            if (!childIsSelected) allChecked = false;
            else allUnchecked = false;

            if (child.children) {
                checkChildren(child.children);
            }
        }
      };

      checkChildren(menu.children);

      if (allChecked) return 'checked';
      if (allUnchecked) return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked';
      return 'indeterminate';
  };

  const renderMenuTree = (menus: Menu[], depth = 0) => {
      return menus.map(menu => {
          const state = getMenuState(menu);

          return (
              <div key={menu.id}>
                  <div 
                      className={`flex items-center space-x-2 py-1.5 cursor-pointer hover:bg-slate-800 rounded px-2 transition-colors`}
                      style={{ paddingLeft: `${depth * 20 + 8}px` }}
                      onClick={() => toggleMenu(menu, state !== 'checked')}
                  >
                      {state === 'checked' && <CheckSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'indeterminate' && <MinusSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'unchecked' && <Square size={16} className="text-slate-500 shrink-0" />}

                      <span className={`${state !== 'unchecked' ? 'text-white' : 'text-slate-400'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderMenuTree(menu.children, depth + 1)}
              </div>
          );
      });
  };

  const isAllRegionsSelected = (currentRole.regionScope?.length || 0) === REGIONS.length;
  const toggleAllRegions = () => {
      if (isAllRegionsSelected) {
          setCurrentRole({ ...currentRole, regionScope: [] });
      } else {
          setCurrentRole({ ...currentRole, regionScope: REGIONS.map(r => r.code) });
      }
  };
  const toggleRegion = (code: string) => {
      const current = currentRole.regionScope || [];
      if (current.includes(code)) {
          setCurrentRole({ ...currentRole, regionScope: current.filter(c => c !== code) });
      } else {
          setCurrentRole({ ...currentRole, regionScope: [...current, code] });
      }
  };

  const filteredSourceData = useMemo(() => {
      let res = sourceData.filter(d => !targetKeys.includes(d.id));
      if (bizCategoryFilter !== 'all') {
          res = res.filter(d => d.category === bizCategoryFilter);
      }
      return res;
  }, [sourceData, targetKeys, bizCategoryFilter]);

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0 px-6 py-6">
         <div className="flex flex-col gap-4">
            {/* Row 1: Search Inputs */}
            <div className="flex flex-wrap gap-6 items-center">
                <Input label="角色名称" placeholder="搜索角色名称" className="w-48" value={searchName} onChange={e => setSearchName(e.target.value)} />
                <Input label="角色编码" placeholder="搜索角色编码" className="w-48" value={searchCode} onChange={e => setSearchCode(e.target.value)} />
                {/* Hide Domain Select in Switching Mode as it is implicit */}
                {mode === 'fusion' && (
                    <Select 
                        label="所属域"
                        className="w-40" 
                        options={[{label: '全部域', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                        value={searchDomainId}
                        onChange={e => setSearchDomainId(e.target.value)}
                    />
                )}
            </div>

            {/* Row 2: Actions */}
            <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchCode(''); setSearchDomainId(''); }}>重置</Button>
                    <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<UserPlus size={16} />} onClick={handleGlobalAdd}>新增角色</Button>
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
            </div>
         </div>
      </Card>

      {/* Role Tree Table */}
      <Card className="flex-1 overflow-hidden flex flex-col" title={mode === 'switching' && currentDomain ? `[${currentDomain.name}] 角色权限树` : "角色权限树"}>
        <div className="flex-1 overflow-auto">
          <Table columns={activeColumns} data={flatTreeData} keyField="id" />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
        </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      {/* Add/Edit Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentRole.id ? "配置角色权限" : "新增角色"}
        size="lg"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>保存配置</Button>
            </>
          }
      >
         <div className="h-[550px] flex flex-col">
            {/* Tabs */}
            <div className="flex border-b border-slate-700 mb-4 shrink-0 bg-[#0f172a] -mx-8 px-8 sticky top-0 z-10">
                {(['info', 'menu', 'data'] as const).map(tab => (
                    <button 
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-400 hover:text-slate-200'}`}
                    >
                        {tab === 'info' && '基本信息'}
                        {tab === 'menu' && '菜单权限'}
                        {tab === 'data' && '数据权限'}
                    </button>
                ))}
            </div>

            {/* Tab Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1">
                {/* 1. Basic Info */}
                {activeTab === 'info' && (
                    <div className="space-y-6 max-w-2xl mx-auto mt-4">
                         <SectionTitle title="角色基础信息" />
                         <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                            <Input 
                                label="角色名称" 
                                value={currentRole.name || ''} 
                                onChange={e => setCurrentRole({...currentRole, name: e.target.value})}
                                placeholder="请输入角色名称" 
                            />
                            <Input 
                                label="角色编码" 
                                value={currentRole.code || ''} 
                                onChange={e => setCurrentRole({...currentRole, code: e.target.value})}
                                placeholder="ROLE_..." 
                                disabled={!!currentRole.id}
                            />
                            <div className="relative">
                                <Select 
                                    label="所属域" 
                                    options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                    value={currentRole.domainId}
                                    onChange={e => setCurrentRole({...currentRole, domainId: e.target.value})}
                                    disabled={isDomainLocked} 
                                    className={isDomainLocked ? "opacity-60 cursor-not-allowed bg-slate-800" : ""}
                                />
                                {isDomainLocked && (
                                    <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                        <Lock size={12} />
                                        <span className="text-xs">已锁定</span>
                                    </div>
                                )}
                            </div>
                            <Input 
                                label="描述" 
                                value={currentRole.description || ''}
                                onChange={e => setCurrentRole({...currentRole, description: e.target.value})}
                            />
                        </div>
                    </div>
                )}
                {/* 2. Menu Permissions */}
                {activeTab === 'menu' && (
                    <div className="space-y-4">
                        <div className="bg-blue-900/10 border border-blue-900/30 rounded p-3 text-xs text-blue-300 mb-2 flex items-center gap-2">
                             <CheckSquare size={14} />
                            提示：勾选该角色可访问的菜单资源。系统支持父子菜单联动选择。
                        </div>
                        <div className="border border-slate-700 rounded-lg p-5 bg-[#1e293b]/30 min-h-[350px]">
                            {renderMenuTree(MOCK_MENUS)}
                        </div>
                    </div>
                )}
                {/* 3. Data Permissions */}
                {activeTab === 'data' && (
                    <div className="space-y-6">
                        {/* Region Scope */}
                        <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <div className="flex justify-between items-center mb-4">
                                <SectionTitle title="区域范围 (Region Scope)" className="mb-0" />
                                <label className="flex items-center space-x-2 cursor-pointer text-xs text-blue-400 hover:text-blue-300 select-none bg-blue-900/20 px-2 py-1 rounded">
                                    <input 
                                        type="checkbox" 
                                        className="rounded bg-slate-900 border-slate-600 text-blue-500"
                                        checked={isAllRegionsSelected}
                                        onChange={toggleAllRegions}
                                    />
                                    <span>全选所有区域</span>
                                </label>
                            </div>
                            <div className="grid grid-cols-4 gap-4">
                                {REGIONS.slice(0, 16).map(reg => (
                                    <label key={reg.code} className="flex items-center space-x-2 cursor-pointer hover:text-blue-400 group">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900" 
                                            checked={currentRole.regionScope?.includes(reg.code) || false}
                                            onChange={() => toggleRegion(reg.code)}
                                        />
                                        <span className="text-sm text-slate-400 group-hover:text-slate-200">{reg.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                         {/* Business Scope (Transfer) */}
                         <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <SectionTitle title="业务范围 (Business Scope)" />

                            <div className="flex h-[320px] gap-4">
                                {/* Source Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex flex-col gap-2">
                                        <div className="flex justify-between items-center px-1 pt-1">
                                            <span className="text-xs font-semibold text-slate-300">待选业务</span>
                                            <span className="text-xs text-slate-500">{sourceSelected.length} 选中</span>
                                        </div>

                                        {/* Business Category Filter */}
                                        <div className="flex flex-wrap gap-1 pb-1">
                                            <button 
                                                onClick={() => setBizCategoryFilter('all')}
                                                className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === 'all' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                            >
                                                全部
                                            </button>
                                            {BUSINESS_TYPES.map(bt => (
                                                <button 
                                                    key={bt.code}
                                                    onClick={() => setBizCategoryFilter(bt.code)}
                                                    className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === bt.code ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                                >
                                                    {bt.name}
                                                </button>
                                            ))}
                                        </div>

                                        <Input placeholder="搜索业务实例..." className="text-xs py-1.5 h-8" />
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {filteredSourceData.map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${sourceSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    sourceSelected.includes(item.id) 
                                                      ? setSourceSelected(sourceSelected.filter(id => id !== item.id))
                                                      : setSourceSelected([...sourceSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={sourceSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                        {filteredSourceData.length === 0 && (
                                            <div className="text-center py-8 text-xs text-slate-500">无匹配数据</div>
                                        )}
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-col justify-center gap-3 px-2">
                                    <Button size="sm" variant="secondary" onClick={moveToRight} disabled={sourceSelected.length === 0} title="添加选中">
                                        <ChevronRight size={16} />
                                    </Button>
                                    <Button size="sm" variant="secondary" onClick={moveToLeft} disabled={targetSelected.length === 0} title="移除选中" className="rotate-180">
                                        <ChevronRight size={16} />
                                    </Button>
                                </div>

                                {/* Target Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[90px]">
                                        <span className="text-xs font-semibold text-slate-300 pl-1">已授权业务 ({targetKeys.length})</span>
                                        <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setTargetKeys([])}>清空</Button>
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {sourceData.filter(d => targetKeys.includes(d.id)).map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${targetSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    targetSelected.includes(item.id) 
                                                      ? setTargetSelected(targetSelected.filter(id => id !== item.id))
                                                      : setTargetSelected([...targetSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={targetSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         title="删除角色"
         message="确定要删除该角色吗？此操作不可恢复，且可能导致关联用户失去权限。"
         onConfirm={confirmDelete}
         onCancel={() => { setConfirmOpen(false); setDeleteId(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Folder, ChevronDown, ChevronRight, User as UserIcon, Mail, Phone, Shield, Lock, Eye, CheckSquare, Check, AlertTriangle, RefreshCcw, Settings, Grid, MoreHorizontal, Building2, GitBranch, Download } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS, MOCK_MENUS, REGIONS, BUSINESS_TYPES, MOCK_DEPTS } from '../constants';
import { User, Domain, Role, Menu, Department } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Unified Node Type for the Sidebar
type MixedNode = {
    id: string;
    name: string;
    type: 'domain' | 'dept';
    data: Domain | Department;
    children?: MixedNode[];
};

export const UserManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  const [selectedNode, setSelectedNode] = useState<{ id: string, type: 'domain' | 'dept' } | null>(null);
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  const [userData, setUserData] = useState<User[]>(MOCK_USERS);

  const [searchUsername, setSearchUsername] = useState('');
  const [searchRoleId, setSearchRoleId] = useState(''); 
  const [searchDomainId, setSearchDomainId] = useState(''); 
  const [searchStatus, setSearchStatus] = useState('');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});
  const [selectedRoleIds, setSelectedRoleIds] = useState<Set<string>>(new Set());

  const [auditUser, setAuditUser] = useState<User | null>(null);

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const handleEdit = (user: User) => {
      setCurrentUser({ ...user });
      const roleIds = user.roles
        .filter(r => r.targetDomainId === user.baseDomainId) 
        .map(r => r.roleId);
      setSelectedRoleIds(new Set(roleIds));
      setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
        key: 'serial', header: '序号', accessor: 'serialNumber', width: '60px' 
    },
    { 
        key: 'user', header: '用户', 
        accessor: (row: User) => (
            <div className="flex items-center gap-3 text-left">
                 <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center border border-slate-600 text-slate-300 shrink-0">
                      <UserIcon size={14} />
                 </div>
                 <div>
                    <div className="text-sm font-medium text-slate-200">{row.username}</div>
                    {row.deptId && (
                        <div className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5">
                            <GitBranch size={10} />
                            {MOCK_DEPTS.find(d => d.id === row.deptId)?.name || row.deptId}
                        </div>
                    )}
                 </div>
            </div>
        )
    },
    { key: 'realName', header: '真实姓名', accessor: 'realName' },
    { 
        key: 'role', header: '所属角色', 
        accessor: (row: User) => {
            const roles = row.roles.map(r => MOCK_ROLES.find(mr => mr.id === r.roleId)?.name).filter(Boolean);
            if (roles.length === 0) return <span className="text-slate-500 text-xs">-</span>;
            return (
                <div className="flex flex-wrap gap-1 justify-center">
                    {roles.map((r, i) => <Badge key={i} color="blue">{r}</Badge>)}
                </div>
            )
        }
    },
    { 
        key: 'domain', header: '所属域', 
        accessor: (row: User) => (
            <div className="flex items-center text-slate-300 text-sm justify-center">
                <Folder size={12} className="mr-1.5 text-blue-500"/>
                {MOCK_DOMAINS.find(d => d.id === row.baseDomainId)?.name}
            </div>
        )
    },
    { key: 'createTime', header: '创建时间', accessor: (row: User) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'updateTime', header: '更新时间', accessor: (row: User) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    { 
        key: 'status', header: '状态', 
        accessor: (row: User) => (
            <div className="flex justify-center">
                <Switch 
                    checked={row.status === 'active'} 
                    onChange={(checked) => initiateStatusChange(row, checked)} 
                />
            </div>
        ),
        width: '80px'
    },
    {
      key: 'action', header: '操作',
      accessor: (row: User) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-yellow-500 hover:!text-yellow-400" icon={<Eye size={14} />} onClick={() => setAuditUser(row)}>权限</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      ),
      width: '200px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Initialize
  useEffect(() => {
      // Set default selected node
      if (mode === 'switching' && currentDomain) {
          setSelectedNode({ id: currentDomain.id, type: 'domain' });
          setExpandedKeys(new Set([currentDomain.id]));
          // Also set the search domain to current domain implicitly for UI consistency (though logic handles it)
          setSearchDomainId(currentDomain.id);
      } else {
          // Find root domain
          const root = MOCK_DOMAINS.find(d => !d.parentId);
          if (root) {
              setSelectedNode({ id: root.id, type: 'domain' });
              setExpandedKeys(new Set([root.id]));
          }
          setSearchDomainId('');
      }
  }, [mode, currentDomain]);

  // --- Left Tree Logic (Mixed) ---
  const mixedTree = useMemo(() => {
      // 1. Convert Domains to MixedNodes
      const domainNodes = new Map<string, MixedNode>();

      // Filter domains based on mode
      let visibleDomains = MOCK_DOMAINS;
      if (mode === 'switching' && currentDomain) {
          visibleDomains = [currentDomain];
      }

      visibleDomains.forEach(d => {
          domainNodes.set(d.id, {
              id: d.id,
              name: d.name,
              type: 'domain',
              data: d,
              children: []
          });
      });

      const rootNodes: MixedNode[] = [];

      // 2. Build Domain Hierarchy
      visibleDomains.forEach(d => {
          const node = domainNodes.get(d.id)!;
          if (d.parentId && domainNodes.has(d.parentId)) {
              domainNodes.get(d.parentId)!.children!.push(node);
          } else {
              rootNodes.push(node);
          }
      });

      // 3. Attach Departments
      const convertDept = (d: Department): MixedNode => ({
          id: d.id,
          name: d.name,
          type: 'dept',
          data: d,
          children: d.children ? d.children.map(convertDept) : []
      });

      domainNodes.forEach((node) => {
          const domainRootDepts = MOCK_DEPTS.filter(d => d.domainId === node.id && d.parentId === null);
          const deptNodes = domainRootDepts.map(d => {
              const buildDeptTree = (root: Department): MixedNode => {
                  const children = MOCK_DEPTS.filter(child => child.parentId === root.id);
                  return {
                      id: root.id,
                      name: root.name,
                      type: 'dept',
                      data: root,
                      children: children.map(buildDeptTree)
                  };
              };
              return buildDeptTree(d);
          });

          node.children = [...(node.children || []), ...deptNodes];
      });

      return rootNodes;
  }, [mode, currentDomain]);

  const toggleExpand = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const renderTreeNodes = (nodes: MixedNode[], depth = 0) => {
      return nodes.map(node => {
          const isExpanded = expandedKeys.has(node.id);
          const isSelected = selectedNode?.id === node.id;
          const hasChildren = node.children && node.children.length > 0;

          return (
              <div key={node.id}>
                  <div 
                      className={`flex items-center py-2 px-2 cursor-pointer transition-all rounded-md mb-1 border border-transparent ${isSelected ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-300 hover:bg-slate-800 hover:border-slate-700'}`}
                      style={{ paddingLeft: `${depth * 16 + 8}px` }}
                      onClick={() => setSelectedNode({ id: node.id, type: node.type })}
                  >
                      <div 
                        className={`mr-1 p-0.5 rounded hover:bg-white/20 transition-colors ${hasChildren ? 'visible' : 'invisible'}`}
                        onClick={(e) => toggleExpand(e, node.id)}
                      >
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </div>

                      {node.type === 'domain' ? (
                          <Building2 size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-blue-500'}`} />
                      ) : (
                          <GitBranch size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-yellow-500'}`} />
                      )}

                      <span className="text-sm truncate select-none font-medium">{node.name}</span>
                  </div>
                  {isExpanded && node.children && renderTreeNodes(node.children, depth + 1)}
              </div>
          );
      });
  };

  // --- Right Table Data Logic ---
  const filteredUsers = useMemo(() => {
      return userData.filter(u => {
          if (selectedNode) {
              if (selectedNode.type === 'domain') {
                  if (u.baseDomainId !== selectedNode.id) return false;
              } else {
                  if (u.deptId !== selectedNode.id) return false;
              }
          }

          const matchUser = !searchUsername || u.username.toLowerCase().includes(searchUsername.toLowerCase()) || u.realName.includes(searchUsername);
          const matchRole = !searchRoleId || u.roles.some(r => r.roleId === searchRoleId);
          const matchDomain = !searchDomainId || u.baseDomainId === searchDomainId;

          const matchStatus = !searchStatus || u.status === searchStatus;

          return matchUser && matchRole && matchDomain && matchStatus;
      });
  }, [userData, selectedNode, searchUsername, searchRoleId, searchDomainId, searchStatus]);

  // Prepared data with serial numbers
  const tableData = useMemo(() => {
      return filteredUsers.map((u, index) => ({
          ...u,
          serialNumber: index + 1
      }));
  }, [filteredUsers]);

  const handleAdd = () => {
      if (!selectedNode || selectedNode.type !== 'domain') {
          if (selectedNode?.type === 'dept') {
             const dept = MOCK_DEPTS.find(d => d.id === selectedNode.id);
             if (dept) {
                 setCurrentUser({ 
                    status: 'active', 
                    baseDomainId: dept.domainId,
                    deptId: dept.id
                 });
                 setSelectedRoleIds(new Set());
                 setIsModalOpen(true);
                 return;
             }
          }
          alert("请先选择左侧组织机构(域)");
          return;
      }
      setCurrentUser({ 
          status: 'active', 
          baseDomainId: selectedNode.id
      });
      setSelectedRoleIds(new Set());
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentUser.username || !currentUser.realName || !currentUser.baseDomainId) {
          alert("请完善基本信息");
          return;
      }

      const newRoles = Array.from(selectedRoleIds).map(rId => {
          const roleDef = MOCK_ROLES.find(r => r.id === rId);
          return {
              roleId: rId,
              targetDomainId: currentUser.baseDomainId!,
              roleName: roleDef?.name
          };
      });

      const timestamp = new Date().toLocaleString();

      if (currentUser.id) {
          setUserData(userData.map(u => u.id === currentUser.id ? { 
              ...u, 
              ...currentUser, 
              roles: newRoles,
              updateTime: timestamp,
              updater: 'admin'
          } as User : u));
      } else {
          const newUser = {
              ...currentUser,
              id: Date.now().toString(),
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin',
              roles: newRoles
          } as User;
          setUserData([...userData, newUser]);
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setUserData(userData.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setUserData(userData.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  // --- Helpers for Modal ---
  const getDeptOptions = (domainId: string) => {
      const depts = MOCK_DEPTS.filter(d => d.domainId === domainId);
      const buildHierarchy = (parentId: string | null = null, depth = 0): {id: string, name: string, depth: number}[] => {
          const children = depts.filter(d => d.parentId === parentId);
          let res: {id: string, name: string, depth: number}[] = [];
          children.forEach(c => {
              res.push({ id: c.id, name: c.name, depth });
              res = res.concat(buildHierarchy(c.id, depth + 1));
          });
          return res;
      };
      return buildHierarchy(null, 0);
  };

  const deptOptions = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return getDeptOptions(currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const availableRoles = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return MOCK_ROLES.filter(r => r.domainId === currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const toggleRoleSelection = (roleId: string) => {
      const newSet = new Set(selectedRoleIds);
      if (newSet.has(roleId)) newSet.delete(roleId);
      else newSet.add(roleId);
      setSelectedRoleIds(newSet);
  };

  // --- Permission Audit Helper ---
  const calculateEffectivePermissions = (user: User) => {
      const userRoles = user.roles.map(ur => MOCK_ROLES.find(r => r.id === ur.roleId)).filter(Boolean) as Role[];
      const allMenuIds = new Set<string>();
      const allRegions = new Set<string>();
      const allBizTypes = new Set<string>();

      userRoles.forEach(role => {
          role.menuIds?.forEach(id => allMenuIds.add(id));
          role.regionScope?.forEach(r => allRegions.add(r));
          role.bizCategoryScope?.forEach(b => allBizTypes.add(b));
      });

      return { menus: allMenuIds, regions: allRegions, bizTypes: allBizTypes, roles: userRoles };
  };

  const renderAuditMenuTree = (menus: Menu[], accessibleIds: Set<string>, depth = 0) => {
      return menus.map(menu => {
          const hasAccess = accessibleIds.has(menu.id);
          return (
              <div key={menu.id}>
                  <div className={`flex items-center space-x-2 py-1.5 rounded px-2`} style={{ paddingLeft: `${depth * 20 + 8}px` }}>
                      {hasAccess ? <Check size={16} className="text-green-500 shrink-0" /> : <div className="w-4 h-4" /> }
                      <span className={`${hasAccess ? 'text-white font-medium' : 'text-slate-600'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderAuditMenuTree(menu.children, accessibleIds, depth + 1)}
              </div>
          );
      });
  };

  return (
    <div className="h-full flex gap-4 overflow-hidden">
        {/* Left Sidebar: Domain Tree */}
        <Card className="w-72 shrink-0 flex flex-col" title="组织机构">
            <div className="mb-3">
                <Input placeholder="搜索组织..." className="text-xs h-8" prefix={<Search size={14}/>} />
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar -mx-2 px-2">
                {renderTreeNodes(mixedTree)}
            </div>
        </Card>

        {/* Right Content */}
        <div className="flex-1 flex flex-col gap-4 overflow-hidden">
            {/* 1. Search Area */}
            <Card className="shrink-0 px-6 py-6">
                <div className="flex flex-col gap-4">
                    {/* Row 1: Search Conditions */}
                    <div className="flex flex-wrap gap-6 items-end">
                        <Input 
                            label="用户名/姓名"
                            placeholder="请输入" 
                            className="w-40" 
                            value={searchUsername} 
                            onChange={e => setSearchUsername(e.target.value)}
                        />
                        {/* New: Role Search */}
                        <div className="w-40">
                            <Select 
                                label="所属角色"
                                options={[{label: '全部', value: ''}, ...MOCK_ROLES.map(r => ({label: r.name, value: r.id}))]}
                                value={searchRoleId}
                                onChange={e => setSearchRoleId(e.target.value)}
                            />
                        </div>
                        {/* New: Domain Search */}
                        <div className="w-40">
                            <Select 
                                label="所属域"
                                options={[{label: '全部', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                                value={searchDomainId}
                                onChange={e => setSearchDomainId(e.target.value)}
                                disabled={mode === 'switching'} // Lock if in switching mode
                                className={mode === 'switching' ? 'opacity-50 cursor-not-allowed' : ''}
                            />
                        </div>
                        <Select
                            label="状态"
                            options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '锁定', value: 'locked'}]}
                            value={searchStatus}
                            onChange={e => setSearchStatus(e.target.value)}
                            className="w-32"
                        />
                    </div>

                    {/* Row 2: Actions */}
                    <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                        <div className="flex gap-3">
                            <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                            <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchUsername(''); setSearchRoleId(''); setSearchDomainId(''); setSearchStatus(''); }}>重置</Button>
                            <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增用户</Button>
                            <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                        </div>
                        <div className="flex gap-3">
                            <Button 
                                size="sm" 
                                variant="secondary" 
                                className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                                icon={<Settings size={14} />}
                                onClick={() => setIsColumnConfigOpen(true)}
                            >
                                列配置
                            </Button>
                        </div>
                    </div>
                </div>
            </Card>

            {/* 2. Table Area */}
            <Card className="flex-1 overflow-hidden flex flex-col">
                <div className="flex justify-between items-center px-4 py-2 border-b border-slate-800/50 bg-slate-900/20">
                     <span className="text-xs text-slate-500">
                         当前过滤: <span className="text-blue-400 font-medium">{selectedNode ? (selectedNode.type === 'domain' ? '域' : '部门') + ' - ' + (mixedTree.find(n => n.id === selectedNode.id)?.name || MOCK_DEPTS.find(d => d.id === selectedNode.id)?.name) : '全部'}</span>
                     </span>
                </div>

                <div className="flex-1 overflow-auto">
                    <Table columns={activeColumns} data={tableData} keyField="id" />
                </div>
                <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                    <div className="text-sm text-slate-400">共 {filteredUsers.length} 条记录</div>
                </div>
            </Card>
        </div>

        <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
        />

        {/* Add/Edit Modal */}
        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title={currentUser.id ? "编辑用户" : "新增用户"}
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={handleSave}>确定</Button>
                </>
              }
        >
            <div className="space-y-8">
                {/* 1. Basic Info */}
                <div>
                    <SectionTitle title="基本信息" />
                    <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                        <Input 
                            label="用户名" 
                            placeholder="登录账号" 
                            value={currentUser.username || ''}
                            onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                        />
                        <Input 
                            label="真实姓名" 
                            placeholder="员工姓名" 
                            value={currentUser.realName || ''}
                            onChange={e => setCurrentUser({...currentUser, realName: e.target.value})}
                        />
                        <Input 
                            label="手机号" 
                            placeholder="11位手机号" 
                            value={currentUser.phone || ''}
                            onChange={e => setCurrentUser({...currentUser, phone: e.target.value})}
                        />
                        <Input 
                            label="邮箱" 
                            placeholder="Email" 
                            value={currentUser.email || ''}
                            onChange={e => setCurrentUser({...currentUser, email: e.target.value})}
                        />

                        {/* Domain Field (ReadOnly) */}
                        <div className="relative">
                             <Select 
                                label="归属组织 (Domain)" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentUser.baseDomainId}
                                disabled={true}
                                className="opacity-60 cursor-not-allowed bg-slate-800"
                             />
                             <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                <Lock size={12} />
                                <span className="text-xs">已锁定</span>
                             </div>
                        </div>

                        {/* Department Select (Dynamic) */}
                        <div className="relative">
                            <label className="text-sm text-slate-400 block mb-1.5">所属部门</label>
                            <select 
                                className="w-full px-3 py-2 bg-[#1e293b] border border-slate-700 rounded focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-white appearance-none hover:border-slate-600 text-sm"
                                value={currentUser.deptId || ''}
                                onChange={e => setCurrentUser({...currentUser, deptId: e.target.value})}
                            >
                                <option value="">-- 请选择部门 --</option>
                                {deptOptions.map(d => (
                                    <option key={d.id} value={d.id}>
                                        {'\u00A0\u00A0'.repeat(d.depth)} {d.depth > 0 ? '└ ' : ''}{d.name}
                                    </option>
                                ))}
                            </select>
                            <ChevronDown size={14} className="absolute right-3 top-[38px] pointer-events-none text-slate-500" />
                        </div>

                         <div className="col-span-2">
                            <label className="text-sm text-slate-400 font-normal mb-1 block">账户状态</label>
                            <div className="flex items-center gap-3 mt-1">
                                <Switch 
                                    checked={currentUser.status === 'active'}
                                    onChange={c => setCurrentUser({...currentUser, status: c ? 'active' : 'locked'})}
                                />
                                <span className={`text-sm ${currentUser.status === 'active' ? 'text-green-400' : 'text-red-400'}`}>
                                    {currentUser.status === 'active' ? '正常启用' : '已锁定'}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* 2. Role Config */}
                <div>
                    <div className="flex justify-between items-center mb-4">
                        <SectionTitle title="角色分配" className="mb-0" />
                        <span className="text-xs font-normal text-slate-500 bg-slate-800/50 px-2 py-1 rounded">
                            组织: {MOCK_DOMAINS.find(d => d.id === currentUser.baseDomainId)?.name}
                        </span>
                    </div>

                    <div className="bg-[#1e293b]/50 rounded border border-slate-700 p-5 min-h-[100px]">
                        {availableRoles.length > 0 ? (
                            <div className="grid grid-cols-2 gap-4">
                                {availableRoles.map(role => (
                                    <label key={role.id} className={`flex items-start p-3 rounded cursor-pointer border transition-all ${selectedRoleIds.has(role.id) ? 'bg-blue-600/10 border-blue-500/50' : 'bg-slate-800/50 border-transparent hover:border-slate-600'}`}>
                                        <input 
                                            type="checkbox" 
                                            className="mt-1 rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900 mr-3 h-4 w-4"
                                            checked={selectedRoleIds.has(role.id)}
                                            onChange={() => toggleRoleSelection(role.id)}
                                        />
                                        <div>
                                            <div className={`text-sm font-medium ${selectedRoleIds.has(role.id) ? 'text-blue-100' : 'text-slate-300'}`}>{role.name}</div>
                                            <div className="text-xs text-slate-500 mt-0.5">{role.code}</div>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-500 py-6">
                                <Shield size={32} className="mb-3 opacity-20"/>
                                <span className="text-sm">该组织下暂无可用角色，请先在角色管理中配置。</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </Modal>

        {/* --- Permission Audit Modal --- */}
        {auditUser && (
            <Modal
                isOpen={!!auditUser}
                onClose={() => setAuditUser(null)}
                title={`权限审计 - ${auditUser.realName}`}
                size="lg"
                footer={<Button onClick={() => setAuditUser(null)}>关闭</Button>}
            >
                <div className="space-y-8">
                    {/* Role Summary */}
                    <div>
                        <SectionTitle title="生效角色" />
                        <div className="bg-slate-800/40 border border-slate-700 rounded-lg p-5">
                            <div className="flex flex-wrap gap-3">
                                {calculateEffectivePermissions(auditUser).roles.map((r, idx) => (
                                    <div key={idx} className="flex items-center gap-2 bg-blue-900/30 border border-blue-500/30 text-blue-200 px-3 py-1.5 rounded text-sm">
                                        <Shield size={14} className="text-blue-400"/>
                                        <span className="font-medium">{r.name}</span>
                                        <span className="opacity-50 text-xs border-l border-blue-500/30 pl-2 ml-1">{r.code}</span>
                                    </div>
                                ))}
                                {calculateEffectivePermissions(auditUser).roles.length === 0 && (
                                    <span className="text-slate-500 text-sm italic flex items-center">
                                        <AlertTriangle size={16} className="mr-2"/> 未分配任何有效角色
                                    </span>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-8 h-[450px]">
                        {/* Functional Permissions */}
                        <div className="flex flex-col">
                            <SectionTitle title="功能权限" />
                            <div className="flex-1 border border-slate-700 rounded-lg bg-[#1e293b]/30 overflow-hidden flex flex-col">
                                <div className="px-4 py-3 border-b border-slate-700 bg-slate-800/50 flex items-center justify-between">
                                    <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">菜单资源</span>
                                    <span className="text-xs text-green-500 flex items-center gap-1"><CheckSquare size={12}/> 已授权</span>
                                </div>
                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                                    {renderAuditMenuTree(MOCK_MENUS, calculateEffectivePermissions(auditUser).menus)}
                                </div>
                            </div>
                        </div>

                        {/* Data Permissions */}
                        <div className="flex flex-col">
                             <SectionTitle title="数据范围" />
                             <div className="flex-1 border border-slate-700 rounded-lg bg-[#1e293b]/30 overflow-hidden flex flex-col">
                                <div className="px-4 py-3 border-b border-slate-700 bg-slate-800/50">
                                    <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">数据维度</span>
                                </div>
                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-4">
                                     <div>
                                         <div className="text-xs text-slate-500 mb-2 font-medium">区域范围</div>
                                         <div className="flex flex-wrap gap-2">
                                             {calculateEffectivePermissions(auditUser).regions.size > 0 ? (
                                                 Array.from(calculateEffectivePermissions(auditUser).regions).map(rCode => (
                                                     <Badge key={rCode} color="gray">{REGIONS.find(r => r.code === rCode)?.name || rCode}</Badge>
                                                 ))
                                             ) : <span className="text-xs text-slate-600 italic">无特定区域限制</span>}
                                         </div>
                                     </div>
                                     <div>
                                         <div className="text-xs text-slate-500 mb-2 font-medium">业务类型</div>
                                         <div className="flex flex-wrap gap-2">
                                             {calculateEffectivePermissions(auditUser).bizTypes.size > 0 ? (
                                                 Array.from(calculateEffectivePermissions(auditUser).bizTypes).map(bCode => (
                                                     <Badge key={bCode} color="blue">{BUSINESS_TYPES.find(b => b.code === bCode)?.name || bCode}</Badge>
                                                 ))
                                             ) : <span className="text-xs text-slate-600 italic">无特定业务限制</span>}
                                         </div>
                                     </div>
                                </div>
                             </div>
                        </div>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Folder, ChevronDown, ChevronRight, Phone, Mail, User, Grid, RefreshCcw, Settings, Lock, Building2, Download } from 'lucide-react';
import { MOCK_DEPTS, MOCK_DOMAINS } from '../constants';
import { Department, Domain } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Unified Node Type for the Sidebar
type MixedNode = {
    id: string;
    name: string;
    type: 'domain' | 'dept';
    data: Domain | Department;
    children?: MixedNode[];
};

export const DeptManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  // -- Selection State --
  const [selectedDomainId, setSelectedDomainId] = useState<string>('');
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  // -- Data State (Departments) --
  const [deptData, setDeptData] = useState<Department[]>(MOCK_DEPTS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [expandedTableKeys, setExpandedTableKeys] = useState<Set<string>>(new Set(['1', '11', '12'])); 

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Edit/Add State
  const [currentDept, setCurrentDept] = useState<Partial<Department>>({});

  // Confirm Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const toggleTableExpand = (id: string) => {
      const newSet = new Set(expandedTableKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedTableKeys(newSet);
  };

  const handleEdit = (dept: Department) => {
      setCurrentDept({ ...dept });
      setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const initiateStatusChange = (dept: Department, checked: boolean) => {
      setTargetStatusChange({ id: dept.id, newStatus: checked ? 'active' : 'inactive' });
      setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
      {
          key: 'name', header: '部门名称',
          accessor: (row: any) => (
              <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center text-left">
                  {row.children && row.children.length > 0 ? (
                      <button onClick={() => toggleTableExpand(row.id)} className="mr-2 text-slate-400 hover:text-white">
                          {expandedTableKeys.has(row.id) ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </button>
                  ) : <span className="w-[22px]"></span>}
                  <Folder size={16} className="mr-2 text-blue-500" />
                  <span className="text-slate-200 font-medium">{row.name}</span>
              </div>
          ),
          width: '30%'
      },
      { key: 'leader', header: '负责人', accessor: 'leader', width: '15%' },
      { key: 'phone', header: '联系电话', accessor: 'phone', width: '15%' },
      { key: 'sort', header: '排序', accessor: 'sort', width: '10%' },
      {
          key: 'status', header: '状态',
          accessor: (row: Department) => (
              <div className="flex justify-center">
                  <Switch 
                      checked={row.status === 'active'} 
                      onChange={(c) => initiateStatusChange(row, c)} 
                  />
              </div>
          ),
          width: '10%'
      },
      { key: 'createTime', header: '创建时间', accessor: 'createTime' },
      {
          key: 'action', header: '操作',
          accessor: (row: Department) => (
              <div className="flex space-x-2 justify-center">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-green-500 hover:!text-green-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.id)}>新增下级</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          ),
          width: '250px'
      }
  ], [expandedTableKeys]);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // --- Initialization ---
  useEffect(() => {
      // Set default selected domain
      if (mode === 'switching' && currentDomain) {
          setSelectedDomainId(currentDomain.id);
          setExpandedKeys(new Set([currentDomain.id]));
      } else {
          // Find root
          const root = MOCK_DOMAINS.find(d => !d.parentId);
          if (root) {
              setSelectedDomainId(root.id);
              setExpandedKeys(new Set([root.id]));
          }
      }
  }, [mode, currentDomain]);

  // --- Left Tree Logic (Mixed Domain + Depts) ---
  const mixedTree = useMemo(() => {
      // 1. Convert Domains to MixedNodes
      const domainNodes = new Map<string, MixedNode>();

      // Filter domains based on mode
      let visibleDomains = MOCK_DOMAINS;
      if (mode === 'switching' && currentDomain) {
          visibleDomains = [currentDomain];
      }

      visibleDomains.forEach(d => {
          domainNodes.set(d.id, {
              id: d.id,
              name: d.name,
              type: 'domain',
              data: d,
              children: []
          });
      });

      const rootNodes: MixedNode[] = [];

      // 2. Build Domain Hierarchy
      visibleDomains.forEach(d => {
          const node = domainNodes.get(d.id)!;
          if (d.parentId && domainNodes.has(d.parentId)) {
              domainNodes.get(d.parentId)!.children!.push(node);
          } else {
              rootNodes.push(node);
          }
      });

      // 3. Attach Departments to Domains
      const convertDept = (d: Department): MixedNode => ({
          id: d.id,
          name: d.name,
          type: 'dept',
          data: d,
          children: d.children ? d.children.map(convertDept) : []
      });

      domainNodes.forEach((node) => {
          const roots = deptData.filter(d => d.domainId === node.id);
          const deptNodes = roots.map(convertDept);
          node.children = [...(node.children || []), ...deptNodes];
      });

      return rootNodes;
  }, [mode, currentDomain, deptData]);

  const toggleExpand = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const handleSidebarClick = (node: MixedNode) => {
      if (node.type === 'domain') {
          setSelectedDomainId(node.id);
      } else {
          const domainId = (node.data as Department).domainId;
          setSelectedDomainId(domainId);
      }
  };

  const renderSidebarNodes = (nodes: MixedNode[], depth = 0) => {
      return nodes.map(node => {
          const isExpanded = expandedKeys.has(node.id);
          const isSelected = selectedDomainId === (node.type === 'domain' ? node.id : (node.data as Department).domainId) && node.type === 'domain'; 

          const hasChildren = node.children && node.children.length > 0;

          return (
              <div key={node.id}>
                  <div 
                      className={`flex items-center py-2 px-2 cursor-pointer transition-all rounded-md mb-1 border border-transparent ${isSelected ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-300 hover:bg-slate-800 hover:border-slate-700'}`}
                      style={{ paddingLeft: `${depth * 16 + 8}px` }}
                      onClick={() => handleSidebarClick(node)}
                  >
                      <div 
                        className={`mr-1 p-0.5 rounded hover:bg-white/20 transition-colors ${hasChildren ? 'visible' : 'invisible'}`}
                        onClick={(e) => toggleExpand(e, node.id)}
                      >
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </div>

                      {node.type === 'domain' ? (
                          <Building2 size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-blue-500'}`} />
                      ) : (
                          <Folder size={14} className="mr-2 text-yellow-500" />
                      )}

                      <span className="text-sm truncate select-none font-medium">{node.name}</span>
                  </div>
                  {isExpanded && node.children && renderSidebarNodes(node.children, depth + 1)}
              </div>
          );
      });
  };

  // --- Right Content Logic (Department Tree Table) ---
  const domainDepartments = useMemo(() => {
      return deptData.filter(d => d.domainId === selectedDomainId);
  }, [deptData, selectedDomainId]);

  const flattenDepts = (depts: Department[], depth = 0): (Department & { depth: number })[] => {
    let result: (Department & { depth: number })[] = [];
    depts.forEach(d => {
      result.push({ ...d, depth });
      if (d.children && expandedTableKeys.has(d.id)) {
        result = result.concat(flattenDepts(d.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = useMemo(() => {
      const visibleNodes = flattenDepts(domainDepartments);
      return visibleNodes.filter(d => {
          const matchName = !searchName || d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchStatus = !searchStatus || d.status === searchStatus;
          return matchName && matchStatus;
      });
  }, [domainDepartments, expandedTableKeys, searchName, searchStatus]);

  const getAllNodes = (depts: Department[]): Department[] => {
      let res: Department[] = [];
      depts.forEach(d => {
          res.push(d);
          if (d.children) res = res.concat(getAllNodes(d.children));
      });
      return res;
  };

  const handleAdd = (parentId: string | null = null) => {
      if (!selectedDomainId) {
          alert("请先选择左侧组织机构(域)");
          return;
      }
      setCurrentDept({
          parentId,
          domainId: selectedDomainId,
          status: 'active',
          sort: 1
      });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentDept.name || !currentDept.leader) {
          alert("请完善基本信息");
          return;
      }

      const deptToSave = { ...currentDept } as Department;

      const updateInTree = (nodes: Department[]): Department[] => {
          return nodes.map(n => {
              if (n.id === currentDept.id) {
                  return { ...n, ...deptToSave, children: n.children }; 
              }
              if (n.children) {
                  return { ...n, children: updateInTree(n.children) };
              }
              return n;
          });
      };

      const addInTree = (nodes: Department[], newItem: Department): Department[] => {
          return nodes.map(n => {
              if (n.id === newItem.parentId) {
                  return { ...n, children: [...(n.children || []), newItem] };
              }
              if (n.children) {
                  return { ...n, children: addInTree(n.children, newItem) };
              }
              return n;
          });
      };

      if (currentDept.id) {
          setDeptData(updateInTree(deptData));
      } else {
          const newDept = {
              ...deptToSave,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              children: []
          } as Department;

          if (newDept.parentId) {
              setDeptData(addInTree(deptData, newDept));
              setExpandedTableKeys(new Set([...expandedTableKeys, newDept.parentId]));
          } else {
              setDeptData([...deptData, newDept]);
          }
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Department[]): Department[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : undefined
              }));
          };
          setDeptData(removeNode(deptData));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          const updateStatus = (nodes: Department[]): Department[] => {
              return nodes.map(n => {
                  if (n.id === targetStatusChange.id) {
                      return { ...n, status: targetStatusChange.newStatus };
                  }
                  if (n.children) {
                      return { ...n, children: updateStatus(n.children) };
                  }
                  return n;
              });
          };
          setDeptData(updateStatus(deptData));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const selectedDomainName = MOCK_DOMAINS.find(d => d.id === selectedDomainId)?.name || '未选择';

  return (
      <div className="h-full flex gap-4 overflow-hidden">
          {/* Left Sidebar: Mixed Tree */}
          <Card className="w-72 shrink-0 flex flex-col" title="组织机构">
              <div className="mb-3">
                  <Input placeholder="搜索组织/部门..." className="text-xs h-8" prefix={<Search size={14}/>} />
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar -mx-2 px-2">
                  {renderSidebarNodes(mixedTree)}
              </div>
          </Card>

          {/* Right Content */}
          <div className="flex-1 flex flex-col gap-4 overflow-hidden">
              <Card className="shrink-0 px-6 py-6">
                  <div className="flex flex-col gap-4">
                      {/* Row 1: Search Conditions */}
                      <div className="flex flex-wrap gap-6 items-end">
                          <Input 
                              label="部门名称"
                              placeholder="请输入部门名称"
                              className="w-48"
                              value={searchName}
                              onChange={e => setSearchName(e.target.value)}
                          />
                          <Select 
                              label="状态"
                              options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                              value={searchStatus}
                              onChange={e => setSearchStatus(e.target.value)}
                              className="w-32"
                          />
                      </div>

                      {/* Row 2: Actions */}
                      <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                          <div className="flex gap-3">
                              <Button variant="primary" icon={<Search size={16}/>}>查询</Button>
                              <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchName(''); setSearchStatus(''); }}>重置</Button>
                              <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={() => handleAdd()}>新增部门</Button>
                              <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                          </div>
                          <div className="flex gap-3">
                              <Button 
                                  size="sm" 
                                  variant="secondary" 
                                  className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                                  icon={<Settings size={14} />}
                                  onClick={() => setIsColumnConfigOpen(true)}
                              >
                                  列配置
                              </Button>
                          </div>
                      </div>
                  </div>
              </Card>

              <Card className="flex-1 overflow-hidden flex flex-col">
                  {/* Info Bar */}
                  <div className="flex justify-between items-center px-4 py-2 border-b border-slate-800/50 bg-slate-900/20">
                       <span className="text-xs text-slate-500">当前归属域: <span className="text-blue-400 font-medium">{selectedDomainName}</span></span>
                  </div>

                  <div className="flex-1 overflow-auto">
                      <Table columns={activeColumns} data={flatData} keyField="id" />
                  </div>
              </Card>
          </div>

          <ColumnConfigDialog 
              isOpen={isColumnConfigOpen} 
              onClose={() => setIsColumnConfigOpen(false)} 
              allColumns={ALL_COLUMNS} 
              currentOrder={columnOrder} 
              onSave={setColumnOrder} 
          />

          {/* Add/Edit Modal */}
          <Modal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              title={currentDept.id ? "编辑部门" : "新增部门"}
              size="md"
              footer={
                  <>
                      <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                      <Button onClick={handleSave}>确定</Button>
                  </>
              }
          >
              <div className="space-y-6">
                  <SectionTitle title="部门信息" />
                  <div className="space-y-4">
                      {/* Domain Read-only Field */}
                      <div className="relative">
                           <label className="text-sm text-slate-400 block mb-1.5">归属组织 (Domain)</label>
                           <Select 
                              options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                              value={currentDept.domainId}
                              disabled={true}
                              className="opacity-60 cursor-not-allowed bg-slate-800"
                           />
                           <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                              <Lock size={12} />
                              <span className="text-xs">锁定</span>
                           </div>
                      </div>

                      <div className="relative">
                          <label className="text-sm text-slate-400 block mb-1.5">上级部门</label>
                          <select 
                              className="w-full px-3 py-2 bg-[#1e293b] border border-slate-700 rounded focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-white appearance-none hover:border-slate-600"
                              value={currentDept.parentId || ''}
                              onChange={e => setCurrentDept({...currentDept, parentId: e.target.value || null})}
                          >
                              <option value="">顶级部门</option>
                              {getAllNodes(domainDepartments).map(d => (
                                  <option key={d.id} value={d.id} disabled={d.id === currentDept.id}>{d.name}</option>
                              ))}
                          </select>
                          <ChevronDown size={14} className="absolute right-3 top-[38px] pointer-events-none text-slate-500" />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="部门名称"
                              placeholder="请输入"
                              value={currentDept.name || ''}
                              onChange={e => setCurrentDept({...currentDept, name: e.target.value})}
                          />
                          <Input 
                              label="显示排序"
                              type="number"
                              value={currentDept.sort || 0}
                              onChange={e => setCurrentDept({...currentDept, sort: parseInt(e.target.value)})}
                          />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="负责人"
                              placeholder="负责人姓名"
                              value={currentDept.leader || ''}
                              onChange={e => setCurrentDept({...currentDept, leader: e.target.value})}
                              prefix={<User size={14}/>}
                          />
                          <Input 
                              label="联系电话"
                              placeholder="手机号码"
                              value={currentDept.phone || ''}
                              onChange={e => setCurrentDept({...currentDept, phone: e.target.value})}
                              prefix={<Phone size={14}/>}
                          />
                      </div>

                      <Input 
                          label="邮箱"
                          placeholder="部门邮箱"
                          value={currentDept.email || ''}
                          onChange={e => setCurrentDept({...currentDept, email: e.target.value})}
                          prefix={<Mail size={14}/>}
                      />

                      <div className="flex flex-col gap-2">
                          <label className="text-sm text-slate-400">部门状态</label>
                          <div className="flex items-center gap-2">
                              <Switch 
                                  checked={currentDept.status === 'active'}
                                  onChange={c => setCurrentDept({...currentDept, status: c ? 'active' : 'inactive'})}
                              />
                              <span className="text-sm text-slate-300">{currentDept.status === 'active' ? '正常' : '停用'}</span>
                          </div>
                      </div>
                  </div>
              </div>
          </Modal>

          <ConfirmDialog 
              isOpen={confirmOpen} 
              message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '停用'}该部门吗？`}
              onConfirm={confirmStatusChange}
              onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
          />

          <ConfirmDialog 
              isOpen={deleteConfirmOpen} 
              title="删除部门"
              message="确定要删除该部门吗？如果有下级部门将一并删除。"
              onConfirm={confirmDelete}
              onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
          />
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Briefcase, Download, Settings } from 'lucide-react';
import { MOCK_POSTS } from '../constants';
import { Post } from '../types';

export const PostManager: React.FC = () => {
  const [data, setData] = useState<Post[]>(MOCK_POSTS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentPost, setCurrentPost] = useState<Partial<Post>>({});

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Confirm Dialogs
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const handleEdit = (post: Post) => {
      setCurrentPost({ ...post });
      setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const ALL_COLUMNS = useMemo(() => [
      { key: 'code', header: '岗位编码', accessor: 'code' },
      { key: 'name', header: '岗位名称', accessor: 'name' },
      { key: 'sort', header: '显示顺序', accessor: 'sort' },
      { 
          key: 'status', header: '状态', 
          accessor: (row: Post) => (
              <div className="flex justify-center">
                <Badge color={row.status === 'active' ? 'blue' : 'red'}>
                    {row.status === 'active' ? '正常' : '停用'}
                </Badge>
              </div>
          ) 
      },
      { key: 'createTime', header: '创建时间', accessor: 'createTime' },
      {
          key: 'action', header: '操作',
          accessor: (row: Post) => (
              <div className="flex space-x-2 justify-center">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14}/>} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14}/>} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          )
      }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  const filteredData = useMemo(() => {
      return data.filter(p => {
          const matchName = !searchName || p.name.toLowerCase().includes(searchName.toLowerCase());
          const matchCode = !searchCode || p.code.toLowerCase().includes(searchCode.toLowerCase());
          const matchStatus = !searchStatus || p.status === searchStatus;
          return matchName && matchCode && matchStatus;
      });
  }, [data, searchName, searchCode, searchStatus]);

  const handleAdd = () => {
      setCurrentPost({ status: 'active', sort: 0 });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentPost.name || !currentPost.code) {
          alert("请完善岗位信息");
          return;
      }
      if (currentPost.id) {
          setData(data.map(p => p.id === currentPost.id ? { ...p, ...currentPost } as Post : p));
      } else {
          const newPost = {
              ...currentPost,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString()
          } as Post;
          setData([...data, newPost]);
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setData(data.filter(p => p.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  return (
      <div className="h-full flex flex-col space-y-4">
          <Card className="shrink-0 px-6 py-6">
              <div className="flex flex-col gap-4">
                  {/* Row 1: Search Inputs */}
                  <div className="flex flex-wrap gap-6 items-end">
                      <Input 
                          label="岗位名称" 
                          placeholder="请输入岗位名称" 
                          value={searchName} 
                          onChange={e => setSearchName(e.target.value)}
                          className="w-40"
                      />
                      <Input 
                          label="岗位编码" 
                          placeholder="请输入岗位编码" 
                          value={searchCode} 
                          onChange={e => setSearchCode(e.target.value)}
                          className="w-40"
                      />
                      <Select 
                          label="状态"
                          options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                          value={searchStatus}
                          onChange={e => setSearchStatus(e.target.value)}
                          className="w-32"
                      />
                  </div>

                  {/* Row 2: Actions */}
                  <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                      <div className="flex gap-3">
                          <Button variant="primary" icon={<Search size={16}/>}>查询</Button>
                          <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchName(''); setSearchCode(''); setSearchStatus(''); }}>重置</Button>
                          <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16}/>} onClick={handleAdd}>新增岗位</Button>
                          <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                      </div>
                      <div className="flex gap-3">
                          <Button 
                              size="sm" 
                              variant="secondary" 
                              className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                              icon={<Settings size={14} />}
                              onClick={() => setIsColumnConfigOpen(true)}
                          >
                              列配置
                          </Button>
                      </div>
                  </div>
              </div>
          </Card>

          <Card className="flex-1 overflow-hidden flex flex-col" title="岗位列表">
              <div className="flex-1 overflow-auto">
                  <Table columns={activeColumns} data={filteredData} keyField="id" />
              </div>
              <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                  <div className="text-sm text-slate-400">共 {filteredData.length} 条</div>
              </div>
          </Card>

          <ColumnConfigDialog 
              isOpen={isColumnConfigOpen} 
              onClose={() => setIsColumnConfigOpen(false)} 
              allColumns={ALL_COLUMNS} 
              currentOrder={columnOrder} 
              onSave={setColumnOrder} 
          />

          <Modal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              title={currentPost.id ? "编辑岗位" : "新增岗位"}
              size="md"
              footer={
                  <>
                      <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                      <Button onClick={handleSave}>确定</Button>
                  </>
              }
          >
              <div className="space-y-4">
                  <Input 
                      label="岗位名称" 
                      value={currentPost.name || ''} 
                      onChange={e => setCurrentPost({...currentPost, name: e.target.value})}
                      placeholder="请输入岗位名称"
                  />
                  <Input 
                      label="岗位编码" 
                      value={currentPost.code || ''} 
                      onChange={e => setCurrentPost({...currentPost, code: e.target.value})}
                      placeholder="请输入编码"
                  />
                  <Input 
                      label="显示顺序" 
                      type="number"
                      value={currentPost.sort || 0} 
                      onChange={e => setCurrentPost({...currentPost, sort: parseInt(e.target.value)})}
                  />
                  <div className="flex flex-col gap-2">
                      <label className="text-sm text-slate-400">岗位状态</label>
                      <div className="flex items-center gap-2">
                          <Switch 
                              checked={currentPost.status === 'active'}
                              onChange={c => setCurrentPost({...currentPost, status: c ? 'active' : 'inactive'})}
                          />
                          <span className="text-sm text-slate-300">{currentPost.status === 'active' ? '正常' : '停用'}</span>
                      </div>
                  </div>
                  <Input 
                      label="备注" 
                      value={currentPost.remark || ''} 
                      onChange={e => setCurrentPost({...currentPost, remark: e.target.value})}
                      placeholder="请输入备注"
                  />
              </div>
          </Modal>

          <ConfirmDialog 
              isOpen={deleteConfirmOpen} 
              title="删除岗位"
              message="确定要删除该岗位吗？"
              onConfirm={confirmDelete}
              onCancel={() => setDeleteConfirmOpen(false)}
          />
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Search, RotateCcw, FileText, Clock, AlertCircle, Eye, Download, Settings } from 'lucide-react';
import { MOCK_LOGS } from '../constants';
import { OperLog } from '../types';

export const LogManager: React.FC = () => {
  const [logs, setLogs] = useState<OperLog[]>(MOCK_LOGS);
  const [searchModule, setSearchModule] = useState('');
  const [searchUser, setSearchUser] = useState('');
  const [searchStatus, setSearchStatus] = useState('');
  const [detailLog, setDetailLog] = useState<OperLog | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const ALL_COLUMNS = useMemo(() => [
      { key: 'title', header: '系统模块', accessor: 'title' },
      { 
          key: 'type', header: '操作类型', 
          accessor: (row: OperLog) => {
              const types = ['其它', '新增', '修改', '删除'];
              return <div className="flex justify-center"><Badge color="gray">{types[row.businessType] || '其它'}</Badge></div>
          }
      },
      { key: 'operName', header: '操作人员', accessor: 'operName' },
      { key: 'ip', header: '主机', accessor: 'operIp' },
      { 
          key: 'status', header: '状态', 
          accessor: (row: OperLog) => (
              <span className={row.status === 'success' ? 'text-green-400' : 'text-red-400'}>
                  {row.status === 'success' ? '成功' : '失败'}
              </span>
          ) 
      },
      { key: 'time', header: '操作时间', accessor: 'operTime' },
      { key: 'cost', header: '消耗时间', accessor: (row: OperLog) => `${row.costTime}ms` },
      {
          key: 'action', header: '操作',
          accessor: (row: OperLog) => (
              <div className="flex justify-center">
                <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Eye size={14}/>} onClick={() => setDetailLog(row)}>详情</Button>
              </div>
          )
      }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  const filteredLogs = useMemo(() => {
      return logs.filter(l => {
          const matchModule = !searchModule || l.title.includes(searchModule);
          const matchUser = !searchUser || l.operName.includes(searchUser);
          const matchStatus = !searchStatus || l.status === searchStatus;
          return matchModule && matchUser && matchStatus;
      });
  }, [logs, searchModule, searchUser, searchStatus]);

  return (
      <div className="h-full flex flex-col space-y-4">
          <Card className="shrink-0 px-6 py-6">
              <div className="flex flex-col gap-4">
                  {/* Row 1: Inputs */}
                  <div className="flex flex-wrap gap-6 items-end">
                      <Input label="系统模块" placeholder="请输入模块名称" value={searchModule} onChange={e => setSearchModule(e.target.value)} className="w-40"/>
                      <Input label="操作人员" placeholder="请输入操作人员" value={searchUser} onChange={e => setSearchUser(e.target.value)} className="w-40"/>
                      <Select label="状态" options={[{label:'全部',value:''},{label:'成功',value:'success'},{label:'失败',value:'fail'}]} value={searchStatus} onChange={e => setSearchStatus(e.target.value)} className="w-32"/>
                  </div>

                  {/* Row 2: Actions */}
                  <div className="flex justify-between items-center border-t border-slate-700/50 pt-4">
                      <div className="flex gap-3">
                          <Button icon={<Search size={16}/>}>查询</Button>
                          <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchModule(''); setSearchUser(''); setSearchStatus(''); }}>重置</Button>
                          <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                      </div>
                      <div className="flex gap-3">
                          <Button 
                              size="sm" 
                              variant="secondary" 
                              className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                              icon={<Settings size={14} />}
                              onClick={() => setIsColumnConfigOpen(true)}
                          >
                              列配置
                          </Button>
                      </div>
                  </div>
              </div>
          </Card>

          <Card className="flex-1 overflow-hidden flex flex-col" title="操作日志列表">
              <div className="flex-1 overflow-auto">
                  <Table columns={activeColumns} data={filteredLogs} keyField="id" />
              </div>
              <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                  <div className="text-sm text-slate-400">共 {filteredLogs.length} 条</div>
              </div>
          </Card>

          <ColumnConfigDialog 
              isOpen={isColumnConfigOpen} 
              onClose={() => setIsColumnConfigOpen(false)} 
              allColumns={ALL_COLUMNS} 
              currentOrder={columnOrder} 
              onSave={setColumnOrder} 
          />

          <Modal isOpen={!!detailLog} onClose={() => setDetailLog(null)} title="操作日志详情" size="md" footer={<Button onClick={() => setDetailLog(null)}>关闭</Button>}>
              {detailLog && (
                  <div className="space-y-4 text-sm">
                      <div className="grid grid-cols-2 gap-4">
                          <div><span className="text-slate-500 block mb-1">操作模块</span><span className="text-slate-200">{detailLog.title}</span></div>
                          <div><span className="text-slate-500 block mb-1">请求地址</span><span className="text-slate-200 break-all">{detailLog.operUrl}</span></div>
                          <div className="col-span-2"><span className="text-slate-500 block mb-1">操作方法</span><span className="text-slate-200 font-mono text-xs bg-slate-900 p-1 rounded block">{detailLog.method}</span></div>
                          <div><span className="text-slate-500 block mb-1">操作人员</span><span className="text-slate-200">{detailLog.operName}</span></div>
                          <div><span className="text-slate-500 block mb-1">主机地址</span><span className="text-slate-200">{detailLog.operIp}</span></div>
                          <div><span className="text-slate-500 block mb-1">操作状态</span><span className={detailLog.status==='success'?'text-green-400':'text-red-400'}>{detailLog.status==='success'?'成功':'失败'}</span></div>
                          <div><span className="text-slate-500 block mb-1">消耗时间</span><span className="text-slate-200">{detailLog.costTime}ms</span></div>
                          <div><span className="text-slate-500 block mb-1">操作时间</span><span className="text-slate-200">{detailLog.operTime}</span></div>
                      </div>
                      {detailLog.errorMsg && (
                          <div className="bg-red-900/20 border border-red-900/50 p-3 rounded text-red-200 mt-4">
                              <div className="flex items-center gap-2 mb-1 font-bold"><AlertCircle size={14}/> 异常信息</div>
                              <div className="text-xs font-mono">{detailLog.errorMsg}</div>
                          </div>
                      )}
                  </div>
              )}
          </Modal>
      </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, ChevronLeft, ChevronRight, ChevronsRight, ChevronsLeft, Users, Repeat, Crown, Globe, Download, Settings, FileText } from 'lucide-react';
import { MOCK_DOMAINS, MOCK_CUSTOMERS } from '../constants';
import { Domain } from '../types';
import { useGlobalContext } from '../GlobalContext';

export const DomainManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentEditDomain, setCurrentEditDomain] = useState<Partial<Domain> | null>(null);

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Domain | null>(null);

  // Transfer State
  const [transferSearch, setTransferSearch] = useState('');
  const [transferPage, setTransferPage] = useState(1);
  const [selectedSource, setSelectedSource] = useState<string[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<string[]>([]);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     if (domain.isSuper) return; // Cannot disable super domain
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const handleEdit = (domain: Domain) => {
    setCurrentEditDomain({ 
      ...domain, 
      customerIds: domain.customerIds || [],
      managementMode: domain.managementMode || 'switching'
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleDelete = (row: Domain) => {
    if (row.isSuper) return;
    setDeleteTarget(row);
    setDeleteConfirmOpen(true);
  };

  // --- Column Definitions ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'serial', header: '序号', accessor: 'serialNumber', width: '60px' 
    },
    { 
      key: 'name', header: '域名称', 
      accessor: (row: Domain) => (
        <div className="flex flex-col text-left">
           <div className="flex items-center">
               {row.isSuper ? (
                 <Crown size={16} className="text-yellow-500 mr-2" />
               ) : (
                 <Building2 size={16} className="text-blue-400 mr-2"/>
               )}
               <span className={`font-medium ${row.isSuper ? 'text-yellow-100' : 'text-blue-100'}`}>{row.name}</span>
               {row.isSuper && <Badge color="yellow" className="ml-2 scale-90">总控</Badge>}
           </div>
           <span className="text-[10px] text-slate-500 font-mono ml-6 mt-0.5">{row.code}</span>
        </div>
      ),
      width: '200px'
    },
    { 
      key: 'desc', header: '描述', 
      accessor: (row: Domain) => <span className="text-slate-400 text-xs truncate max-w-[150px] block text-left" title={row.description}>{row.description || '-'}</span> 
    },
    {
      key: 'mode', header: '管理模式',
      accessor: (row: Domain) => (
         row.managementMode === 'fusion' ? (
           <Badge color="blue" className="flex items-center gap-1 w-fit mx-auto">
              <Users size={10} /> 跨域融合
           </Badge>
         ) : (
           <Badge color="gray" className="flex items-center gap-1 w-fit mx-auto">
              <Repeat size={10} /> 按域切换
           </Badge>
         )
      )
    },
    { 
      key: 'customers', header: '关联客户', 
      accessor: (row: Domain) => {
        if (row.isSuper) {
             return <span className="text-slate-400 text-xs italic">所有客户权限</span>;
        }
        const ids = row.customerIds || [];
        if (ids.length === 0) return <span className="text-slate-500">-</span>;

        const names = ids.map(id => MOCK_CUSTOMERS.find(c => c.id === id)?.name).filter(Boolean) as string[];
        const displayCount = 2;
        const visibleNames = names.slice(0, displayCount);
        const diff = names.length - displayCount;

        return (
          <div className="flex items-center justify-center gap-1" title={names.join('、')}>
            <span className="text-slate-300 text-sm truncate max-w-[150px]">{visibleNames.join('、')}</span>
            {diff > 0 && <Badge color="gray" className="scale-90">+{diff}</Badge>}
          </div>
        )
      } 
    },
    { 
      key: 'status', header: '状态', 
      accessor: (row: Domain) => (
        <div className="flex justify-center">
            <Switch 
                checked={row.status === 'active'} 
                onChange={(checked) => initiateStatusChange(row, checked)} 
                disabled={row.isSuper}
            />
        </div>
      ),
      width: '80px'
    },
    { key: 'createTime', header: '创建时间', accessor: (row: Domain) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'updateTime', header: '更新时间', accessor: (row: Domain) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    {
      key: 'action', header: '操作',
      accessor: (row: Domain) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          {!row.isSuper && (
            <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row)}>删除</Button>
          )}
        </div>
      ),
      width: '140px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Reset search on context change
  useEffect(() => {
    setSearchName('');
    setSearchCode('');
    setSearchStatus('');
  }, [mode, currentDomain]);

  // Filtering Data
  const filteredData = useMemo(() => {
      let baseData = data;
      // Filter by Context
      if (mode === 'switching' && currentDomain) {
          baseData = data.filter(d => d.id === currentDomain.id);
      }

      return baseData.filter(d => {
          const matchName = d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchCode = d.code.toLowerCase().includes(searchCode.toLowerCase());
          const matchStatus = searchStatus ? d.status === searchStatus : true;
          return matchName && matchCode && matchStatus;
      });
  }, [data, searchName, searchCode, searchStatus, mode, currentDomain]);

  // Prepared data for table with serial numbers
  const tableData = useMemo(() => {
      return filteredData.map((d, index) => ({
          ...d,
          serialNumber: index + 1
      }));
  }, [filteredData]);

  const handleAdd = () => {
    setCurrentEditDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: null,
      customerIds: [],
      managementMode: 'switching',
      isSuper: false,
      description: ''
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const confirmDelete = () => {
    if (deleteTarget) {
        setData(data.filter(n => n.id !== deleteTarget.id));
    }
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          setData(data.map(item => item.id === targetStatusChange.id ? { ...item, status: targetStatusChange.newStatus } : item));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const handleSave = () => {
      setIsModalOpen(false);
      const timestamp = new Date().toLocaleString();
      if (currentEditDomain?.id) {
          // Update
          setData(data.map(n => n.id === currentEditDomain.id ? { 
              ...n, 
              ...currentEditDomain,
              updateTime: timestamp,
              updater: 'admin' // Mock user
          } as Domain : n));
      } else {
          // Create
          const newDomain = {
              ...currentEditDomain,
              id: Date.now().toString(),
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin',
              parentId: null
          } as Domain;
          setData([...data, newDomain]);
      }
  };

  // --- Transfer Logic ---
  const currentCustomerIds = currentEditDomain?.customerIds || [];
  const ITEMS_PER_TRANSFER_PAGE = 8; // Keep pagination for transfer list inside modal only

  const availableCustomers = useMemo(() => {
    return MOCK_CUSTOMERS.filter(c => !currentCustomerIds.includes(c.id));
  }, [currentCustomerIds]);

  const filteredSource = useMemo(() => {
    return availableCustomers.filter(c => c.name.toLowerCase().includes(transferSearch.toLowerCase()));
  }, [availableCustomers, transferSearch]);

  const totalTransferPages = Math.ceil(filteredSource.length / ITEMS_PER_TRANSFER_PAGE);
  const currentSourcePage = filteredSource.slice((transferPage - 1) * ITEMS_PER_TRANSFER_PAGE, transferPage * ITEMS_PER_TRANSFER_PAGE);

  const handleSelectAllSource = (checked: boolean) => {
    if (checked) {
        const allFilteredIds = filteredSource.map(c => c.id);
        setSelectedSource([...new Set([...selectedSource, ...allFilteredIds])]);
    } else {
        const filteredIds = filteredSource.map(c => c.id);
        setSelectedSource(selectedSource.filter(id => !filteredIds.includes(id)));
    }
  };

  const moveToTarget = () => {
    const newIds = [...currentCustomerIds, ...selectedSource];
    setCurrentEditDomain(prev => ({ ...prev!, customerIds: newIds }));
    setSelectedSource([]);
  };

  const moveToSource = () => {
    const newIds = currentCustomerIds.filter(id => !selectedTarget.includes(id));
    setCurrentEditDomain(prev => ({ ...prev!, customerIds: newIds }));
    setSelectedTarget([]);
  };

  return (
    <div className="space-y-4 h-full flex flex-col">
      <Card className="shrink-0" bodyClassName="p-4">
        <div className="flex flex-col gap-3">
           {/* Row 1: Search Conditions */}
           <div className="flex flex-wrap gap-4 items-center">
               <Input 
                 label="域名称" 
                 placeholder="输入名称" 
                 className="w-48" 
                 value={searchName} 
                 onChange={e => setSearchName(e.target.value)} 
               />
               <Input 
                 label="域编码" 
                 placeholder="输入编码" 
                 className="w-48" 
                 value={searchCode} 
                 onChange={e => setSearchCode(e.target.value)} 
               />
               <Select 
                 label="状态" 
                 options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '禁用', value: 'inactive'}]} 
                 className="w-32" 
                 value={searchStatus}
                 onChange={e => setSearchStatus(e.target.value)}
               />
           </div>

           {/* Row 2: Actions */}
           <div className="flex justify-between items-center border-t border-slate-700/50 pt-3">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button 
                        variant="secondary" 
                        icon={<RotateCcw size={16} />} 
                        onClick={() => { setSearchName(''); setSearchCode(''); setSearchStatus(''); }}
                    >
                        重置
                    </Button>
                    {/* Add button is strictly Green and in Search Area as requested */}
                    {mode === 'fusion' && (
                        <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增子域</Button>
                    )}
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
           </div>
        </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col" title={mode === 'switching' && currentDomain ? `[${currentDomain.name}] 域信息` : "域列表"}>
         <div className="flex-1 overflow-auto">
            <Table columns={activeColumns} data={tableData} />
         </div>
         <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {filteredData.length} 条</div>
         </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={currentEditDomain?.isSuper ? "智慧运维总控信息" : (currentEditDomain?.id ? "编辑子域信息" : "新增子域")}
        size="lg"
        footer={
          <>
            <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
            <Button onClick={handleSave}>确定</Button>
          </>
        }
      >
         <div className="space-y-6">
           {/* Basic Info */}
           <div>
               <SectionTitle title="域基础信息" />
               <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                    <div className="col-span-1">
                        <Input 
                            label="域名称" 
                            value={currentEditDomain?.name || ''}
                            onChange={(e) => setCurrentEditDomain(prev => ({...prev!, name: e.target.value}))}
                            placeholder="请输入域名称" 
                            disabled={currentEditDomain?.isSuper}
                        />
                    </div>

                    <div className="col-span-1">
                        <Input 
                            label="域编码" 
                            value={currentEditDomain?.code || ''} 
                            onChange={(e) => setCurrentEditDomain(prev => ({ ...prev!, code: e.target.value }))}
                            placeholder="唯一标识 (Code)" 
                            disabled={!!currentEditDomain?.id} 
                        />
                    </div>

                    <div className="col-span-1">
                        <Input label="管理员账号" defaultValue={currentEditDomain?.manager} placeholder="关联初始管理员" />
                    </div>

                    <div className="col-span-2">
                        <label className="text-sm text-slate-400 block mb-1.5">描述信息</label>
                        <textarea 
                            className="w-full bg-[#1e293b] border border-slate-700 rounded p-2 text-sm text-white focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-slate-600"
                            rows={3}
                            placeholder="请输入域描述..."
                            value={currentEditDomain?.description || ''}
                            onChange={(e) => setCurrentEditDomain(prev => ({ ...prev!, description: e.target.value }))}
                        />
                    </div>

                    <div className="col-span-2 bg-[#1e293b]/50 p-5 rounded-lg border border-slate-700/50">
                            <label className="text-sm font-medium text-slate-300 block mb-4">管理模式 (Management Mode)</label>
                            <div className="grid grid-cols-2 gap-6">
                                <div 
                                    className={`border rounded p-4 cursor-pointer transition-all flex items-start gap-4 ${currentEditDomain?.managementMode === 'fusion' ? 'bg-blue-600/10 border-blue-500' : 'bg-[#0f172a] border-slate-700 hover:border-slate-500'}`}
                                    onClick={() => !currentEditDomain?.isSuper && setCurrentEditDomain(prev => ({ ...prev!, managementMode: 'fusion' }))}
                                >
                                    <div className={`mt-0.5 rounded-full p-1.5 ${currentEditDomain?.managementMode === 'fusion' ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-700 text-slate-400'}`}>
                                        <Users size={16} />
                                    </div>
                                    <div>
                                        <div className={`text-sm font-bold ${currentEditDomain?.managementMode === 'fusion' ? 'text-blue-200' : 'text-slate-300'}`}>跨域融合模式</div>
                                        <div className="text-xs text-slate-400 mt-1.5 leading-relaxed">
                                            支持跨域查询，管理员可直接访问所有关联客户的数据。
                                        </div>
                                    </div>
                                </div>

                                <div 
                                    className={`border rounded p-4 cursor-pointer transition-all flex items-start gap-4 ${currentEditDomain?.managementMode === 'switching' ? 'bg-blue-600/10 border-blue-500' : 'bg-[#0f172a] border-slate-700 hover:border-slate-500'}`}
                                    onClick={() => !currentEditDomain?.isSuper && setCurrentEditDomain(prev => ({ ...prev!, managementMode: 'switching' }))}
                                >
                                    <div className={`mt-0.5 rounded-full p-1.5 ${currentEditDomain?.managementMode === 'switching' ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-700 text-slate-400'}`}>
                                        <Repeat size={16} />
                                    </div>
                                    <div>
                                        <div className={`text-sm font-bold ${currentEditDomain?.managementMode === 'switching' ? 'text-blue-200' : 'text-slate-300'}`}>按域切换模式</div>
                                        <div className="text-xs text-slate-400 mt-1.5 leading-relaxed">
                                            需切换不同上下文来访问特定数据，数据隔离性强。
                                        </div>
                                    </div>
                                </div>
                            </div>
                            {currentEditDomain?.isSuper && <div className="mt-3 text-xs text-amber-500/80 flex items-center gap-1"><Crown size={12}/> 总控中心默认启用跨域融合模式，拥有全局视野。</div>}
                    </div>
                </div>
            </div>

           {/* Customer Transfer Frame */}
           <div>
               <SectionTitle title="关联客户配置" />

               {currentEditDomain?.isSuper ? (
                   <div className="bg-slate-800/30 rounded-lg p-8 text-center border border-slate-700 border-dashed">
                       <Crown size={32} className="mx-auto text-yellow-500 mb-3 opacity-50"/>
                       <p className="text-slate-300 font-medium">总控中心默认拥有所有客户权限</p>
                       <p className="text-slate-500 text-sm mt-1">无需手动配置关联客户</p>
                   </div>
               ) : (
                <div className="flex h-[320px] gap-4">
                  {/* Left: Source */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg space-y-2">
                         <div className="flex gap-2">
                             <Input 
                                placeholder="搜索客户..." 
                                className="h-8 text-sm py-1" 
                                value={transferSearch}
                                onChange={(e) => { setTransferSearch(e.target.value); setTransferPage(1); }}
                             />
                         </div>
                         <div className="flex justify-between items-center px-1">
                             <label className="flex items-center space-x-2 cursor-pointer text-xs text-slate-300 select-none">
                                <input 
                                    type="checkbox" 
                                    className="rounded bg-slate-900 border-slate-600 text-blue-500" 
                                    onChange={(e) => handleSelectAllSource(e.target.checked)}
                                    checked={filteredSource.length > 0 && filteredSource.every(c => selectedSource.includes(c.id))}
                                />
                                <span>全选 ({filteredSource.length})</span>
                             </label>
                             <span className="text-xs text-slate-500">{selectedSource.length} 已选</span>
                         </div>
                      </div>

                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {currentSourcePage.map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedSource.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedSource.includes(item.id)
                                      ? setSelectedSource(selectedSource.filter(id => id !== item.id))
                                      : setSelectedSource([...selectedSource, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedSource.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                         {filteredSource.length === 0 && <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>}
                      </div>

                      {/* Pagination Controls for Transfer */}
                      {totalTransferPages > 1 && (
                          <div className="p-2 border-t border-slate-700 flex justify-between items-center bg-slate-800/30">
                              <button disabled={transferPage === 1} onClick={() => setTransferPage(p => p - 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronLeft size={16}/></button>
                              <span className="text-xs text-slate-400">{transferPage} / {totalTransferPages}</span>
                              <button disabled={transferPage === totalTransferPages} onClick={() => setTransferPage(p => p + 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronRight size={16}/></button>
                          </div>
                      )}
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col justify-center gap-3">
                        <Button size="sm" variant="secondary" onClick={moveToTarget} disabled={selectedSource.length === 0} title="添加" className="w-10">
                            <ChevronsRight size={18} />
                        </Button>
                        <Button size="sm" variant="secondary" onClick={moveToSource} disabled={selectedTarget.length === 0} title="移除" className="w-10">
                            <ChevronsLeft size={18} />
                        </Button>
                  </div>

                  {/* Right: Target */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[76px]">
                          <span className="text-xs font-semibold text-slate-300 pl-1">已关联客户 ({currentCustomerIds.length})</span>
                          <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setCurrentEditDomain(prev => ({...prev!, customerIds: []}))}>清空</Button>
                      </div>
                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {MOCK_CUSTOMERS.filter(c => currentCustomerIds.includes(c.id)).map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedTarget.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedTarget.includes(item.id)
                                      ? setSelectedTarget(selectedTarget.filter(id => id !== item.id))
                                      : setSelectedTarget([...selectedTarget, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedTarget.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                      </div>
                  </div>
               </div>
               )}
           </div>

           <Input label="备注信息" placeholder="可选填..." />
        </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '禁用'}该域吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除域"
         message={`确定要删除“${deleteTarget?.name}”吗？此操作不可恢复。`}
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTarget(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Folder, FileText, MousePointer, Search, RotateCcw, Download, Settings } from 'lucide-react';
import { MOCK_MENUS } from '../constants';
import { Menu } from '../types';

export const MenuManager: React.FC = () => {
  const [data, setData] = useState<Menu[]>(MOCK_MENUS);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchDescription, setSearchDescription] = useState('');
  const [searchVisible, setSearchVisible] = useState('');

  // Column Config State
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const [currentMenu, setCurrentMenu] = useState<Partial<Menu> & { isExternal?: boolean; isCache?: boolean }>({});

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newVisible: boolean } | null>(null);

  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  const initiateStatusChange = (menu: Menu, checked: boolean) => {
    setTargetStatusChange({ id: menu.id, newVisible: checked });
    setConfirmOpen(true);
  };

  const handleEdit = (menu: Menu) => {
    setCurrentMenu({ 
        ...menu, 
        parentId: menu.parentId || '0',
        isExternal: false, 
        isCache: true 
    });
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      const target = fullFlatData.find(m => m.id === id);
      if (target && target.children && target.children.length > 0) {
          alert("该菜单包含子菜单，请先删除子菜单！");
          return;
      }
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'name', header: '菜单名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center text-left">
           {row.type === 'dir' && <Folder size={16} className="text-yellow-500 mr-2" />}
           {row.type === 'menu' && <FileText size={16} className="text-blue-400 mr-2" />}
           {row.type === 'button' && <MousePointer size={16} className="text-slate-400 mr-2" />}
           <span className="text-slate-200">{row.name}</span>
        </div>
      ),
      width: '200px'
    },
    { 
      key: 'type', header: '类别', 
      accessor: (row: Menu) => {
          if (row.type === 'dir') return <Badge color="yellow">目录</Badge>;
          if (row.type === 'menu') return <Badge color="blue">菜单</Badge>;
          return <Badge color="gray">按钮</Badge>;
      },
      width: '80px'
    },
    { key: 'desc', header: '描述', accessor: (row: Menu) => <span className="text-slate-400 text-xs truncate max-w-[150px] block text-left" title={row.description}>{row.description || '-'}</span> },
    { key: 'sort', header: '排序', accessor: 'sort', width: '60px' },
    { 
      key: 'status', header: '状态', 
      accessor: (row: Menu) => (
        <div className="flex justify-center">
            <Switch 
            checked={row.visible} 
            onChange={(checked) => initiateStatusChange(row, checked)} 
            />
        </div>
      ),
      width: '80px'
    },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'createTime', header: '创建时间', accessor: (row: Menu) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    { key: 'updateTime', header: '更新时间', accessor: (row: Menu) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    {
      key: 'action', header: '操作',
      accessor: (row: Menu) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      ),
      width: '140px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  const flattenMenus = (menus: Menu[], depth = 0): (Menu & { depth: number })[] => {
    let result: (Menu & { depth: number })[] = [];
    menus.forEach(m => {
      result.push({ ...m, depth });
      if (m.children) {
        result = result.concat(flattenMenus(m.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = useMemo(() => {
    const all = flattenMenus(data);
    return all.filter(m => {
        const matchName = !searchName || m.name.toLowerCase().includes(searchName.toLowerCase());
        const matchDesc = !searchDescription || (m.description && m.description.toLowerCase().includes(searchDescription.toLowerCase()));
        const matchVisible = searchVisible === '' || String(m.visible) === searchVisible;
        return matchName && matchDesc && matchVisible;
    });
  }, [data, searchName, searchDescription, searchVisible]);

  const fullFlatData = useMemo(() => flattenMenus(data), [data]);

  const handleAdd = () => {
    setCurrentMenu({ 
        type: 'menu', 
        parentId: '0', 
        sort: 1, 
        visible: true,
        isExternal: false,
        isCache: true
    });
    setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentMenu.name || !currentMenu.type) {
          alert("请完善必要信息");
          return;
      }

      const timestamp = new Date().toLocaleString();
      const menuToSave = {
          ...currentMenu,
          parentId: currentMenu.parentId === '0' ? null : currentMenu.parentId,
      } as Menu;

      if (currentMenu.id) {
          const updateNode = (nodes: Menu[]): Menu[] => {
              return nodes.map(n => {
                  if (n.id === currentMenu.id) {
                      return { 
                          ...n, 
                          ...menuToSave,
                          updateTime: timestamp,
                          updater: 'admin' 
                      };
                  }
                  if (n.children) {
                      return { ...n, children: updateNode(n.children) };
                  }
                  return n;
              });
          };
          setData(updateNode(data));
      } else {
          const newId = Date.now().toString();
          const newMenu = { 
              ...menuToSave, 
              id: newId, 
              children: [],
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin'
          };

          if (newMenu.parentId) {
              const addNode = (nodes: Menu[]): Menu[] => {
                  return nodes.map(n => {
                      if (n.id === newMenu.parentId) {
                          return { ...n, children: [...(n.children || []), newMenu] };
                      }
                      if (n.children) {
                          return { ...n, children: addNode(n.children) };
                      }
                      return n;
                  });
              };
              setData(addNode(data));
          } else {
              setData([...data, newMenu]);
          }
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Menu[]): Menu[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : []
              }));
          };
          setData(removeNode(data));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
     if (targetStatusChange) {
         const updateVisible = (items: Menu[]): Menu[] => {
             return items.map(item => {
                 if (item.id === targetStatusChange.id) {
                     return { ...item, visible: targetStatusChange.newVisible };
                 }
                 if (item.children) {
                     return { ...item, children: updateVisible(item.children) };
                 }
                 return item;
             });
         };
         setData(updateVisible(data));
     }
     setConfirmOpen(false);
     setTargetStatusChange(null);
  };

  return (
    <div className="h-full flex flex-col space-y-4">
      <Card className="shrink-0" bodyClassName="p-4">
         <div className="flex flex-col gap-3">
            <div className="flex flex-wrap gap-4 items-center">
                <Input 
                    label="菜单名称"
                    placeholder="菜单名称" 
                    className="w-48" 
                    value={searchName}
                    onChange={(e) => setSearchName(e.target.value)}
                />
                <Input 
                    label="菜单描述"
                    placeholder="描述信息" 
                    className="w-48" 
                    value={searchDescription}
                    onChange={(e) => setSearchDescription(e.target.value)}
                />
                <Select 
                    label="状态"
                    options={[{label: '全部', value: ''}, {label: '显示', value: 'true'}, {label: '隐藏', value: 'false'}]}
                    value={searchVisible}
                    onChange={e => setSearchVisible(e.target.value)}
                    className="w-32"
                />
            </div>

            <div className="flex justify-between items-center border-t border-slate-700/50 pt-3">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchDescription(''); setSearchVisible(''); }}>重置</Button>
                    <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增菜单</Button>
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
            </div>
         </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-auto">
          <Table columns={activeColumns} data={flatData} />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatData.length} 条</div>
        </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentMenu.id ? "编辑菜单" : "新增菜单"}
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>确定</Button>
            </>
          }
      >
         <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="text-sm font-medium text-slate-300 mb-2 block">类型</label>
                    <div className="flex space-x-4">
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="dir"
                                checked={currentMenu.type === 'dir'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'dir'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'dir' ? 'text-blue-400' : 'text-slate-400'}>目录</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="menu"
                                checked={currentMenu.type === 'menu'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'menu'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'menu' ? 'text-blue-400' : 'text-slate-400'}>菜单</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="button"
                                checked={currentMenu.type === 'button'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'button'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'button' ? 'text-blue-400' : 'text-slate-400'}>按钮</span>
                        </label>
                    </div>
                </div>

                <div className="col-span-2">
                    <Input 
                        label="上级菜单" 
                        value={fullFlatData.find(m => m.id === currentMenu.parentId)?.name || '主目录'}
                        disabled 
                        className="bg-slate-800 cursor-not-allowed"
                    />
                </div>

                <Input 
                    label="菜单名称" 
                    value={currentMenu.name || ''} 
                    onChange={e => setCurrentMenu({...currentMenu, name: e.target.value})} 
                />

                <Input 
                    label="显示排序" 
                    type="number"
                    value={currentMenu.sort || 0} 
                    onChange={e => setCurrentMenu({...currentMenu, sort: parseInt(e.target.value)})} 
                />

                {currentMenu.type !== 'button' && (
                    <div className="col-span-2 flex space-x-4">
                        <div className="flex-1">
                            <Input 
                                label="路由地址" 
                                value={currentMenu.path || ''} 
                                onChange={e => setCurrentMenu({...currentMenu, path: e.target.value})} 
                                placeholder="/system/menu"
                            />
                        </div>
                        <div className="flex-1">
                            <Input 
                                label="组件路径" 
                                value={currentMenu.component || ''} 
                                onChange={e => setCurrentMenu({...currentMenu, component: e.target.value})} 
                                placeholder="views/system/menu/index"
                            />
                        </div>
                    </div>
                )}

                <div className="col-span-2">
                    <Input 
                        label="权限标识" 
                        value={currentMenu.permission || ''} 
                        onChange={e => setCurrentMenu({...currentMenu, permission: e.target.value})} 
                        placeholder="system:menu:list"
                    />
                </div>

                <div className="col-span-2">
                    <label className="text-sm text-slate-400 block mb-1.5">菜单描述</label>
                    <textarea 
                        className="w-full bg-[#1e293b] border border-slate-700 rounded p-2 text-sm text-white focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-slate-600"
                        rows={2}
                        placeholder="请输入菜单描述..."
                        value={currentMenu.description || ''}
                        onChange={e => setCurrentMenu({...currentMenu, description: e.target.value})}
                    />
                </div>

                <div className="flex flex-col gap-2">
                    <label className="text-sm text-slate-400">显示状态</label>
                    <div className="flex items-center gap-2">
                        <Switch 
                            checked={currentMenu.visible !== false} 
                            onChange={c => setCurrentMenu({...currentMenu, visible: c})} 
                        />
                        <span className="text-sm text-slate-300">{currentMenu.visible !== false ? '显示' : '隐藏'}</span>
                    </div>
                </div>
            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newVisible ? '显示' : '隐藏'}该菜单吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除菜单"
         message="确定要删除该菜单吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, MinusSquare, Shield, ChevronDown, Folder, UserPlus, Lock, ChevronRight, Download, Settings } from 'lucide-react';
import { MOCK_ROLES, REGIONS, MOCK_DOMAINS, MOCK_MENUS, BUSINESS_TYPES } from '../constants';
import { Role, Domain, Menu } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Type to represent either a domain header or a role item row
type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; roleCount: number; expanded: boolean }
  | { type: 'role'; id: string; data: Role; parentDomainId: string };

export const RoleManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [roleData, setRoleData] = useState<Role[]>(MOCK_ROLES);

  // Expanded Domains State
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});

  // Menu Permissions State (IDs)
  const [selectedMenuIds, setSelectedMenuIds] = useState<Set<string>>(new Set());

  const [isDomainLocked, setIsDomainLocked] = useState(false); 
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Search
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchDomainId, setSearchDomainId] = useState('');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  // --- Mock Transfer Data State ---
  const [sourceData] = useState(() => {
      const list = [];
      for(let i=1; i<=8; i++) list.push({ id: `line-${i}`, name: `互联网专线-电路${i}`, category: 'BIZ_LINE' });
      for(let i=1; i<=8; i++) list.push({ id: `5g-${i}`, name: `5G切片-车间${i}`, category: 'BIZ_5G' });
      for(let i=1; i<=8; i++) list.push({ id: `idc-${i}`, name: `IDC机柜-机房${i}`, category: 'BIZ_IDC' });
      for(let i=1; i<=5; i++) list.push({ id: `comp-${i}`, name: `东数西算-节点${i}`, category: 'BIZ_COMP' });
      return list;
  });
  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);
  const [bizCategoryFilter, setBizCategoryFilter] = useState<string>('all');

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setIsDomainLocked(true); 
    setSelectedMenuIds(new Set(role.menuIds || []));
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleAddInDomain = (domainId: string) => {
    setCurrentRole({ 
        domainId: domainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11']));
    setIsDomainLocked(true);
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
      key: 'name', header: '名称 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group text-left"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-blue-500 fill-blue-500/10 group-hover:text-blue-400" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.roleCount} 角色</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300 relative text-left">
                      <div className="absolute left-[29px] top-[-20px] bottom-[50%] w-[1px] bg-slate-700"></div>
                      <div className="absolute left-[29px] top-[50%] w-4 h-[1px] bg-slate-700"></div>
                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium hover:text-green-400 transition-colors cursor-default">{row.data.name}</span>
                  </div>
              );
          }
      },
      width: '35%'
    },
    { 
      key: 'code', header: '编码', 
      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic opacity-50">{row.data.code}</span>,
      width: '20%'
    },
    { 
      key: 'desc', header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? <span className="text-slate-400 text-sm truncate block max-w-xs text-left">{row.data.description}</span> : '',
    },
    {
      key: 'action', header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <div className="flex justify-center">
                    <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAddInDomain(row.data.id)}>
                        新增角色
                    </Button>
                </div>
              )
          }
          return (
            <div className="flex space-x-2 justify-center">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>配置</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '200px'
    }
  ], [expandedDomains]); // Re-render when expanded domains change to update icon

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Handle Context Change
  useEffect(() => {
    setSearchName('');
    setSearchCode('');
    setSearchDomainId('');
    if (mode === 'switching' && currentDomain) {
        setExpandedDomains(new Set([currentDomain.id]));
    } else {
        setExpandedDomains(new Set(MOCK_DOMAINS.map(d => d.id)));
    }
  }, [mode, currentDomain]);

  useEffect(() => {
    if (isModalOpen) {
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
        setBizCategoryFilter('all');
    }
  }, [isModalOpen]);

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  // --- Process Data into Flat Tree Structure ---
  const flatTreeData = useMemo(() => {
    // 1. Determine Context
    let contextDomains = MOCK_DOMAINS;
    if (mode === 'switching' && currentDomain) {
        contextDomains = MOCK_DOMAINS.filter(d => d.id === currentDomain.id);
    }

    let filteredRoles = roleData;
    if (searchName) filteredRoles = filteredRoles.filter(r => r.name.includes(searchName));
    if (searchCode) filteredRoles = filteredRoles.filter(r => r.code.includes(searchCode));

    // Strictly filter roles in switching mode
    if (mode === 'switching' && currentDomain) {
        filteredRoles = filteredRoles.filter(r => r.domainId === currentDomain.id);
    }

    const result: TreeItem[] = [];
    contextDomains.forEach(domain => {
        // Filter by Domain ID if selected in local search
        if (searchDomainId && domain.id !== searchDomainId) return;

        const domainRoles = filteredRoles.filter(r => r.domainId === domain.id);

        // If searching by name/code and no roles match, skip this domain
        if ((searchName || searchCode) && domainRoles.length === 0) return; 

        // Auto expand if searching or filtering or switching
        const isExpanded = expandedDomains.has(domain.id) || !!searchName || !!searchCode || !!searchDomainId || (mode === 'switching');

        result.push({
            type: 'domain',
            id: `d-${domain.id}`,
            data: domain,
            roleCount: domainRoles.length,
            expanded: isExpanded
        });

        if (isExpanded) {
            domainRoles.forEach(role => {
                result.push({
                    type: 'role',
                    id: role.id,
                    data: role,
                    parentDomainId: domain.id
                });
            });
        }
    });

    return result;
  }, [roleData, expandedDomains, searchName, searchCode, searchDomainId, mode, currentDomain]);

  // --- Handlers ---
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  // Triggered by Top Button
  const handleGlobalAdd = () => {
    const defaultDomainId = (mode === 'switching' && currentDomain) ? currentDomain.id : (MOCK_DOMAINS[0]?.id || '');

    setCurrentRole({ 
        domainId: defaultDomainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11'])); 
    setIsDomainLocked(mode === 'switching');
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setRoleData(roleData.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      const roleToSave = {
          ...currentRole,
          menuIds: Array.from(selectedMenuIds)
      } as Role;

      if (roleToSave.id) {
          setRoleData(roleData.map(r => r.id === roleToSave.id ? roleToSave : r));
      } else {
          const newRole = { 
              ...roleToSave, 
              id: Date.now().toString(),
              code: roleToSave.code || `ROLE_${Date.now()}` 
          } as Role;
          setRoleData([...roleData, newRole]);
      }
      setIsModalOpen(false);
  };

  // --- Menu Logic ---
  const getChildIds = (menu: Menu): string[] => {
      let ids: string[] = [];
      if (menu.children) {
          menu.children.forEach(child => {
              ids.push(child.id);
              ids = [...ids, ...getChildIds(child)];
          });
      }
      return ids;
  };

  const getParentIds = (targetId: string, menus: Menu[], path: string[] = []): string[] => {
      for (const menu of menus) {
          if (menu.id === targetId) return path;
          if (menu.children) {
              const res = getParentIds(targetId, menu.children, [...path, menu.id]);
              if (res.length > 0) return res;
          }
      }
      return [];
  };

  const toggleMenu = (menu: Menu, checked: boolean) => {
      const newSelected = new Set(selectedMenuIds);
      const childIds = getChildIds(menu);
      if (checked) {
          newSelected.add(menu.id);
          childIds.forEach(id => newSelected.add(id));
          const parentIds = getParentIds(menu.id, MOCK_MENUS);
          parentIds.forEach(id => newSelected.add(id));
      } else {
          newSelected.delete(menu.id);
          childIds.forEach(id => newSelected.delete(id));
      }
      setSelectedMenuIds(newSelected);
  };

  type CheckState = 'checked' | 'unchecked' | 'indeterminate';

  const getMenuState = (menu: Menu): CheckState => {
      if (!menu.children || menu.children.length === 0) {
          return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked';
      }

      let allChecked = true;
      let allUnchecked = true;

      const checkChildren = (children: Menu[]) => {
        for (const child of children) {
            const childIsSelected = selectedMenuIds.has(child.id);
            if (!childIsSelected) allChecked = false;
            else allUnchecked = false;

            if (child.children) {
                checkChildren(child.children);
            }
        }
      };

      checkChildren(menu.children);

      if (allChecked) return 'checked';
      if (allUnchecked) return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked';
      return 'indeterminate';
  };

  const renderMenuTree = (menus: Menu[], depth = 0) => {
      return menus.map(menu => {
          const state = getMenuState(menu);

          return (
              <div key={menu.id}>
                  <div 
                      className={`flex items-center space-x-2 py-1.5 cursor-pointer hover:bg-slate-800 rounded px-2 transition-colors`}
                      style={{ paddingLeft: `${depth * 20 + 8}px` }}
                      onClick={() => toggleMenu(menu, state !== 'checked')}
                  >
                      {state === 'checked' && <CheckSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'indeterminate' && <MinusSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'unchecked' && <Square size={16} className="text-slate-500 shrink-0" />}

                      <span className={`${state !== 'unchecked' ? 'text-white' : 'text-slate-400'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderMenuTree(menu.children, depth + 1)}
              </div>
          );
      });
  };

  const isAllRegionsSelected = (currentRole.regionScope?.length || 0) === REGIONS.length;
  const toggleAllRegions = () => {
      if (isAllRegionsSelected) {
          setCurrentRole({ ...currentRole, regionScope: [] });
      } else {
          setCurrentRole({ ...currentRole, regionScope: REGIONS.map(r => r.code) });
      }
  };
  const toggleRegion = (code: string) => {
      const current = currentRole.regionScope || [];
      if (current.includes(code)) {
          setCurrentRole({ ...currentRole, regionScope: current.filter(c => c !== code) });
      } else {
          setCurrentRole({ ...currentRole, regionScope: [...current, code] });
      }
  };

  const filteredSourceData = useMemo(() => {
      let res = sourceData.filter(d => !targetKeys.includes(d.id));
      if (bizCategoryFilter !== 'all') {
          res = res.filter(d => d.category === bizCategoryFilter);
      }
      return res;
  }, [sourceData, targetKeys, bizCategoryFilter]);

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0" bodyClassName="p-4">
         <div className="flex flex-col gap-3">
            {/* Row 1: Search Inputs */}
            <div className="flex flex-wrap gap-4 items-center">
                <Input label="角色名称" placeholder="搜索角色名称" className="w-48" value={searchName} onChange={e => setSearchName(e.target.value)} />
                <Input label="角色编码" placeholder="搜索角色编码" className="w-48" value={searchCode} onChange={e => setSearchCode(e.target.value)} />
                {/* Hide Domain Select in Switching Mode as it is implicit */}
                {mode === 'fusion' && (
                    <Select 
                        label="所属域"
                        className="w-40" 
                        options={[{label: '全部域', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                        value={searchDomainId}
                        onChange={e => setSearchDomainId(e.target.value)}
                    />
                )}
            </div>

            {/* Row 2: Actions */}
            <div className="flex justify-between items-center border-t border-slate-700/50 pt-3">
                <div className="flex gap-3">
                    <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchCode(''); setSearchDomainId(''); }}>重置</Button>
                    <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<UserPlus size={16} />} onClick={handleGlobalAdd}>新增角色</Button>
                    <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                </div>
                <div className="flex gap-3">
                    <Button 
                        size="sm" 
                        variant="secondary" 
                        className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                        icon={<Settings size={14} />}
                        onClick={() => setIsColumnConfigOpen(true)}
                    >
                        列配置
                    </Button>
                </div>
            </div>
         </div>
      </Card>

      {/* Role Tree Table */}
      <Card className="flex-1 overflow-hidden flex flex-col" title={mode === 'switching' && currentDomain ? `[${currentDomain.name}] 角色权限树` : "角色权限树"}>
        <div className="flex-1 overflow-auto">
          <Table columns={activeColumns} data={flatTreeData} keyField="id" />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
        </div>
      </Card>

      <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
      />

      {/* Add/Edit Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentRole.id ? "配置角色权限" : "新增角色"}
        size="lg"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>保存配置</Button>
            </>
          }
      >
         <div className="h-[550px] flex flex-col">
            {/* Tabs */}
            <div className="flex border-b border-slate-700 mb-4 shrink-0 bg-[#0f172a] -mx-8 px-8 sticky top-0 z-10">
                {(['info', 'menu', 'data'] as const).map(tab => (
                    <button 
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-400 hover:text-slate-200'}`}
                    >
                        {tab === 'info' && '基本信息'}
                        {tab === 'menu' && '菜单权限'}
                        {tab === 'data' && '数据权限'}
                    </button>
                ))}
            </div>

            {/* Tab Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1">
                {/* 1. Basic Info */}
                {activeTab === 'info' && (
                    <div className="space-y-6 max-w-2xl mx-auto mt-4">
                         <SectionTitle title="角色基础信息" />
                         <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                            <Input 
                                label="角色名称" 
                                value={currentRole.name || ''} 
                                onChange={e => setCurrentRole({...currentRole, name: e.target.value})}
                                placeholder="请输入角色名称" 
                            />
                            <Input 
                                label="角色编码" 
                                value={currentRole.code || ''} 
                                onChange={e => setCurrentRole({...currentRole, code: e.target.value})}
                                placeholder="ROLE_..." 
                                disabled={!!currentRole.id}
                            />
                            <div className="relative">
                                <Select 
                                    label="所属域" 
                                    options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                    value={currentRole.domainId}
                                    onChange={e => setCurrentRole({...currentRole, domainId: e.target.value})}
                                    disabled={isDomainLocked} 
                                    className={isDomainLocked ? "opacity-60 cursor-not-allowed bg-slate-800" : ""}
                                />
                                {isDomainLocked && (
                                    <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                        <Lock size={12} />
                                        <span className="text-xs">已锁定</span>
                                    </div>
                                )}
                            </div>
                            <Input 
                                label="描述" 
                                value={currentRole.description || ''}
                                onChange={e => setCurrentRole({...currentRole, description: e.target.value})}
                            />
                        </div>
                    </div>
                )}
                {/* 2. Menu Permissions */}
                {activeTab === 'menu' && (
                    <div className="space-y-4">
                        <div className="bg-blue-900/10 border border-blue-900/30 rounded p-3 text-xs text-blue-300 mb-2 flex items-center gap-2">
                             <CheckSquare size={14} />
                            提示：勾选该角色可访问的菜单资源。系统支持父子菜单联动选择。
                        </div>
                        <div className="border border-slate-700 rounded-lg p-5 bg-[#1e293b]/30 min-h-[350px]">
                            {renderMenuTree(MOCK_MENUS)}
                        </div>
                    </div>
                )}
                {/* 3. Data Permissions */}
                {activeTab === 'data' && (
                    <div className="space-y-6">
                        {/* Region Scope */}
                        <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <div className="flex justify-between items-center mb-4">
                                <SectionTitle title="区域范围 (Region Scope)" className="mb-0" />
                                <label className="flex items-center space-x-2 cursor-pointer text-xs text-blue-400 hover:text-blue-300 select-none bg-blue-900/20 px-2 py-1 rounded">
                                    <input 
                                        type="checkbox" 
                                        className="rounded bg-slate-900 border-slate-600 text-blue-500"
                                        checked={isAllRegionsSelected}
                                        onChange={toggleAllRegions}
                                    />
                                    <span>全选所有区域</span>
                                </label>
                            </div>
                            <div className="grid grid-cols-4 gap-4">
                                {REGIONS.slice(0, 16).map(reg => (
                                    <label key={reg.code} className="flex items-center space-x-2 cursor-pointer hover:text-blue-400 group">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900" 
                                            checked={currentRole.regionScope?.includes(reg.code) || false}
                                            onChange={() => toggleRegion(reg.code)}
                                        />
                                        <span className="text-sm text-slate-400 group-hover:text-slate-200">{reg.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                         {/* Business Scope (Transfer) */}
                         <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <SectionTitle title="业务范围 (Business Scope)" />

                            <div className="flex h-[320px] gap-4">
                                {/* Source Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex flex-col gap-2">
                                        <div className="flex justify-between items-center px-1 pt-1">
                                            <span className="text-xs font-semibold text-slate-300">待选业务</span>
                                            <span className="text-xs text-slate-500">{sourceSelected.length} 选中</span>
                                        </div>

                                        {/* Business Category Filter */}
                                        <div className="flex flex-wrap gap-1 pb-1">
                                            <button 
                                                onClick={() => setBizCategoryFilter('all')}
                                                className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === 'all' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                            >
                                                全部
                                            </button>
                                            {BUSINESS_TYPES.map(bt => (
                                                <button 
                                                    key={bt.code}
                                                    onClick={() => setBizCategoryFilter(bt.code)}
                                                    className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === bt.code ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                                >
                                                    {bt.name}
                                                </button>
                                            ))}
                                        </div>

                                        <Input placeholder="搜索业务实例..." className="text-xs py-1.5 h-8" />
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {filteredSourceData.map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${sourceSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    sourceSelected.includes(item.id) 
                                                      ? setSourceSelected(sourceSelected.filter(id => id !== item.id))
                                                      : setSourceSelected([...sourceSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={sourceSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                        {filteredSourceData.length === 0 && (
                                            <div className="text-center py-8 text-xs text-slate-500">无匹配数据</div>
                                        )}
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-col justify-center gap-3 px-2">
                                    <Button size="sm" variant="secondary" onClick={moveToRight} disabled={sourceSelected.length === 0} title="添加选中">
                                        <ChevronRight size={16} />
                                    </Button>
                                    <Button size="sm" variant="secondary" onClick={moveToLeft} disabled={targetSelected.length === 0} title="移除选中" className="rotate-180">
                                        <ChevronRight size={16} />
                                    </Button>
                                </div>

                                {/* Target Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[90px]">
                                        <span className="text-xs font-semibold text-slate-300 pl-1">已授权业务 ({targetKeys.length})</span>
                                        <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setTargetKeys([])}>清空</Button>
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {sourceData.filter(d => targetKeys.includes(d.id)).map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${targetSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    targetSelected.includes(item.id) 
                                                      ? setTargetSelected(targetSelected.filter(id => id !== item.id))
                                                      : setTargetSelected([...targetSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={targetSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         title="删除角色"
         message="确定要删除该角色吗？此操作不可恢复，且可能导致关联用户失去权限。"
         onConfirm={confirmDelete}
         onCancel={() => { setConfirmOpen(false); setDeleteId(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Folder, ChevronDown, ChevronRight, User as UserIcon, Mail, Phone, Shield, Lock, Eye, CheckSquare, Check, AlertTriangle, RefreshCcw, Settings, Grid, MoreHorizontal, Building2, GitBranch, Download } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS, MOCK_MENUS, REGIONS, BUSINESS_TYPES, MOCK_DEPTS } from '../constants';
import { User, Domain, Role, Menu, Department } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Unified Node Type for the Sidebar
type MixedNode = {
    id: string;
    name: string;
    type: 'domain' | 'dept';
    data: Domain | Department;
    children?: MixedNode[];
};

export const UserManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  const [selectedNode, setSelectedNode] = useState<{ id: string, type: 'domain' | 'dept' } | null>(null);
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  const [userData, setUserData] = useState<User[]>(MOCK_USERS);

  const [searchUsername, setSearchUsername] = useState('');
  const [searchRoleId, setSearchRoleId] = useState(''); 
  const [searchDomainId, setSearchDomainId] = useState(''); 
  const [searchStatus, setSearchStatus] = useState('');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});
  const [selectedRoleIds, setSelectedRoleIds] = useState<Set<string>>(new Set());

  const [auditUser, setAuditUser] = useState<User | null>(null);

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const handleEdit = (user: User) => {
      setCurrentUser({ ...user });
      const roleIds = user.roles
        .filter(r => r.targetDomainId === user.baseDomainId) 
        .map(r => r.roleId);
      setSelectedRoleIds(new Set(roleIds));
      setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
    { 
        key: 'serial', header: '序号', accessor: 'serialNumber', width: '60px' 
    },
    { 
        key: 'user', header: '用户', 
        accessor: (row: User) => (
            <div className="flex items-center gap-3 text-left">
                 <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center border border-slate-600 text-slate-300 shrink-0">
                      <UserIcon size={14} />
                 </div>
                 <div>
                    <div className="text-sm font-medium text-slate-200">{row.username}</div>
                    {row.deptId && (
                        <div className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5">
                            <GitBranch size={10} />
                            {MOCK_DEPTS.find(d => d.id === row.deptId)?.name || row.deptId}
                        </div>
                    )}
                 </div>
            </div>
        )
    },
    { key: 'realName', header: '真实姓名', accessor: 'realName' },
    { 
        key: 'role', header: '所属角色', 
        accessor: (row: User) => {
            const roles = row.roles.map(r => MOCK_ROLES.find(mr => mr.id === r.roleId)?.name).filter(Boolean);
            if (roles.length === 0) return <span className="text-slate-500 text-xs">-</span>;
            return (
                <div className="flex flex-wrap gap-1 justify-center">
                    {roles.map((r, i) => <Badge key={i} color="blue">{r}</Badge>)}
                </div>
            )
        }
    },
    { 
        key: 'domain', header: '所属域', 
        accessor: (row: User) => (
            <div className="flex items-center text-slate-300 text-sm justify-center">
                <Folder size={12} className="mr-1.5 text-blue-500"/>
                {MOCK_DOMAINS.find(d => d.id === row.baseDomainId)?.name}
            </div>
        )
    },
    { key: 'createTime', header: '创建时间', accessor: (row: User) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.createTime?.split(' ')[0]}<br/>{row.createTime?.split(' ')[1]}</span> },
    { key: 'creator', header: '创建人', accessor: 'creator' },
    { key: 'updateTime', header: '更新时间', accessor: (row: User) => <span className="text-xs text-slate-400 block w-[80px] mx-auto">{row.updateTime?.split(' ')[0]}<br/>{row.updateTime?.split(' ')[1]}</span> },
    { key: 'updater', header: '更新人', accessor: 'updater' },
    { 
        key: 'status', header: '状态', 
        accessor: (row: User) => (
            <div className="flex justify-center">
                <Switch 
                    checked={row.status === 'active'} 
                    onChange={(checked) => initiateStatusChange(row, checked)} 
                />
            </div>
        ),
        width: '80px'
    },
    {
      key: 'action', header: '操作',
      accessor: (row: User) => (
        <div className="flex space-x-2 justify-center">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-yellow-500 hover:!text-yellow-400" icon={<Eye size={14} />} onClick={() => setAuditUser(row)}>权限</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      ),
      width: '200px'
    }
  ], []);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // Initialize
  useEffect(() => {
      // Set default selected node
      if (mode === 'switching' && currentDomain) {
          setSelectedNode({ id: currentDomain.id, type: 'domain' });
          setExpandedKeys(new Set([currentDomain.id]));
          // Also set the search domain to current domain implicitly for UI consistency (though logic handles it)
          setSearchDomainId(currentDomain.id);
      } else {
          // Find root domain
          const root = MOCK_DOMAINS.find(d => !d.parentId);
          if (root) {
              setSelectedNode({ id: root.id, type: 'domain' });
              setExpandedKeys(new Set([root.id]));
          }
          setSearchDomainId('');
      }
  }, [mode, currentDomain]);

  // --- Left Tree Logic (Mixed) ---
  const mixedTree = useMemo(() => {
      // 1. Convert Domains to MixedNodes
      const domainNodes = new Map<string, MixedNode>();

      // Filter domains based on mode
      let visibleDomains = MOCK_DOMAINS;
      if (mode === 'switching' && currentDomain) {
          visibleDomains = [currentDomain];
      }

      visibleDomains.forEach(d => {
          domainNodes.set(d.id, {
              id: d.id,
              name: d.name,
              type: 'domain',
              data: d,
              children: []
          });
      });

      const rootNodes: MixedNode[] = [];

      // 2. Build Domain Hierarchy
      visibleDomains.forEach(d => {
          const node = domainNodes.get(d.id)!;
          if (d.parentId && domainNodes.has(d.parentId)) {
              domainNodes.get(d.parentId)!.children!.push(node);
          } else {
              rootNodes.push(node);
          }
      });

      // 3. Attach Departments
      const convertDept = (d: Department): MixedNode => ({
          id: d.id,
          name: d.name,
          type: 'dept',
          data: d,
          children: d.children ? d.children.map(convertDept) : []
      });

      domainNodes.forEach((node) => {
          const domainRootDepts = MOCK_DEPTS.filter(d => d.domainId === node.id && d.parentId === null);
          const deptNodes = domainRootDepts.map(d => {
              const buildDeptTree = (root: Department): MixedNode => {
                  const children = MOCK_DEPTS.filter(child => child.parentId === root.id);
                  return {
                      id: root.id,
                      name: root.name,
                      type: 'dept',
                      data: root,
                      children: children.map(buildDeptTree)
                  };
              };
              return buildDeptTree(d);
          });

          node.children = [...(node.children || []), ...deptNodes];
      });

      return rootNodes;
  }, [mode, currentDomain]);

  const toggleExpand = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const renderTreeNodes = (nodes: MixedNode[], depth = 0) => {
      return nodes.map(node => {
          const isExpanded = expandedKeys.has(node.id);
          const isSelected = selectedNode?.id === node.id;
          const hasChildren = node.children && node.children.length > 0;

          return (
              <div key={node.id}>
                  <div 
                      className={`flex items-center py-2 px-2 cursor-pointer transition-all rounded-md mb-1 border border-transparent ${isSelected ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-300 hover:bg-slate-800 hover:border-slate-700'}`}
                      style={{ paddingLeft: `${depth * 16 + 8}px` }}
                      onClick={() => setSelectedNode({ id: node.id, type: node.type })}
                  >
                      <div 
                        className={`mr-1 p-0.5 rounded hover:bg-white/20 transition-colors ${hasChildren ? 'visible' : 'invisible'}`}
                        onClick={(e) => toggleExpand(e, node.id)}
                      >
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </div>

                      {node.type === 'domain' ? (
                          <Building2 size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-blue-500'}`} />
                      ) : (
                          <GitBranch size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-yellow-500'}`} />
                      )}

                      <span className="text-sm truncate select-none font-medium">{node.name}</span>
                  </div>
                  {isExpanded && node.children && renderTreeNodes(node.children, depth + 1)}
              </div>
          );
      });
  };

  // --- Right Table Data Logic ---
  const filteredUsers = useMemo(() => {
      return userData.filter(u => {
          if (selectedNode) {
              if (selectedNode.type === 'domain') {
                  if (u.baseDomainId !== selectedNode.id) return false;
              } else {
                  if (u.deptId !== selectedNode.id) return false;
              }
          }

          const matchUser = !searchUsername || u.username.toLowerCase().includes(searchUsername.toLowerCase()) || u.realName.includes(searchUsername);
          const matchRole = !searchRoleId || u.roles.some(r => r.roleId === searchRoleId);
          const matchDomain = !searchDomainId || u.baseDomainId === searchDomainId;

          const matchStatus = !searchStatus || u.status === searchStatus;

          return matchUser && matchRole && matchDomain && matchStatus;
      });
  }, [userData, selectedNode, searchUsername, searchRoleId, searchDomainId, searchStatus]);

  // Prepared data with serial numbers
  const tableData = useMemo(() => {
      return filteredUsers.map((u, index) => ({
          ...u,
          serialNumber: index + 1
      }));
  }, [filteredUsers]);

  const handleAdd = () => {
      if (!selectedNode || selectedNode.type !== 'domain') {
          if (selectedNode?.type === 'dept') {
             const dept = MOCK_DEPTS.find(d => d.id === selectedNode.id);
             if (dept) {
                 setCurrentUser({ 
                    status: 'active', 
                    baseDomainId: dept.domainId,
                    deptId: dept.id
                 });
                 setSelectedRoleIds(new Set());
                 setIsModalOpen(true);
                 return;
             }
          }
          alert("请先选择左侧组织机构(域)");
          return;
      }
      setCurrentUser({ 
          status: 'active', 
          baseDomainId: selectedNode.id
      });
      setSelectedRoleIds(new Set());
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentUser.username || !currentUser.realName || !currentUser.baseDomainId) {
          alert("请完善基本信息");
          return;
      }

      const newRoles = Array.from(selectedRoleIds).map(rId => {
          const roleDef = MOCK_ROLES.find(r => r.id === rId);
          return {
              roleId: rId,
              targetDomainId: currentUser.baseDomainId!,
              roleName: roleDef?.name
          };
      });

      const timestamp = new Date().toLocaleString();

      if (currentUser.id) {
          setUserData(userData.map(u => u.id === currentUser.id ? { 
              ...u, 
              ...currentUser, 
              roles: newRoles,
              updateTime: timestamp,
              updater: 'admin'
          } as User : u));
      } else {
          const newUser = {
              ...currentUser,
              id: Date.now().toString(),
              createTime: timestamp,
              creator: 'admin',
              updateTime: timestamp,
              updater: 'admin',
              roles: newRoles
          } as User;
          setUserData([...userData, newUser]);
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setUserData(userData.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setUserData(userData.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  // --- Helpers for Modal ---
  const getDeptOptions = (domainId: string) => {
      const depts = MOCK_DEPTS.filter(d => d.domainId === domainId);
      const buildHierarchy = (parentId: string | null = null, depth = 0): {id: string, name: string, depth: number}[] => {
          const children = depts.filter(d => d.parentId === parentId);
          let res: {id: string, name: string, depth: number}[] = [];
          children.forEach(c => {
              res.push({ id: c.id, name: c.name, depth });
              res = res.concat(buildHierarchy(c.id, depth + 1));
          });
          return res;
      };
      return buildHierarchy(null, 0);
  };

  const deptOptions = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return getDeptOptions(currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const availableRoles = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return MOCK_ROLES.filter(r => r.domainId === currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const toggleRoleSelection = (roleId: string) => {
      const newSet = new Set(selectedRoleIds);
      if (newSet.has(roleId)) newSet.delete(roleId);
      else newSet.add(roleId);
      setSelectedRoleIds(newSet);
  };

  // --- Permission Audit Helper ---
  const calculateEffectivePermissions = (user: User) => {
      const userRoles = user.roles.map(ur => MOCK_ROLES.find(r => r.id === ur.roleId)).filter(Boolean) as Role[];
      const allMenuIds = new Set<string>();
      const allRegions = new Set<string>();
      const allBizTypes = new Set<string>();

      userRoles.forEach(role => {
          role.menuIds?.forEach(id => allMenuIds.add(id));
          role.regionScope?.forEach(r => allRegions.add(r));
          role.bizCategoryScope?.forEach(b => allBizTypes.add(b));
      });

      return { menus: allMenuIds, regions: allRegions, bizTypes: allBizTypes, roles: userRoles };
  };

  const renderAuditMenuTree = (menus: Menu[], accessibleIds: Set<string>, depth = 0) => {
      return menus.map(menu => {
          const hasAccess = accessibleIds.has(menu.id);
          return (
              <div key={menu.id}>
                  <div className={`flex items-center space-x-2 py-1.5 rounded px-2`} style={{ paddingLeft: `${depth * 20 + 8}px` }}>
                      {hasAccess ? <Check size={16} className="text-green-500 shrink-0" /> : <div className="w-4 h-4" /> }
                      <span className={`${hasAccess ? 'text-white font-medium' : 'text-slate-600'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderAuditMenuTree(menu.children, accessibleIds, depth + 1)}
              </div>
          );
      });
  };

  return (
    <div className="h-full flex gap-4 overflow-hidden">
        {/* Left Sidebar: Domain Tree */}
        <Card className="w-72 shrink-0 flex flex-col" title="组织机构">
            <div className="mb-3">
                <Input placeholder="搜索组织..." className="text-xs h-8" prefix={<Search size={14}/>} />
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar -mx-2 px-2">
                {renderTreeNodes(mixedTree)}
            </div>
        </Card>

        {/* Right Content */}
        <div className="flex-1 flex flex-col gap-4 overflow-hidden">
            {/* 1. Search Area */}
            <Card className="shrink-0" bodyClassName="p-4">
                <div className="flex flex-col gap-3">
                    {/* Row 1: Search Conditions */}
                    <div className="flex flex-wrap gap-4 items-end">
                        <Input 
                            label="用户名/姓名"
                            placeholder="请输入" 
                            className="w-40" 
                            value={searchUsername} 
                            onChange={e => setSearchUsername(e.target.value)}
                        />
                        {/* New: Role Search */}
                        <div className="w-40">
                            <Select 
                                label="所属角色"
                                options={[{label: '全部', value: ''}, ...MOCK_ROLES.map(r => ({label: r.name, value: r.id}))]}
                                value={searchRoleId}
                                onChange={e => setSearchRoleId(e.target.value)}
                            />
                        </div>
                        {/* New: Domain Search */}
                        <div className="w-40">
                            <Select 
                                label="所属域"
                                options={[{label: '全部', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                                value={searchDomainId}
                                onChange={e => setSearchDomainId(e.target.value)}
                                disabled={mode === 'switching'} // Lock if in switching mode
                                className={mode === 'switching' ? 'opacity-50 cursor-not-allowed' : ''}
                            />
                        </div>
                        <Select
                            label="状态"
                            options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '锁定', value: 'locked'}]}
                            value={searchStatus}
                            onChange={e => setSearchStatus(e.target.value)}
                            className="w-32"
                        />
                    </div>

                    {/* Row 2: Actions */}
                    <div className="flex justify-between items-center border-t border-slate-700/50 pt-3">
                        <div className="flex gap-3">
                            <Button variant="primary" icon={<Search size={16} />}>查询</Button>
                            <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchUsername(''); setSearchRoleId(''); setSearchDomainId(''); setSearchStatus(''); }}>重置</Button>
                            <Button className="bg-emerald-600 hover:bg-emerald-500 text-white" icon={<Plus size={16} />} onClick={handleAdd}>新增用户</Button>
                            <Button className="bg-emerald-600/10 text-emerald-500 border border-emerald-600/50 hover:bg-emerald-600/20" icon={<Download size={16} />}>导出</Button>
                        </div>
                        <div className="flex gap-3">
                            <Button 
                                size="sm" 
                                variant="secondary" 
                                className="bg-amber-500/10 text-amber-500 border-amber-500/50 hover:bg-amber-500/20 px-2 py-1 text-xs" 
                                icon={<Settings size={14} />}
                                onClick={() => setIsColumnConfigOpen(true)}
                            >
                                列配置
                            </Button>
                        </div>
                    </div>
                </div>
            </Card>

            {/* 2. Table Area */}
            <Card className="flex-1 overflow-hidden flex flex-col">
                <div className="flex justify-between items-center px-4 py-2 border-b border-slate-800/50 bg-slate-900/20">
                     <span className="text-xs text-slate-500">
                         当前过滤: <span className="text-blue-400 font-medium">{selectedNode ? (selectedNode.type === 'domain' ? '域' : '部门') + ' - ' + (mixedTree.find(n => n.id === selectedNode.id)?.name || MOCK_DEPTS.find(d => d.id === selectedNode.id)?.name) : '全部'}</span>
                     </span>
                </div>

                <div className="flex-1 overflow-auto">
                    <Table columns={activeColumns} data={tableData} keyField="id" />
                </div>
                <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                    <div className="text-sm text-slate-400">共 {filteredUsers.length} 条记录</div>
                </div>
            </Card>
        </div>

        <ColumnConfigDialog 
          isOpen={isColumnConfigOpen} 
          onClose={() => setIsColumnConfigOpen(false)} 
          allColumns={ALL_COLUMNS} 
          currentOrder={columnOrder} 
          onSave={setColumnOrder} 
        />

        {/* Add/Edit Modal */}
        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title={currentUser.id ? "编辑用户" : "新增用户"}
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={handleSave}>确定</Button>
                </>
              }
        >
            <div className="space-y-8">
                {/* 1. Basic Info */}
                <div>
                    <SectionTitle title="基本信息" />
                    <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                        <Input 
                            label="用户名" 
                            placeholder="登录账号" 
                            value={currentUser.username || ''}
                            onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                        />
                        <Input 
                            label="真实姓名" 
                            placeholder="员工姓名" 
                            value={currentUser.realName || ''}
                            onChange={e => setCurrentUser({...currentUser, realName: e.target.value})}
                        />
                        <Input 
                            label="手机号" 
                            placeholder="11位手机号" 
                            value={currentUser.phone || ''}
                            onChange={e => setCurrentUser({...currentUser, phone: e.target.value})}
                        />
                        <Input 
                            label="邮箱" 
                            placeholder="Email" 
                            value={currentUser.email || ''}
                            onChange={e => setCurrentUser({...currentUser, email: e.target.value})}
                        />

                        {/* Domain Field (ReadOnly) */}
                        <div className="relative">
                             <Select 
                                label="归属组织 (Domain)" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentUser.baseDomainId}
                                disabled={true}
                                className="opacity-60 cursor-not-allowed bg-slate-800"
                             />
                             <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                <Lock size={12} />
                                <span className="text-xs">已锁定</span>
                             </div>
                        </div>

                        {/* Department Select (Dynamic) */}
                        <div className="relative">
                            <label className="text-sm text-slate-400 block mb-1.5">所属部门</label>
                            <select 
                                className="w-full px-3 py-2 bg-[#1e293b] border border-slate-700 rounded focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-white appearance-none hover:border-slate-600 text-sm"
                                value={currentUser.deptId || ''}
                                onChange={e => setCurrentUser({...currentUser, deptId: e.target.value})}
                            >
                                <option value="">-- 请选择部门 --</option>
                                {deptOptions.map(d => (
                                    <option key={d.id} value={d.id}>
                                        {'\u00A0\u00A0'.repeat(d.depth)} {d.depth > 0 ? '└ ' : ''}{d.name}
                                    </option>
                                ))}
                            </select>
                            <ChevronDown size={14} className="absolute right-3 top-[38px] pointer-events-none text-slate-500" />
                        </div>

                         <div className="col-span-2">
                            <label className="text-sm text-slate-400 font-normal mb-1 block">账户状态</label>
                            <div className="flex items-center gap-3 mt-1">
                                <Switch 
                                    checked={currentUser.status === 'active'}
                                    onChange={c => setCurrentUser({...currentUser, status: c ? 'active' : 'locked'})}
                                />
                                <span className={`text-sm ${currentUser.status === 'active' ? 'text-green-400' : 'text-red-400'}`}>
                                    {currentUser.status === 'active' ? '正常启用' : '已锁定'}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* 2. Role Config */}
                <div>
                    <div className="flex justify-between items-center mb-4">
                        <SectionTitle title="角色分配" className="mb-0" />
                        <span className="text-xs font-normal text-slate-500 bg-slate-800/50 px-2 py-1 rounded">
                            组织: {MOCK_DOMAINS.find(d => d.id === currentUser.baseDomainId)?.name}
                        </span>
                    </div>

                    <div className="bg-[#1e293b]/50 rounded border border-slate-700 p-5 min-h-[100px]">
                        {availableRoles.length > 0 ? (
                            <div className="grid grid-cols-2 gap-4">
                                {availableRoles.map(role => (
                                    <label key={role.id} className={`flex items-start p-3 rounded cursor-pointer border transition-all ${selectedRoleIds.has(role.id) ? 'bg-blue-600/10 border-blue-500/50' : 'bg-slate-800/50 border-transparent hover:border-slate-600'}`}>
                                        <input 
                                            type="checkbox" 
                                            className="mt-1 rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900 mr-3 h-4 w-4"
                                            checked={selectedRoleIds.has(role.id)}
                                            onChange={() => toggleRoleSelection(role.id)}
                                        />
                                        <div>
                                            <div className={`text-sm font-medium ${selectedRoleIds.has(role.id) ? 'text-blue-100' : 'text-slate-300'}`}>{role.name}</div>
                                            <div className="text-xs text-slate-500 mt-0.5">{role.code}</div>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-500 py-6">
                                <Shield size={32} className="mb-3 opacity-20"/>
                                <span className="text-sm">该组织下暂无可用角色，请先在角色管理中配置。</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </Modal>

        {/* --- Permission Audit Modal --- */}
        {auditUser && (
            <Modal
                isOpen={!!auditUser}
                onClose={() => setAuditUser(null)}
                title={`权限审计 - ${auditUser.realName}`}
                size="lg"
                footer={<Button onClick={() => setAuditUser(null)}>关闭</Button>}
            >
                <div className="space-y-8">
                    {/* Role Summary */}
                    <div>
                        <SectionTitle title="生效角色" />
                        <div className="bg-slate-800/40 border border-slate-700 rounded-lg p-5">
                            <div className="flex flex-wrap gap-3">
                                {calculateEffectivePermissions(auditUser).roles.map((r, idx) => (
                                    <div key={idx} className="flex items-center gap-2 bg-blue-900/30 border border-blue-500/30 text-blue-200 px-3 py-1.5 rounded text-sm">
                                        <Shield size={14} className="text-blue-400"/>
                                        <span className="font-medium">{r.name}</span>
                                        <span className="opacity-50 text-xs border-l border-blue-500/30 pl-2 ml-1">{r.code}</span>
                                    </div>
                                ))}
                                {calculateEffectivePermissions(auditUser).roles.length === 0 && (
                                    <span className="text-slate-500 text-sm italic flex items-center">
                                        <AlertTriangle size={16} className="mr-2"/> 未分配任何有效角色
                                    </span>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-8 h-[450px]">
                        {/* Functional Permissions */}
                        <div className="flex flex-col">
                            <SectionTitle title="功能权限" />
                            <div className="flex-1 border border-slate-700 rounded-lg bg-[#1e293b]/30 overflow-hidden flex flex-col">
                                <div className="px-4 py-3 border-b border-slate-700 bg-slate-800/50 flex items-center justify-between">
                                    <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">菜单资源</span>
                                    <span className="text-xs text-green-500 flex items-center gap-1"><CheckSquare size={12}/> 已授权</span>
                                </div>
                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                                    {renderAuditMenuTree(MOCK_MENUS, calculateEffectivePermissions(auditUser).menus)}
                                </div>
                            </div>
                        </div>

                        {/* Data Permissions */}
                        <div className="flex flex-col">
                             <SectionTitle title="数据范围" />
                             <div className="flex-1 border border-slate-700 rounded-lg bg-[#1e293b]/30 overflow-hidden flex flex-col">
                                <div className="px-4 py-3 border-b border-slate-700 bg-slate-800/50">
                                    <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">数据维度</span>
                                </div>
                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-4">
                                     <div>
                                         <div className="text-xs text-slate-500 mb-2 font-medium">区域范围</div>
                                         <div className="flex flex-wrap gap-2">
                                             {calculateEffectivePermissions(auditUser).regions.size > 0 ? (
                                                 Array.from(calculateEffectivePermissions(auditUser).regions).map(rCode => (
                                                     <Badge key={rCode} color="gray">{REGIONS.find(r => r.code === rCode)?.name || rCode}</Badge>
                                                 ))
                                             ) : <span className="text-xs text-slate-600 italic">无特定区域限制</span>}
                                         </div>
                                     </div>
                                     <div>
                                         <div className="text-xs text-slate-500 mb-2 font-medium">业务类型</div>
                                         <div className="flex flex-wrap gap-2">
                                             {calculateEffectivePermissions(auditUser).bizTypes.size > 0 ? (
                                                 Array.from(calculateEffectivePermissions(auditUser).bizTypes).map(bCode => (
                                                     <Badge key={bCode} color="blue">{BUSINESS_TYPES.find(b => b.code === bCode)?.name || bCode}</Badge>
                                                 ))
                                             ) : <span className="text-xs text-slate-600 italic">无特定业务限制</span>}
                                         </div>
                                     </div>
                                </div>
                             </div>
                        </div>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle, ColumnConfigDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Folder, ChevronDown, ChevronRight, Phone, Mail, User, Grid, RefreshCcw, Settings, Lock, Building2, Download } from 'lucide-react';
import { MOCK_DEPTS, MOCK_DOMAINS } from '../constants';
import { Department, Domain } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Unified Node Type for the Sidebar
type MixedNode = {
    id: string;
    name: string;
    type: 'domain' | 'dept';
    data: Domain | Department;
    children?: MixedNode[];
};

export const DeptManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  // -- Selection State --
  const [selectedDomainId, setSelectedDomainId] = useState<string>('');
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  // -- Data State (Departments) --
  const [deptData, setDeptData] = useState<Department[]>(MOCK_DEPTS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [expandedTableKeys, setExpandedTableKeys] = useState<Set<string>>(new Set(['1', '11', '12'])); 

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Edit/Add State
  const [currentDept, setCurrentDept] = useState<Partial<Department>>({});

  // Confirm Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Column Config
  const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

  const toggleTableExpand = (id: string) => {
      const newSet = new Set(expandedTableKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedTableKeys(newSet);
  };

  const handleEdit = (dept: Department) => {
      setCurrentDept({ ...dept });
      setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const initiateStatusChange = (dept: Department, checked: boolean) => {
      setTargetStatusChange({ id: dept.id, newStatus: checked ? 'active' : 'inactive' });
      setConfirmOpen(true);
  };

  // --- Column Defs ---
  const ALL_COLUMNS = useMemo(() => [
      {
          key: 'name', header: '部门名称',
          accessor: (row: any) => (
              <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center text-left">
                  {row.children && row.children.length > 0 ? (
                      <button onClick={() => toggleTableExpand(row.id)} className="mr-2 text-slate-400 hover:text-white">
                          {expandedTableKeys.has(row.id) ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </button>
                  ) : <span className="w-[22px]"></span>}
                  <Folder size={16} className="mr-2 text-blue-500" />
                  <span className="text-slate-200 font-medium">{row.name}</span>
              </div>
          ),
          width: '30%'
      },
      { key: 'leader', header: '负责人', accessor: 'leader', width: '15%' },
      { key: 'phone', header: '联系电话', accessor: 'phone', width: '15%' },
      { key: 'sort', header: '排序', accessor: 'sort', width: '10%' },
      {
          key: 'status', header: '状态',
          accessor: (row: Department) => (
              <div className="flex justify-center">
                  <Switch 
                      checked={row.status === 'active'} 
                      onChange={(c) => initiateStatusChange(row, c)} 
                  />
              </div>
          ),
          width: '10%'
      },
      { key: 'createTime', header: '创建时间', accessor: 'createTime' },
      {
          key: 'action', header: '操作',
          accessor: (row: Department) => (
              <div className="flex space-x-2 justify-center">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-green-500 hover:!text-green-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.id)}>新增下级</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          ),
          width: '250px'
      }
  ], [expandedTableKeys]);

  const [columnOrder, setColumnOrder] = useState(ALL_COLUMNS.map(c => c.key));

  const activeColumns = useMemo(() => {
      return columnOrder.map(key => ALL_COLUMNS.find(c => c.key === key)).filter(Boolean);
  }, [columnOrder, ALL_COLUMNS]);

  // --- Initialization ---
  useEffect(() => {
      // Set default selected domain
      if (mode === 'switching' && currentDomain) {
          setSelectedDomainId(currentDomain.id);
          setExpandedKeys(new Set([currentDomain.id]));
      } else {
          // Find root
          const root = MOCK_DOMAINS.find(d => !d.parentId);
          if (root) {
              setSelectedDomainId(root.id);
              setExpandedKeys(new Set([root.id]));
          }
      }
  }, [mode, currentDomain]);

  // --- Left Tree Logic (Mixed Domain + Depts) ---
  const mixedTree = useMemo(() => {
      // 1. Convert Domains to MixedNodes
      const domainNodes = new Map<string, MixedNode>();

      // Filter domains based on mode
      let visibleDomains = MOCK_DOMAINS;
      if (mode === 'switching' && currentDomain) {
          visibleDomains = [currentDomain];
      }

      visibleDomains.forEach(d => {
          domainNodes.set(d.id, {
              id: d.id,
              name: d.name,
              type: 'domain',
              data: d,
              children: []
          });
      });

      const rootNodes: MixedNode[] = [];

      // 2. Build Domain Hierarchy
      visibleDomains.forEach(d => {
          const node = domainNodes.get(d.id)!;
          if (d.parentId && domainNodes.has(d.parentId)) {
              domainNodes.get(d.parentId)!.children!.push(node);
          } else {
              rootNodes.push(node);
          }
      });

      // 3. Attach Departments to Domains
      const convertDept = (d: Department): MixedNode => ({
          id: d.id,
          name: d.name,
          type: 'dept',
          data: d,
          children: d.children ? d.children.map(convertDept) : []
      });

      domainNodes.forEach((node) => {
          const roots = deptData.filter(d => d.domainId === node.id);
          const deptNodes = roots.map(convertDept);
          node.children = [...(node.children || []), ...deptNodes];
      });

      return rootNodes;
  }, [mode, currentDomain, deptData]);

  const toggleExpand = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const handleSidebarClick = (node: MixedNode) => {
      if (node.type === 'domain') {
          setSelectedDomainId(node.id);
      } else {
          const domainId = (node.data as Department).domainId;
          setSelectedDomainId(domainId);
      }
  };

  const renderSidebarNodes = (nodes: MixedNode[], depth = 0) => {
      return nodes.map(node => {
          const isExpanded = expandedKeys.has(node.id);
          const isSelected = selectedDomainId === (node.type === 'domain' ? node.id : (node.data as Department).domainId) && node.type === 'domain'; 

          const hasChildren = node.children && node.children.length > 0;

          return (
              <div key={node.id}>
                  <div 
                      className={`flex items-center py-2 px-2 cursor-pointer transition-all rounded-md mb-1 border border-transparent ${isSelected ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-300 hover:bg-slate-800 hover:border-slate-700'}`}
                      style={{ paddingLeft: `${depth * 16 + 8}px` }}
                      onClick={() => handleSidebarClick(node)}
                  >
                      <div 
                        className={`mr-1 p-0.5 rounded hover:bg-white/20 transition-colors ${hasChildren ? 'visible' : 'invisible'}`}
                        onClick={(e) => toggleExpand(e, node.id)}
                      >
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </div>

                      {node.type === 'domain' ? (
                          <Building2 size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-blue-500'}`} />
                      ) : (
                          <Folder size={14} className="mr-2 text-yellow-500" />
                      )}

                      <span className="text-sm truncate select-none font-medium">{node.name}</span>
                  </div>
                  {isExpanded && node.children && renderSidebarNodes(node.children, depth + 1)}
              </div>
          );
      });
  };

  // --- Right Content Logic (Department Tree Table) ---
  const domainDepartments = useMemo(() => {
      return deptData.filter(d => d.domainId === selectedDomainId);
  }, [deptData, selectedDomainId]);

  const flattenDepts = (depts: Department[], depth = 0): (Department & { depth: number })[] => {
    let result: (Department & { depth: number })[] = [];
    depts.forEach(d => {
      result.push({ ...d, depth });
      if (d.children && expandedTableKeys.has(d.id)) {
        result = result.concat(flattenDepts(d.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = useMemo(() => {
      const visibleNodes = flattenDepts(domainDepartments);
      return visibleNodes.filter(d => {
          const matchName = !searchName || d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchStatus = !searchStatus || d.status === searchStatus;
          return matchName && matchStatus;
      });
  }, [domainDepartments, expandedTableKeys, searchName, searchStatus]);

  const getAllNodes = (depts: Department[]): Department[] => {
      let res: Department[] = [];
      depts.forEach(d => {
          res.push(d);
          if (d.children) res = res.concat(getAllNodes(d.children));
      });
      return res;
  };

  const handleAdd = (parentId: string | null = null) => {
      if (!selectedDomainId) {
          alert("请先选择左侧组织机构(域)");
          return;
      }
      setCurrentDept({
          parentId,
          domainId: selectedDomainId,
          status: 'active',
          sort: 1
      });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentDept.name || !currentDept.leader) {
          alert("请完善基本信息");
          return;
      }

      const deptToSave = { ...currentDept } as Department;

      const updateInTree = (nodes: Department[]): Department[] => {
          return nodes.map(n => {
              if (n.id === currentDept.id) {
                  return { ...n, ...deptToSave, children: n.children }; 
              }
              if (n.children) {
                  return { ...n, children: updateInTree(n.children) };
              }
              return n;
          });
      };

      const addInTree = (nodes: Department[], newItem: Department): Department[] => {
          return nodes.map(n => {
              if (n.id === newItem.parentId) {
                  return { ...n, children: [...(n.children || []), newItem] };
              }
              if (n.children) {
                  return { ...n, children: addInTree(n.children, newItem) };
              }
              return n;
          });
      };

      if (currentDept.id) {
          setDeptData(updateInTree(deptData));
      } else {
          const newDept = {
              ...deptToSave,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              children: []
          } as Department;

          if (newDept.parentId) {
              setDeptData(addInTree(deptData, newDept));
              setExpandedTableKeys(new Set([...expandedTableKeys, newDept.parentId]));
          } else {
              setDeptData([...deptData, newDept]);
          }
      }
      setIsModalOpen(false);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Department[]): Department[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : undefined
              }));
          };
          setDeptData(removeNode(deptData));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          const updateStatus = (nodes: Department[]): Department[] => {
              return nodes.map(n => {
                  if (n.id === targetStatusChange.id) {
                      return { ...n, status: targetStatusChange.newStatus };
                  }
                  if (n.children) {
                      return { ...n, children: updateStatus(n.children) };
                  }
                  return n;
              });
          };
          setDeptData(updateStatus(deptData));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const selectedDomainName = MOCK_DOMAINS.find(d => d.id === selectedDomainId)?.name || '未选择';

  return (
