                          />
                          <Select 
                              label="状态"
                              options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                              value={searchStatus}
                              onChange={e => setSearchStatus(e.target.value)}
                              className="w-32"
                          />
                      </div>

                      {/* Row 2: Actions */}
                      <div className="flex justify-between items-center border-t border-slate-700/50 pt-3">
