                          <div><span className="text-slate-500 block mb-1">操作状态</span><span className={detailLog.status==='success'?'text-green-400':'text-red-400'}>{detailLog.status==='success'?'成功':'失败'}</span></div>
                          <div><span className="text-slate-500 block mb-1">消耗时间</span><span className="text-slate-200">{detailLog.costTime}ms</span></div>
                          <div><span className="text-slate-500 block mb-1">操作时间</span><span className="text-slate-200">{detailLog.operTime}</span></div>
                      </div>
                      {detailLog.errorMsg && (
                          <div className="bg-red-900/20 border border-red-900/50 p-3 rounded text-red-200 mt-4">
                              <div className="flex items-center gap-2 mb-1 font-bold"><AlertCircle size={14}/> 异常信息</div>
                              <div className="text-xs font-mono">{detailLog.errorMsg}</div>
                          </div>
                      )}
                  </div>
              )}
          </Modal>
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Book, List, RefreshCcw } from 'lucide-react';
import { MOCK_DICT_TYPES, MOCK_DICT_DATA } from '../constants';
import { DictType, DictData } from '../types';

export const DictManager: React.FC = () => {
  // Left: Type List State
  const [types, setTypes] = useState<DictType[]>(MOCK_DICT_TYPES);
  const [selectedTypeId, setSelectedTypeId] = useState<string>(MOCK_DICT_TYPES[0]?.id || '');
  const [searchType, setSearchType] = useState('');

  // Right: Data List State
  const [datas, setDatas] = useState<DictData[]>(MOCK_DICT_DATA);
  const [searchLabel, setSearchLabel] = useState('');

  // Modal State
  const [typeModalOpen, setTypeModalOpen] = useState(false);
  const [dataModalOpen, setDataModalOpen] = useState(false);
  const [currentType, setCurrentType] = useState<Partial<DictType>>({});
  const [currentData, setCurrentData] = useState<Partial<DictData>>({});

  // --- Type Logic ---
  const filteredTypes = useMemo(() => {
      return types.filter(t => !searchType || t.name.includes(searchType) || t.type.includes(searchType));
  }, [types, searchType]);

  const handleAddType = () => {
      setCurrentType({ status: 'active' });
      setTypeModalOpen(true);
  };

  const handleEditType = (t: DictType) => {
      setCurrentType({ ...t });
      setTypeModalOpen(true);
  };

  const handleSaveType = () => {
      if (!currentType.name || !currentType.type) return;
      if (currentType.id) {
          setTypes(types.map(t => t.id === currentType.id ? { ...t, ...currentType } as DictType : t));
      } else {
          setTypes([...types, { ...currentType, id: Date.now().toString(), createTime: new Date().toLocaleDateString() } as DictType]);
      }
      setTypeModalOpen(false);
  };

  // --- Data Logic ---
  const selectedTypeObj = types.find(t => t.id === selectedTypeId);

  const filteredDatas = useMemo(() => {
      if (!selectedTypeObj) return [];
      return datas.filter(d => 
          d.dictType === selectedTypeObj.type && 
          (!searchLabel || d.label.includes(searchLabel))
      );
  }, [datas, selectedTypeObj, searchLabel]);

  const handleAddData = () => {
      if (!selectedTypeObj) return;
      setCurrentData({ dictType: selectedTypeObj.type, status: 'active', sort: 0, isDefault: false, classType: 'default' });
      setDataModalOpen(true);
  };

  const handleEditData = (d: DictData) => {
      setCurrentData({ ...d });
      setDataModalOpen(true);
  };

  const handleSaveData = () => {
      if (!currentData.label || !currentData.value) return;
      if (currentData.id) {
          setDatas(datas.map(d => d.id === currentData.id ? { ...d, ...currentData } as DictData : d));
      } else {
          setDatas([...datas, { ...currentData, id: Date.now().toString() } as DictData]);
      }
      setDataModalOpen(false);
  };

  // --- Render ---
  const typeColumns = [
      { header: '字典名称', accessor: 'name' },
      { header: '字典类型', accessor: 'type' },
      { header: '操作', accessor: (row: DictType) => (
          <div className="flex gap-2">
              <button className="text-blue-400 hover:text-blue-300" onClick={(e) => { e.stopPropagation(); handleEditType(row); }}><Edit2 size={12}/></button>
          </div>
      )}
  ];

  const dataColumns = [
      { header: '标签', accessor: 'label' },
      { header: '键值', accessor: 'value' },
      { header: '排序', accessor: 'sort' },
      { 
          header: '样式', 
          accessor: (row: DictData) => (
              <Badge color={row.classType === 'danger' ? 'red' : row.classType === 'success' ? 'green' : row.classType === 'warning' ? 'yellow' : 'blue'}>
                  {row.classType || 'default'}
              </Badge>
          ) 
      },
      { 
          header: '状态', 
          accessor: (row: DictData) => <span className={row.status==='active'?'text-green-400':'text-red-400'}>{row.status==='active'?'正常':'停用'}</span> 
      },
      {
          header: '操作',
          accessor: (row: DictData) => (
              <div className="flex gap-2">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={12}/>} onClick={() => handleEditData(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={12}/>} onClick={() => setDatas(datas.filter(d => d.id !== row.id))}>删除</Button>
              </div>
          )
      }
  ];

  return (
      <div className="h-full flex gap-4">
          {/* Left: Types */}
          <Card className="w-1/3 flex flex-col" title="字典类型" bodyClassName="p-3">
              <div className="flex gap-2 mb-3">
                  <Input placeholder="字典名称/类型" value={searchType} onChange={e => setSearchType(e.target.value)} className="flex-1 text-xs h-8" />
                  <Button size="sm" icon={<Plus size={14}/>} onClick={handleAddType}></Button>
              </div>
              <div className="flex-1 overflow-auto border border-slate-700/50 rounded">
                  <table className="w-full text-sm text-left text-slate-300">
                      <thead className="bg-slate-800 text-xs text-slate-400">
                          <tr>
                              <th className="px-3 py-2">名称</th>
                              <th className="px-3 py-2">类型</th>
                              <th className="px-3 py-2 w-10"></th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-800">
                          {filteredTypes.map(t => (
                              <tr 
                                key={t.id} 
                                className={`cursor-pointer hover:bg-slate-800/50 transition-colors ${selectedTypeId === t.id ? 'bg-blue-900/20' : ''}`}
                                onClick={() => setSelectedTypeId(t.id)}
                              >
                                  <td className="px-3 py-2">{t.name}</td>
                                  <td className="px-3 py-2 text-slate-500 text-xs" title={t.type}>{t.type}</td>
                                  <td className="px-3 py-2">
                                      <Edit2 size={12} className="text-slate-500 hover:text-blue-400" onClick={(e) => {e.stopPropagation(); handleEditType(t)}}/>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </Card>

          {/* Right: Data */}
          <div className="flex-1 flex flex-col gap-4">
              <Card className="shrink-0" bodyClassName="p-3">
                  <div className="flex justify-between items-center">
                      <div className="flex gap-4 items-center">
                          <span className="text-sm font-bold text-slate-200 flex items-center gap-2">
                              <Book size={16} className="text-blue-500"/>
                              {selectedTypeObj ? selectedTypeObj.name : '请选择字典'}
                          </span>
                          <span className="text-xs text-slate-500 bg-slate-800 px-2 py-0.5 rounded">{selectedTypeObj?.type}</span>
                      </div>
                      <div className="flex gap-2">
                          <Input placeholder="数据标签" value={searchLabel} onChange={e => setSearchLabel(e.target.value)} className="w-40 h-8 text-xs" />
                          <Button size="sm" icon={<Search size={14}/>}>搜索</Button>
                          <Button size="sm" variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={14}/>} onClick={handleAddData} disabled={!selectedTypeId}>新增数据</Button>
                      </div>
                  </div>
              </Card>

              <Card className="flex-1 overflow-hidden flex flex-col">
                  <div className="flex-1 overflow-auto">
                      <Table columns={dataColumns} data={filteredDatas} keyField="id" />
                  </div>
              </Card>
          </div>

          {/* Modals */}
          <Modal isOpen={typeModalOpen} onClose={() => setTypeModalOpen(false)} title={currentType.id ? "编辑字典类型" : "新增字典类型"} size="sm" 
            footer={<><Button variant="secondary" onClick={() => setTypeModalOpen(false)}>取消</Button><Button onClick={handleSaveType}>确定</Button></>}>
              <div className="space-y-4">
                  <Input label="字典名称" value={currentType.name || ''} onChange={e => setCurrentType({...currentType, name: e.target.value})} />
                  <Input label="字典类型" value={currentType.type || ''} onChange={e => setCurrentType({...currentType, type: e.target.value})} />
                  <Input label="备注" value={currentType.remark || ''} onChange={e => setCurrentType({...currentType, remark: e.target.value})} />
              </div>
          </Modal>

          <Modal isOpen={dataModalOpen} onClose={() => setDataModalOpen(false)} title={currentData.id ? "编辑字典数据" : "新增字典数据"} size="sm"
            footer={<><Button variant="secondary" onClick={() => setDataModalOpen(false)}>取消</Button><Button onClick={handleSaveData}>确定</Button></>}>
              <div className="space-y-4">
                  <Input label="数据标签" value={currentData.label || ''} onChange={e => setCurrentData({...currentData, label: e.target.value})} />
                  <Input label="数据键值" value={currentData.value || ''} onChange={e => setCurrentData({...currentData, value: e.target.value})} />
                  <Input label="显示排序" type="number" value={currentData.sort || 0} onChange={e => setCurrentData({...currentData, sort: parseInt(e.target.value)})} />
                  <Select label="回显样式" options={[{label:'Default',value:'default'},{label:'Primary',value:'primary'},{label:'Success',value:'success'},{label:'Danger',value:'danger'}]} 
                      value={currentData.classType} onChange={e => setCurrentData({...currentData, classType: e.target.value as any})} />
                  <div className="flex flex-col gap-2">
                      <label className="text-sm text-slate-400">状态</label>
                      <Switch checked={currentData.status === 'active'} onChange={c => setCurrentData({...currentData, status: c?'active':'inactive'})} />
                  </div>
              </div>
          </Modal>
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Button, Badge, Input, SectionTitle } from '../components/UI';
import { Search, Plus, LayoutGrid, Eye, Code, Edit2 } from 'lucide-react';
import { BUSINESS_TYPES, MOCK_COMPONENTS } from '../constants';
import { useGlobalContext } from '../GlobalContext';
import { BizLinePreview } from '../components/previews/BizLinePreview';
import { BizInetPreview } from '../components/previews/BizInetPreview';
import { BizIntranetPreview } from '../components/previews/BizIntranetPreview';
import { BizDialPreview } from '../components/previews/BizDialPreview';
import { BizCollectPreview } from '../components/previews/BizCollectPreview';
import { BizCompPreview } from '../components/previews/BizCompPreview';
import { Biz5GPreview } from '../components/previews/Biz5GPreview';
import { BizIdcPreview } from '../components/previews/BizIdcPreview';
import { BizBasePreview } from '../components/previews/BizBasePreview';
import { BizOtherPreview } from '../components/previews/BizOtherPreview';
import { GenericPreview } from '../components/previews/GenericPreview';
import { ComponentEditor } from '../components/ComponentEditor';

export const ComponentManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [search, setSearch] = useState('');

  // Editor State
  const [editingComponent, setEditingComponent] = useState<any>(null);

  // Permission Logic: Filter allowed business types
  const allowedCategories = useMemo(() => {
    // If Super Domain (fusion), show everything
    if (mode === 'fusion' || !currentDomain) {
      return BUSINESS_TYPES;
    }
    // Filter categories based on domain's businessTypes
    return BUSINESS_TYPES.filter(bt => 
      currentDomain.businessTypes.includes(bt.code) || bt.code === 'BIZ_BASE' || bt.code === 'BIZ_OTHER'
    );
  }, [mode, currentDomain]);

  // 1. Get all components available to the current context (Permission filtered only)
  const allAccessibleComponents = useMemo(() => {
    let list = MOCK_COMPONENTS;
    if (mode !== 'fusion' && currentDomain) {
        list = list.filter(c => 
            currentDomain.businessTypes.includes(c.category) || 
            c.category === 'BIZ_BASE' || 
            c.category === 'BIZ_OTHER'
        );
    }
    return list;
  }, [mode, currentDomain]);

  // 2. Filter components for display based on category and search
  const filteredComponents = useMemo(() => {
    let list = allAccessibleComponents;

    // Category Filter
    if (activeCategory !== 'all') {
      list = list.filter(c => c.category === activeCategory);
    }

    // Search Filter
    if (search) {
      list = list.filter(c => c.name.toLowerCase().includes(search.toLowerCase()));
    }

    return list;
  }, [allAccessibleComponents, activeCategory, search]);

  // Helper to get count for a specific category within accessible components
  const getCategoryCount = (categoryCode: string) => {
      return allAccessibleComponents.filter(c => c.category === categoryCode).length;
  };

  // --- Render Preview Wrapper ---
  const renderPreview = (comp: typeof MOCK_COMPONENTS[0]) => {
      switch (comp.category) {
        case 'BIZ_LINE': return <BizLinePreview comp={comp} />;
        case 'BIZ_INET': return <BizInetPreview comp={comp} />;
        case 'BIZ_INTRANET': return <BizIntranetPreview comp={comp} />;
        case 'BIZ_DIAL': return <BizDialPreview comp={comp} />;
        case 'BIZ_COLLECT': return <BizCollectPreview comp={comp} />;
        case 'BIZ_COMP': return <BizCompPreview comp={comp} />;
        case 'BIZ_5G': return <Biz5GPreview comp={comp} />;
        case 'BIZ_IDC': return <BizIdcPreview comp={comp} />;
        case 'BIZ_BASE': return <BizBasePreview comp={comp} />;
        case 'BIZ_OTHER': return <BizOtherPreview comp={comp} />;
        default: return <GenericPreview comp={comp} />;
      }
  };

  return (
    <div className="flex h-full gap-6">
      {/* Sidebar Categories */}
      <div className="w-64 flex flex-col gap-2 bg-slate-900/50 p-4 rounded-lg border border-slate-800">
        <SectionTitle title="组件列表" className="mb-2" />
        <button 
          onClick={() => setActiveCategory('all')}
          className={`flex items-center justify-between px-3 py-2 rounded text-sm transition-all ${activeCategory === 'all' ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800'}`}
        >
          全部组件
          <Badge color={activeCategory === 'all' ? 'blue' : 'gray'}>
            {filteredComponents.length} / {allAccessibleComponents.length}
          </Badge>
        </button>
        <div className="h-px bg-slate-800 my-2" />
        <div className="flex-1 overflow-y-auto space-y-1 custom-scrollbar pr-1">
            {allowedCategories.map(cat => {
                const count = getCategoryCount(cat.code);
                return (
                    <button 
                        key={cat.code}
                        onClick={() => setActiveCategory(cat.code)}
                        className={`w-full flex items-center justify-between px-3 py-2 rounded text-sm transition-all border ${activeCategory === cat.code ? 'bg-blue-600/10 text-blue-400 border-blue-500/50' : 'border-transparent text-slate-400 hover:bg-slate-800'}`}
                    >
                        <div className="flex items-center gap-2 truncate">
                            {activeCategory === cat.code && <div className="w-1.5 h-1.5 rounded-full bg-blue-500 shadow-[0_0_4px_#3b82f6]"></div>}
                            <span className="truncate">{cat.name}</span>
                        </div>
                        <span className={`text-[10px] px-1.5 py-0.5 rounded border min-w-[24px] text-center ${activeCategory === cat.code ? 'text-blue-300 bg-blue-900/30 border-blue-800' : 'text-slate-600 bg-slate-800/50 border-slate-700/50'}`}>
                            {count}
                        </span>
                    </button>
                );
            })}
        </div>
        {mode === 'fusion' && (
             <Button variant="secondary" className="mt-4 border-dashed border-slate-600" icon={<Plus size={14}/>}>添加组件</Button>
        )}
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col gap-4 overflow-hidden">
        <Card className="shrink-0" bodyClassName="p-4">
          <div className="flex justify-between items-center">
             <div className="flex items-center gap-2">
                <Input 
                  placeholder="搜索组件名称..." 
                  className="w-64" 
                  value={search} 
                  onChange={e => setSearch(e.target.value)}
                  prefix={<Search size={16} />}
                />
             </div>
             <div className="text-xs text-slate-500">
                当前业务域：<span className="text-slate-300 font-medium">{currentDomain?.name || '全域融合'}</span>
             </div>
          </div>
        </Card>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 pb-4">
             {filteredComponents.map(comp => (
               <div 
                  key={comp.id} 
                  className="bg-[#0b1121] border border-slate-800 rounded-lg overflow-hidden hover:border-blue-500/50 hover:shadow-lg transition-all cursor-pointer group flex flex-col h-[220px]"
                  onClick={() => setEditingComponent(comp)}
               >
                  {/* Visualization Area */}
                  <div className="h-[130px] bg-[#020617] relative border-b border-slate-800/50 group-hover:bg-[#0f172a] transition-colors overflow-hidden">
                      {renderPreview(comp)}

                      {/* Hover Overlay */}
                      <div className="absolute inset-0 bg-black/40 backdrop-blur-[1px] opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2 z-20">
                           <Button size="sm" variant="primary" className="h-7 text-xs" icon={<Edit2 size={12}/>} onClick={(e) => { e.stopPropagation(); setEditingComponent(comp); }}>编辑</Button>
                      </div>

                      {/* Type Badge */}
                      <div className="absolute top-2 right-2 z-10">
                        <Badge color="gray" className="bg-black/50 backdrop-blur-sm border-0 text-[10px] scale-90 opacity-60 group-hover:opacity-100">{comp.type}</Badge>
                      </div>
                  </div>

                  {/* Info Area */}
                  <div className="flex-1 p-3 flex flex-col justify-between">
                      <div>
                        <div className="flex justify-between items-start mb-1">
                            <h4 className="text-slate-200 font-bold text-sm truncate group-hover:text-blue-400 transition-colors" title={comp.name}>{comp.name}</h4>
                        </div>
                        <div className="flex items-center gap-1.5 mb-2">
                             <div className={`w-1.5 h-1.5 rounded-full ${['BIZ_5G', 'BIZ_COMP'].includes(comp.category) ? 'bg-purple-500' : (['BIZ_IDC'].includes(comp.category) ? 'bg-emerald-500' : 'bg-blue-500')}`}></div>
                             <span className="text-[10px] text-slate-500 uppercase">{BUSINESS_TYPES.find(b => b.code === comp.category)?.name}</span>
                        </div>
                      </div>
                      <div className="flex justify-between items-center border-t border-slate-800/50 pt-2 mt-1">
                          <span className="text-[10px] text-slate-600">v1.2.0</span>
                          <Code size={12} className="text-slate-600 hover:text-blue-400" />
                      </div>
                  </div>
               </div>
             ))}
             {filteredComponents.length === 0 && (
               <div className="col-span-full py-20 flex flex-col items-center text-slate-600">
                  <LayoutGrid size={48} className="opacity-10 mb-4" />
                  <p>该分类下暂无可用组件或您没有相关业务权限</p>
               </div>
             )}
          </div>
        </div>
      </div>

      {/* Editor Overlay */}
      {editingComponent && (
          <ComponentEditor 
              component={editingComponent} 
              onClose={() => setEditingComponent(null)} 
          />
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Button, Badge, Input, SectionTitle } from '../components/UI';
import { Search, Plus, MoreVertical, Edit2, Play, Monitor, Building2 } from 'lucide-react';
import { MOCK_TEMPLATES, BUSINESS_TYPES, MOCK_CUSTOMERS } from '../constants';
import { useGlobalContext } from '../GlobalContext';
import { TemplateEditor } from '../components/TemplateEditor';

export const TemplateManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [search, setSearch] = useState('');
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState<any>(null);
  const [startInPreview, setStartInPreview] = useState(false);

  // Filter templates based on domain (Switching mode only shows domain specific templates based on Customer ID)
  const filteredTemplates = useMemo(() => {
    let list = MOCK_TEMPLATES;

    // In Switching Mode, we filter by the customers that belong to the current domain
    if (mode === 'switching' && currentDomain) {
        const allowedCustomerIds = currentDomain.customerIds || [];
        list = list.filter(t => t.customerId && allowedCustomerIds.includes(t.customerId));
    }

    if (search) {
      list = list.filter(t => {
          const customerName = MOCK_CUSTOMERS.find(c => c.id === t.customerId)?.name || '';
          return t.name.toLowerCase().includes(search.toLowerCase()) || customerName.toLowerCase().includes(search.toLowerCase());
      });
    }
    return list;
  }, [mode, currentDomain, search]);

  const handleEdit = (temp: any) => {
    setEditingTemplate(temp);
    setStartInPreview(false);
    setIsEditorOpen(true);
  };

  const handlePreview = (temp: any) => {
    setEditingTemplate(temp);
    setStartInPreview(true);
    setIsEditorOpen(true);
  };

  return (
    <div className="h-full flex flex-col gap-6">
      {/* Header */}
      <Card className="shrink-0" bodyClassName="p-4">
         <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
               <span className="text-slate-100 font-bold">全部页面</span>
               <Badge color="blue">{filteredTemplates.length}</Badge>
               <div className="w-px h-6 bg-slate-800 mx-2" />
               <Input 
                placeholder="搜索页面或客户名称..." 
                className="w-64 h-9" 
                value={search}
                onChange={e => setSearch(e.target.value)}
                prefix={<Search size={16} />}
               />
            </div>
            <Button variant="primary" icon={<Plus size={16} />} onClick={() => handleEdit({})}>新建页面</Button>
         </div>
      </Card>

      {/* Template Grid */}
      <div className="flex-1 overflow-y-auto custom-scrollbar">
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 pb-6">
            {filteredTemplates.map(temp => {
                const customer = MOCK_CUSTOMERS.find(c => c.id === temp.customerId);
                return (
                  <div key={temp.id} className="bg-[#0b1121] border border-slate-800 rounded-lg overflow-hidden group hover:border-blue-500/50 hover:shadow-lg transition-all flex flex-col relative">
                     {/* Status Badge */}
                     <div className="absolute top-2 right-2 z-10">
                        <Badge color={temp.status === 'published' ? 'green' : 'gray'} className="bg-black/60 backdrop-blur border-0">
                            {temp.status === 'published' ? '已发布' : '草稿'}
                        </Badge>
                     </div>

                     {/* Thumbnail / Preview Area */}
                     <div className="h-40 bg-slate-900 relative overflow-hidden flex items-center justify-center border-b border-slate-800/50">
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent z-0" />

                        {/* Placeholder Icon */}
                        <Monitor size={48} className="text-slate-700 opacity-20" />

