import React, { useState } from 'react';
import { Card, Table, Button, Badge, Input, ColumnConfigDialog } from '../components/UI';
import { Search, Plus, Edit2, Trash2, Settings, RefreshCw } from 'lucide-react';
import { MOCK_MENUS } from '../constants';

export const MenuManager: React.FC = () => {
    const [search, setSearch] = useState('');
    const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

    // Flatten menu hierarchy for display
    const flattenMenus = (menus: any[], level = 0): any[] => {
        let res: any[] = [];
        menus.forEach(m => {
            res.push({...m, level});
            if(m.children) res = res.concat(flattenMenus(m.children, level + 1));
        });
        return res;
    };
    const flatData = flattenMenus(MOCK_MENUS).filter(m => m.name.includes(search));

    const allColumns = [
        { key: 'name', header: '菜单名称' },
        { key: 'type', header: '类型' },
        { key: 'path', header: '路由路径' },
        { key: 'component', header: '组件路径' },
        { key: 'sort', header: '排序' },
        { key: 'visible', header: '可见' },
        { key: 'createTime', header: '创建时间' },
        { key: 'action', header: '操作' }
    ];
    const [visibleColumns, setVisibleColumns] = useState(allColumns.map(c => c.key));

    const columns = [
        { 
            header: '菜单名称', 
            accessor: (row: any) => <span style={{paddingLeft: row.level * 20}}>{row.name}</span>,
            key: 'name' 
        },
        { 
            header: '类型', 
            accessor: (row: any) => <Badge color={row.type === 'dir' ? 'blue' : (row.type === 'menu' ? 'green' : 'gray')}>{row.type === 'dir' ? '目录' : (row.type === 'menu' ? '菜单' : '按钮')}</Badge>,
            key: 'type' 
        },
        { header: '路由路径', accessor: 'path', key: 'path' },
        { header: '组件路径', accessor: 'component', key: 'component' },
        { header: '排序', accessor: 'sort', key: 'sort' },
        { 
            header: '可见', 
            accessor: (row: any) => row.visible ? <Badge color="green">显示</Badge> : <Badge color="red">隐藏</Badge>,
            key: 'visible' 
        },
        { header: '创建时间', accessor: 'createTime', key: 'createTime' },
        {
            header: '操作',
            accessor: () => (
                <div className="flex gap-2">
                    <Button size="sm" variant="ghost" icon={<Edit2 size={14}/>} />
                    <Button size="sm" variant="ghost" className="text-red-400 hover:text-red-300" icon={<Trash2 size={14}/>} />
                </div>
            ),
            key: 'action'
        }
    ].filter(c => visibleColumns.includes(c.key));

    return (
        <div className="h-full flex flex-col gap-4">
             <Card className="shrink-0" bodyClassName="p-4">
                <div className="flex justify-between items-center">
                    <div className="flex gap-4">
                        <Input 
                            placeholder="请输入菜单名称" 
                            prefix={<Search size={16}/>} 
                            value={search} 
                            onChange={e => setSearch(e.target.value)} 
                        />
                        <Button variant="secondary" icon={<RefreshCw size={16}/>}>重置</Button>
                    </div>
                    <div className="flex gap-3">
                         <Button 
                            size="sm" 
                            variant="secondary" 
                            className="bg-[#EDA93B]/10 text-[#EDA93B] border-[#EDA93B]/50 hover:bg-[#EDA93B]/20 px-2 py-1 text-xs" 
                            icon={<Settings size={14} />}
                            onClick={() => setIsColumnConfigOpen(true)}
                        >
                            列配置
                        </Button>
                        <Button icon={<Plus size={16}/>}>新增菜单</Button>
                    </div>
                </div>
            </Card>
            <div className="flex-1 overflow-hidden">
                <Table columns={columns} data={flatData} />
            </div>
            <ColumnConfigDialog 
                isOpen={isColumnConfigOpen}
                onClose={() => setIsColumnConfigOpen(false)}
                allColumns={allColumns}
                currentOrder={visibleColumns}
                onSave={setVisibleColumns}
            />
        </div>
    );
};

