import React, { useState } from 'react';
import { Card, Table, Button, Badge, Input, ColumnConfigDialog } from '../components/UI';
import { Search, Plus, Edit2, Trash2, Settings, RefreshCw } from 'lucide-react';
import { MOCK_DEPTS, MOCK_DOMAINS } from '../constants';

export const DeptManager: React.FC = () => {
    const [search, setSearch] = useState('');
    const [isColumnConfigOpen, setIsColumnConfigOpen] = useState(false);

    // Flatten depts for display
    const flattenDepts = (depts: any[], level = 0): any[] => {
        let res: any[] = [];
        depts.forEach(d => {
            res.push({...d, level});
            if(d.children) res = res.concat(flattenDepts(d.children, level + 1));
        });
        return res;
    };
    const flatData = flattenDepts(MOCK_DEPTS).filter(d => d.name.includes(search));

    const allColumns = [
        { key: 'name', header: '部门名称' },
