        },
        { header: '创建时间', accessor: 'createTime', key: 'createTime' },
        {
            header: '操作',
            accessor: () => (
                <div className="flex gap-2">
                    <Button size="sm" variant="ghost" icon={<Edit2 size={14}/>} />
                    <Button size="sm" variant="ghost" className="text-red-400 hover:text-red-300" icon={<Trash2 size={14}/>} />
